-- Journey 009
UPDATE clinical_journeys 
SET sessions = '[{"session_number":1,"session_title":"Avaliação Inicial e Construção do Vínculo","session_phase":"initial","session_content":{"narrative":"Você recebe Ana Clara, 32 anos, arquiteta. Ela chega à sessão com postura curvada, fala pausada e evita contato visual. Relata que há cerca de quatro meses vem sentindo um ''vazio profundo'', perda de interesse pelo trabalho que antes amava, e fadiga constante que a impede de concluir projetos. Descreve dificuldades para dormir (acorda às 3h da manhã e não consegue voltar a dormir) e perda de apetite. Ana menciona sentimentos de inutilidade e culpa por ''decepcionar'' sua equipe no escritório. Ela nega ideação suicida atual, mas admite que já pensou que ''seria mais fácil se tudo acabasse''. Durante a narrativa, chora silenciosamente. O foco desta sessão é realizar uma avaliação diagnóstica inicial dentro dos critérios do DSM-5-TR para Depressão Maior, estabelecer rapport e começar a psicoeducação.","session_goals":["Realizar avaliação diagnóstica dos sintomas de acordo com o DSM-5-TR.","Estabelecer aliança terapêutica e validar o sofrimento da paciente."],"key_observations":["Humor deprimido e anedonia claramente presentes.","Sintomas neurovegetativos (insônia terminal, hiporexia) são proeminentes.","Presença de sentimentos de culpa/inutilidade, mas negação de ideação suicida ativa."],"critical_decision_point":"Como você responde à pergunta sobre o prognóstico?"},"expert_commentary":"A pergunta sobre prognóstico é um momento crucial para construir esperança realista. A opção A é ideal pois combina validação emocional (essencial para o rapport) com psicoeducação, um pilar da TCC para depressão. Como destacado por Beck (2011), a colaboração ativa é central, e informar o paciente sobre a natureza do transtorno reduz a desmoralização. Evitar reasseguramento vazio (B) ou fuga técnica (C, D) é fundamental, pois invalidaria a experiência da paciente.","learning_focus":"Construção de Aliança Terapêutica e Psicoeducação Inicial","decision_options":[{"option_letter":"A","intervention":"Validar o medo, fornecer psicoeducação sobre a depressão como um transtorno tratável e enfatizar a colaboração no processo.","approach":"Psicoeducação e Validação","is_optimal":true,"immediate_outcome":"Ana se acalma um pouco, sente-se ouvida e demonstra um leve alívio ao saber que existe um caminho. Ela concorda em colaborar no tratamento.","long_term_effect":"","impact":{"rapport":9,"insight":7,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Garantir de forma genérica e otimista que ''tudo vai ficar bem'', minimizando a gravidade dos sintomas.","approach":"Reasseguramento Genérico","is_optimal":false,"immediate_outcome":"Ana sente que você não está levando sua dor a sério. Ela concorda com a cabeça, mas o vínculo fica fragilizado e ela se retrai.","long_term_effect":"","impact":{"rapport":4,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Desviar da pergunta, focando imediatamente na coleta de mais dados sobre o histórico familiar.","approach":"Fuga para a Avaliação","is_optimal":false,"immediate_outcome":"Ana se sente ignorada em sua angústia central. Ela responde às perguntas de forma mecânica, mas o engajamento terapêutico diminui.","long_term_effect":"","impact":{"rapport":3,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Adotar uma postura excessivamente técnica, listando estatísticas de remissão e diferentes modalidades de tratamento.","approach":"Resposta Excessivamente Técnica","is_optimal":false,"immediate_outcome":"A paciente fica sobrecarregada com informações. Ela não absorve o conteúdo e sua expressão de desespero aumenta.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":2,"session_title":"Identificando Pensamentos Automáticos e Atividade Agradável","session_phase":"middle","session_content":{"narrative":"Ana Clara chega um pouco menos arrastada, relatando que pensou sobre a psicoeducação da sessão anterior e isso a ''acalmou um pouco''. No entanto, relata que a semana foi difícil: evitou uma reunião importante e passou o fim de semana inteiro na cama. Você introduz o modelo cognitivo, explicando a conexão entre situação, pensamento, emoção e comportamento. Juntos, identificam uma situação recente: ''Olhar o e-mail do trabalho na manhã de segunda-feira''. Ana identifica o pensamento automático: ''Eu não consigo fazer nada direito. Vou falhar de novo''. A emoção associada foi desespero (90%) e a conduta foi fechar o notebook e voltar para a cama. O humor durante a sessão flutua entre um engajamento inicial e momentos de desânimo quando fala sobre suas falhas percebidas.","session_goals":["Introduzir e praticar o modelo cognitivo com um exemplo concreto.","Planejar uma atividade agradável de baixa demanda para quebrar o ciclo de inatividade."],"key_observations":["Consegue identificar pensamentos automáticos com relativa facilidade quando guiada.","A inatividade e a evitação são comportamentos de segurança que mantêm a depressão.","Há um leve aumento na esperança, mas ainda muito frágil."],"critical_decision_point":"Como você trabalha esse pensamento automático que ameaça sabotar a tarefa comportamental?"},"expert_commentary":"A opção A demonstra a essência da TCC colaborativa e graduada. O pensamento de Ana é uma distorção cognitiva clássica (abstração seletiva e desqualificação do positivo). Usar questionamento socrático para examinar evidências, como proposto por Judith Beck (2011), é mais eficaz do que confronto (D) ou insistência (B). Ajustar a tarefa (''graduação de tarefas'') é vital na depressão, onde a anedonia e a baixa energia são barreiras. Ignorar a barreira (C) compromete a ativação comportamental, um componente essencial do tratamento.","learning_focus":"Aplicação do Modelo Cognitivo e Graduação de Tarefas Comportamentais","decision_options":[{"option_letter":"A","intervention":"Convidar Ana a examinar a evidência para esse pensamento e, em colaboração, ajustar a atividade para algo menor e mais factível.","approach":"Questionamento Socrático e Ajuste Colaborativo","is_optimal":true,"immediate_outcome":"Ana percebe que está prevendo o fracasso sem evidência. Juntos, definem ''preparar uma xícara de chá e sentar na varanda por 5 minutos'' como meta. Ela se compromete.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Insistir na atividade original do café, incentivando-a a ''enfrentar o medo'' e ''quebrar o padrão''.","approach":"Encorajamento Direto sem Flexibilidade","is_optimal":false,"immediate_outcome":"Ana sente-se pressionada e incapaz. Ela pode até tentar, mas com alta probabilidade de autossabotagem, reforçando sua crença de incompetência.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Abandonar completamente o planejamento de atividade e voltar apenas para a análise dos pensamentos da semana.","approach":"Evitação da Intervenção Comportamental","is_optimal":false,"immediate_outcome":"Perde-se uma oportunidade crucial de ativar a paciente. A sessão fica apenas no nível cognitivo, sem gerar experiência corretiva comportamental.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Interpretar o pensamento como resistência ao tratamento e confrontá-la sobre seu ''medo de melhorar''.","approach":"Confrontação Psicodinâmica Inadequada","is_optimal":false,"immediate_outcome":"A paciente se sente atacada e incompreendida. O vínculo terapêutico é severamente danificado, podendo levar ao abandono do tratamento.","long_term_effect":"","impact":{"rapport":2,"insight":3,"behavioral_change":1,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":3,"session_title":"Trabalhando Crenças Intermediárias e Prevenção de Recaída","session_phase":"advanced","session_content":{"narrative":"Ana Clara relata que conseguiu realizar a atividade ajustada (tomar chá na varanda) em dois dias. Ela descreve um momento breve de ''paz''. No diário de pensamentos, identificou outros pensamentos como ''Se não for perfeito, é um fracasso''. Você propõe explorar a crença por trás disso. Após trabalho, ela articula uma regra condicional: ''Se eu não fizer tudo perfeitamente, então sou uma incompetente''. Esta crença está ligada a um alto padrão de desempenho profissional. O humor está um pouco mais reativo, e ela demonstra frustração ao perceber como essa regra a desgasta. Nesta fase, é importante consolidar os ganhos e começar a discutir a autonomia e prevenção de recaída, uma vez que os sintomas neurovegetativos começam a mostrar leve melhora.","session_goals":["Identificar e começar a questionar crenças intermediárias (regras/atitudes disfuncionais).","Introduzir o conceito de prevenção de recaída e planejar para situações de risco."],"key_observations":["A paciente começa a conectar padrões de pensamento a regras rígidas de vida.","Há um engajamento mais ativo no processo de reestruturação cognitiva.","A melhora comportamental é frágil e ainda muito vinculada à estrutura das sessões."],"critical_decision_point":"Como você trabalha esse medo de recaída e promove autonomia?"},"expert_commentary":"A opção A é ótima porque aborda a prevenção de recaída, um componente final crucial na TCC para depressão (Segal, Williams, & Teasdale, 2018). Ela transforma a ansiedade da paciente em uma oportunidade de planejamento proativo, promovendo autoeficácia. A simples reasseguração (B) ou a extensão desnecessária (D) são iatrogênicas a longo prazo. Um plano de ação concreto, criado em colaboração, internaliza o papel do terapeuta e prepara o paciente para o encerramento futuro.","learning_focus":"Promoção de Autonomia e Prevenção de Recaída","decision_options":[{"option_letter":"A","intervention":"Normalizar o medo, revisar as ferramentas aprendidas (diário, questionamento de pensamentos, atividades) e co-criar um ''plano de ação'' para situações de risco.","approach":"Prevenção de Recaída Colaborativa","is_optimal":true,"immediate_outcome":"Ana sente-se capacitada, não apenas tranquilizada. Ela sai com um plano concreto (e.g., ''Se pensar X, eu faço Y''), aumentando sua autoeficácia e preparação para o futuro.","long_term_effect":"","impact":{"rapport":8,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Reassegurá-la de que você ainda estará lá por muitas sessões e que ela não precisa se preocupar com isso agora.","approach":"Reasseguramento Dependente","is_optimal":false,"immediate_outcome":"Reduz a ansiedade momentânea, mas reforça a dependência do terapeuta. Não promove as habilidades de autogerenciamento necessárias para a manutenção dos ganhos.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Desafiar o medo como um pensamento catastrófico, sem dedicar tempo para construir um plano prático.","approach":"Puramente Cognitivo, sem Plano de Ação","is_optimal":false,"immediate_outcome":"Ana intelectualmente concorda, mas fica com a sensação de estar despreparada. A ansiedade sobre o futuro persiste.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Concordar que o risco é alto e sugerir estender a terapia indefinidamente para ''monitoramento''.","approach":"Medicalização da Prevenção","is_optimal":false,"immediate_outcome":"A mensagem é de que a paciente é frágil e incapaz de se autogerir. Prejudica a autonomia e pode criar dependência terapêutica.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":4,"session_title":"Explorando a Inércia e a Ativação Comportamental","session_phase":"middle","session_content":{"narrative":"Marcos, 42 anos, chega à sessão visivelmente mais arrumado, mas com um olhar cansado. Ele relata que a semana foi difícil, com ''dias cinzentos'' e uma sensação constante de peso. Ele menciona ter tentado seguir a sugestão da sessão anterior de fazer uma caminhada curta, mas desistiu após dois dias, dizendo que ''não viu sentido'' e que a fadiga era grande. Ele descreve um padrão de evitação: fica na cama até tarde, adia tarefas domésticas e evita ligações da família. O humor deprimido é persistente, com anedonia marcante (''nem a série que eu gostava me prende mais''). Ele fala com certa autocrítica sobre sua ''preguiça''. A sessão se concentra em validar o esforço da tentativa, normalizar a dificuldade como parte do transtorno, e mapear com mais detalhes o ciclo da depressão: humor baixo leva à inatividade, que reduz o contato com reforçadores, piorando o humor. É introduzido o conceito de ''Atividade de Mestre'' versus ''Atividade de Controle'' (Beck, 2011), explicando como a depressão ''sequestra'' a motivação.","session_goals":["Psicoeducar sobre o ciclo depressivo da inatividade e anedonia","Introduzir os princípios da Ativação Comportamental de forma colaborativa"],"key_observations":["Relato de tentativa fracassada de atividade, indicando baixa energia e desesperança","Presença de autocrítica (''preguiça'') internalizando os sintomas como falha de caráter","Padrão claro de evitação e retraimento social, alinhado com critérios do DSM-5-TR para Episódio Depressivo Maior"],"critical_decision_point":"Como você responde para engajá-lo no processo?"},"expert_commentary":"A resistência à Ativação Comportamental é comum e previsível. A opção ótima (A) segue o princípio de ''colaboração empírica'' (Beck, 2011). Primeiro, valida-se a experiência emocional para manter a aliança. Depois, reformula-se a intervenção como um ''experimento'' para testar a previsão da depressão (''nada ajuda''), não como uma solução mágica. Isso reduz a pressão e enquadra a ação como coleta de dados, alinhando-se com o modelo cognitivo. É crucial começar com atividades ''minúsculas'' (Lewinsohn, 1974) para garantir sucesso e combater a desesperança.","learning_focus":"Manejo de resistência e engajamento em intervenções comportamentais na depressão","decision_options":[{"option_letter":"A","intervention":"Validar a emoção e reformular o objetivo","approach":"Abordagem colaborativa baseada em TCC, alinhada com a psicoeducação","is_optimal":true,"immediate_outcome":"Você concorda que a tristeza é real e não se trata de fingir. Explica que a depressão ''diz'' que nada vai ajudar, mas a Ativação Comportamental é um teste comportamental para verificar essa previsão. Propõe começar com atividades muito pequenas e neutras, não para gerar prazer imediato, mas para quebrar o ciclo da inércia. Marcos parece menos resistente e aceita planejar uma ''atividade-experimento'' minúscula para os próximos dias.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Enfatizar a importância da disciplina e da força de vontade","approach":"Abordagem diretiva e motivacional","is_optimal":false,"immediate_outcome":"Você tenta motivar Marcos, dizendo que ele precisa se esforçar mais e que a mudança exige disciplina. Marcos se sente incompreendido e pressionado, reforçando sua crença de que está falhando por falta de força de vontade. Ele concorda com o plano apenas para encerrar o assunto, mas o engajamento terapêutico diminui.","long_term_effect":"","impact":{"rapport":3,"insight":2,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Mudar de tópico e explorar as origens da sua tristeza na infância","approach":"Abordagem psicodinâmica prematura","is_optimal":false,"immediate_outcome":"Você pergunta se essa sensação de desesperança lembra algo da sua infância. Marcos fica confuso, pois esperava estratégias para o presente. A sessão perde o foco no modelo cognitivo-comportamental atual, gerando dispersão e frustração no paciente, que não vê conexão prática com seu sofrimento imediato.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Concordar que pode não funcionar e sugerir focar apenas no apoio emocional","approach":"Abordagem excessivamente passiva e não-diretiva","is_optimal":false,"immediate_outcome":"Você valida sua descrença e sugere que talvez seja cedo para intervenções ativas, propondo apenas conversar sobre seus sentimentos nas próximas sessões. Isso reforça a impotência de Marcos e a crença de que não há saída. A terapia estagna, sem direção ou esperança de mudança.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":1,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":5,"session_title":"Testando Experimentos Comportamentais e Identificando Pensamentos Automáticos","session_phase":"middle","session_content":{"narrative":"Marcos inicia a sessão relatando que realizou o ''experimento'' combinado: levantar da cama e preparar um café, sem a expectativa de se animar, apenas para observar. Ele conta que, no primeiro dia, foi mecânico, mas nos dias seguintes, notou que o simples ato de tomar café na varanda trouxe um breve momento de ''paz''. No entanto, rapidamente minimiza: ''Mas foi só um instante, o dia depois piorou''. Você explora esse ''instante de paz'' como um dado importante, destacando que a previsão da depressão (''nada ajuda'') pode não ser 100% verdadeira. A partir dessa situação concreta, você guia Marcos a identificar o pensamento automático que surgiu após o momento positivo: ''Isso não vai durar, amanhã será igual''. A sessão avança para a psicoeducação sobre a tríade cognitiva negativa (visão de si, do mundo e do futuro) e a introdução do registro de pensamentos. Marcos demonstra certa curiosidade intelectual sobre o modelo, mas ainda cético quanto à aplicação em sua vida.","session_goals":["Analisar os resultados do experimento comportamental para desafiar a desesperança","Introduzir a identificação de pensamentos automáticos e a conexão pensamento-emoção"],"key_observations":["Paciente conseguiu realizar atividade de baixa demanda, mas desvaloriza o resultado positivo (viés cognitivo de desqualificação do positivo)","Surgimento espontâneo de um pensamento automático sobre o futuro, exemplificando a visão negativa do futuro (desesperança) típica da depressão","Engajamento intelectual é um ponto de entrada para o trabalho cognitivo, mas o afeto permanece embotado"],"critical_decision_point":"Como você procede para manter a adesão à técnica cognitiva?"},"expert_commentary":"A objeção de Marcos é valiosa e comum. A TCC pode ser percebida como mecânica. A resposta ótima (A) transforma a objeção em parte do processo colaborativo. Primeiro, valida-se a preocupação (não é ''pensamento positivo''). Depois, redefine-se a ferramenta como um ''mapa'' para entender padrões, não como uma solução. Por fim, convida-se para um ''experimento'', mantendo a postura empírica. Isso preserva a aliança, educa sobre o verdadeiro propósito da reestruturação cognitiva (identificar distorções, não trocar pensamentos) e mantém o paciente no papel de cientista de sua própria experiência (Padesky, 1995).","learning_focus":"Psicoeducação sobre o modelo cognitivo e manejo de objeções às técnicas de reestruturação cognitiva","decision_options":[{"option_letter":"A","intervention":"Clarificar o objetivo da técnica e convidar para uma crítica colaborativa","approach":"Abordagem psicoeducacional e colaborativa, normalizando a resistência","is_optimal":true,"immediate_outcome":"Você agradece pelo feedback honesto e concorda que não se trata de ''pensar positivo''. Explica que o objetivo é entender o padrão da sua mente depressiva, que distorce situações (como desqualificar o momento de paz), e não substituir pensamentos ruins por bons. Pergunta: ''Podemos testar se essa ferramenta, mesmo que robotizada, pode nos ajudar a mapear esse território?''. Marcos, sentindo-se ouvido, aceita tentar como um novo ''experimento'', não como uma verdade imposta.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Insistir na importância da técnica e pedir que ele confie no processo","approach":"Abordagem autoritária e não colaborativa","is_optimal":false,"immediate_outcome":"Você defende a técnica, citando sua eficácia comprovada, e pede que Marcos a pratique em casa como tarefa. Ele se sente invalidado e pressionado. A aliança terapêutica é prejudicada, e é provável que ele não realize os registros, voltando na próxima sessão com mais frustração.","long_term_effect":"","impact":{"rapport":2,"insight":3,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Abandonar a técnica cognitiva e retornar exclusivamente à ativação comportamental","approach":"Abordagem de evitação do conflito terapêutico","is_optimal":false,"immediate_outcome":"Você cede à resistência e propõe focar apenas em planejar mais atividades. Isso confirma a crença de Marcos de que seus padrões de pensamento são intocáveis ou ''reais demais'' para serem examinados. Perde-se uma oportunidade crucial de intervenção no nível cognitivo, limitando o potencial da TCC.","long_term_effect":"","impact":{"rapport":6,"insight":2,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Interpretar a irritação como resistência à mudança e confrontá-lo","approach":"Abordagem psicodinâmica inadequada ao contexto de TCC","is_optimal":false,"immediate_outcome":"Você sugere que a irritação dele pode ser um medo de descobrir coisas sobre si mesmo ou de melhorar. Marcos se sente atacado e misinterpretado. A conversa vira uma discussão defensiva sobre motivações, arruinando o clima colaborativo e o foco no aqui-e-agora.","long_term_effect":"","impact":{"rapport":1,"insight":4,"behavioral_change":1,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":6,"session_title":"Trabalhando Crenças Centrais e o Medo da Recuperação","session_phase":"advanced","session_content":{"narrative":"Marcos traz dois registros de pensamentos incompletos. Um deles captura uma situação em que um colega de trabalho não respondeu a uma mensagem. O pensamento automático foi ''Ele me acha incompetente e chato'', seguido de tristeza e isolamento. Ao explorar, identifica-se a distorção de ''leitura mental'' e ''personalização''. Juntos, geram uma resposta alternativa mais equilibrada. Marcos demonstra habilidade crescente nesse processo. No entanto, ao final da análise, ele fica quieto e então comenta: ''Se eu melhorar e parar de ser tão... assim... as pessoas vão esperar que eu seja sempre normal. E se eu não conseguir? É menos pior elas já me verem como o deprimido''. Este é um momento crucial, indicando o surgimento de uma ''crença central'' (ex.: ''Sou defeituoso'') e uma ''crença positiva sobre a doença'' (a depressão como escudo). A sessão explora esse medo da recuperação e a função que o estado depressivo pode ter, sem julgamentos.","session_goals":["Consolidar a habilidade de identificar e questionar pensamentos automáticos em situações sociais","Explorar e validar o medo da recuperação e as crenças subjacentes que sustentam a depressão"],"key_observations":["Paciente mostra capacidade inicial de usar ferramentas cognitivas (identificar distorções), indicando progresso","Surgimento de fala sobre o ''medo de melhorar'', sinalizando trabalho em nível de crenças centrais (ex.: incompetência, defeito) e possíveis ganhos secundários (a depressão como identidade estável)","O afeto durante este relato é de ansiedade e vulnerabilidade, um sinal de que temas nucleares estão sendo tocados"],"critical_decision_point":"Como você trabalha essa ambivalência entre a mudança e a segurança da depressão?"},"expert_commentary":"O ''medo da recuperação'' é um marco no tratamento da depressão crônica. A opção ótima (A) segue a estratégia de trabalhar com ''crenças positivas sobre o problema'' (Beck, 2011). Primeiro, valida-se e explora-se a função (proteção, previsibilidade). Isso reduz a defesa e aumenta a insight. Só então se introduz uma redefinição da recuperação como ''expansão de escolhas'' e ''flexibilidade'', não como um estado de perfeição inatingível. Essa abordagem respeita a ambivalência do paciente (conceito da Entrevista Motivacional integrado à TCC) e trabalha no nível das crenças centrais (''preciso ser perfeito para ser aceito'') de forma indireta e menos ameaçadora.","learning_focus":"Trabalho com crenças centrais e ambivalência em fases avançadas da terapia para depressão","decision_options":[{"option_letter":"A","intervention":"Validar o medo e explorar a função protetora da depressão, antes de desafiar a crença","approach":"Abordagem baseada em TCC para crenças, integrando conceitos motivacionais","is_optimal":true,"immediate_outcome":"Você responde: ''É compreensível sentir isso. A depressão, por mais que doe, se tornou um território conhecido. Vamos entender o que ela parece proteger você?'' Isso normaliza sua ambivalência. Explorando, Marcos articula que a depressão ''justifica'' suas falhas e afasta a pressão. Você então pergunta: ''E se a recuperação não fosse sobre ser ''sempre normal'', mas sobre ter mais escolhas, inclusive a de dizer não ou de ter dias ruins, mas sem o sofrimento constante?''. Isso abre espaço para redefinir a recuperação de forma menos ameaçadora.","long_term_effect":"","impact":{"rapport":9,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Confrontar diretamente a crença, afirmando que é irracional e um obstáculo","approach":"Abordagem confrontativa e não empática","is_optimal":false,"immediate_outcome":"Você argumenta que isso é uma ''crença disfuncional'' que está impedindo seu progresso e que ele não pode querer ficar doente. Marcos se sente criticado e incompreendido. Ele se retrai emocionalmente, concordando superficialmente para encerrar o assunto, mas internalizando mais culpa. A exploração do tema é abortada.","long_term_effect":"","impact":{"rapport":2,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Garantir que, uma vez curado, as expectativas serão manejáveis e ele será ''normal''","approach":"Abordagem de tranquilização ingênua e promessa irrealista","is_optimal":false,"immediate_outcome":"Você tenta acalmá-lo, dizendo que quando ele melhorar, tudo será mais fácil e as pessoas serão compreensivas. Isso soa como um clichê para Marcos, que não acredita. A intervenção é superficial e não aborda o medo real de falhar sob novas expectativas. A credibilidade terapêutica diminui.","long_term_effect":"","impact":{"rapport":5,"insight":2,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar de assunto para evitar o desconforto do paciente","approach":"Abordagem evitativa do terapeuta","is_optimal":false,"immediate_outcome":"Percebendo a ansiedade de Marcos, você rapidamente retorna ao registro de pensamentos anterior, dizendo que podem trabalhar nisso mais tarde. Isso ensina ao paciente que temas difíceis devem ser evitados, reforçando a evitação como estratégia. Perde-se um momento terapêutico rico e profundo.","long_term_effect":"","impact":{"rapport":4,"insight":1,"behavioral_change":1,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":7,"session_title":"Desafiando a Triade Cognitiva","session_phase":"middle","session_content":{"narrative":"Marcela, 34 anos, chega à sessão relatando um leve aumento na energia, mas sua visão negativa sobre si mesma, o mundo e o futuro persiste. Ela menciona ter conseguido fazer uma caminhada curta, mas imediatamente desqualifica o feito: ''Fiz, mas não adianta, continuo sendo uma fracassada''. Você nota que o humor deprimido e a anedonia (critérios A1 e A2 do DSM-5-TR para Depressão Maior) ainda são centrais, mas há uma abertura para o trabalho cognitivo. Durante a sessão, você utiliza o registro de pensamentos automáticos que foi combinado na sessão anterior. Marcela traz um exemplo recente: ao receber um feedback neutro no trabalho, seu pensamento foi ''Meu chefe acha que sou incompetente, vou ser demitida''. A emoção associada foi desespero e a consequência comportamental foi o isolamento. O foco da sessão é começar a questionar a validade desses pensamentos, introduzindo o conceito de distorções cognitivas, como a leitura mental e a catastrofização.","session_goals":["Identificar e registrar pensamentos automáticos negativos em situações específicas.","Introduzir e psicoeducar sobre distorções cognitivas comuns na depressão."],"key_observations":["Paciente demonstra capacidade de monitorar pensamentos, mas com autocrítica severa.","Houveram ganhos comportamentais mínimos (caminhada), mas a cognição permanece rígida e negativa.","A aliança terapêutica está consolidada, permitindo um trabalho mais direto sobre cognições."],"critical_decision_point":"Como você procede para desafiar este pensamento de forma colaborativa?"},"expert_commentary":"A opção ótima (A) segue o princípio de Beck de ''cientista colaborativo''. Em vez de confrontar, convida a paciente a testar sua crença, o que é menos ameaçador e mais empoderador. Conforme Beck (2011) enfatiza, ''as experiências comportamentais fornecem os dados mais convincentes para modificar crenças disfuncionais''. A opção B, embora tecnicamente correta sobre a distorção, é prematura e autoritária, podendo gerar resistência. As opções C e D são suportivas, mas não promovem mudança cognitiva, essencial nesta fase do tratamento.","learning_focus":"Habilidade de conduzir o questionamento socrático e desenhar experimentos comportamentais para testar pensamentos automáticos.","decision_options":[{"option_letter":"A","intervention":"Propor um experimento comportamental simples: ''E se você pedisse um esclarecimento breve sobre o feedback na próxima oportunidade?''","approach":"Abordagem Cognitivo-Comportamental focada em testar crenças através da ação.","is_optimal":true,"immediate_outcome":"Marcela reluta, mas aceita considerar a ideia. Isso coloca a crença como uma hipótese a ser testada, não um fato, reduzindo a angústia imediata e criando uma ponte para a reestruturação cognitiva.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Confrontar diretamente a distorção: ''Isso é uma leitura mental. Você não pode saber o que ele pensa.''","approach":"Confrontação psicopedagógica.","is_optimal":false,"immediate_outcome":"Marcela se sente invalidada e corrigida, respondendo com ''Você não entende...''. A aliança é abalada e ela se fecha, interrompendo o processo de questionamento.","long_term_effect":"","impact":{"rapport":3,"insight":2,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Mudar de tópico para uma área onde ela se sente mais confortável, evitando o desconforto.","approach":"Evitação para preservar o rapport.","is_optimal":false,"immediate_outcome":"O alívio é momentâneo, mas reforça a esquiva como estratégia de coping. A crença central de incompetência não é abordada, e o progresso terapêutico estagna.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Validar apenas o sofrimento: ''Deve ser muito difícil se sentir assim constantemente.''","approach":"Apoio empático sem intervenção ativa.","is_optimal":false,"immediate_outcome":"Marcela se sente acolhida, mas a intervenção não avança na mudança cognitiva. A sessão termina com validação, mas sem novos insights ou ferramentas para a paciente.","long_term_effect":"","impact":{"rapport":8,"insight":4,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":8,"session_title":"Analisando Evidências e Desenvolvendo Pensamentos Alternativos","session_phase":"middle","session_content":{"narrative":"Marcela inicia a sessão relatando que não realizou o experimento comportamental (pedir esclarecimento ao chefe). Ela diz que a ansiedade foi grande demais. No entanto, trouxe novos registros de pensamentos. Você valida o esforço de registro e, sem criticar a evitação, explora o que a impediu. Juntos, identificam que o pensamento ''Vou gaguejar e parecer ainda mais incompetente'' foi um obstáculo. Você decide, então, trabalhar na técnica de análise de evidências para o pensamento original (''Meu chefe acha que sou incompetente''). Em uma folha, dividem colunas para ''Evidências a Favor'' e ''Evidências Contra''. Inicialmente, Marcela preenche rapidamente a coluna a favor com generalizações (''Ele não me elogiou'', ''Eu sempre erro''). Com perguntas guiadas, você a ajuda a identificar evidências contra: ''Você foi promovida há dois anos'', ''Ele continua te delegando tarefas importantes''. Aos poucos, um pensamento alternativo mais balanceado começa a surgir: ''O feedback foi neutro, não negativo. Posso não estar no meu melhor, mas isso não me define como incompetente''.","session_goals":["Aplicar a técnica de análise de evidências para um pensamento automático central.","Gerar um pensamento alternativo mais realista e menos disfuncional."],"key_observations":["Paciente demonstra resistência comportamental, mas engajamento cognitivo no registro.","A habilidade de identificar evidências contra é inicialmente deficitária, indicando rigidez cognitiva.","O pensamento alternativo gerado é ainda frágil, mas representa um primeiro passo crucial na reestruturação."],"critical_decision_point":"Como você responde a essa desconexão entre cognição racional e crença emocional?"},"expert_commentary":"A opção A é clinicamente sofisticada. Reconhece a distinção entre crenças automáticas, intermediárias e centrais, conceito fundamental no modelo de Beck. Judith Beck (2011) destaca que ''as crenças centrais são mantidas mesmo na presença de evidências contrárias''. Validar a emoção enquanto direciona para a estrutura subjacente é essencial para progressos duradouros. A opção B é mecanicista e ignora o afeto. A opção C abandona a estrutura da TCC, retrocedendo. A opção D é iatrogênica, replicando uma invalidação que pode ser parte da história do paciente.","learning_focus":"Habilidade de identificar e começar a abordar crenças centrais, diferenciando-as de pensamentos automáticos, e manejar a resistência cognitivo-afetiva.","decision_options":[{"option_letter":"A","intervention":"Normalizar a desconexão e introduzir o conceito de ''crença central'': ''É comum acreditar racionalmente, mas não sentir. Isso pode apontar para uma crença mais profunda, como ''Sou defeituosa''. Podemos explorar isso?''","approach":"Psicoeducação e sondagem para crenças intermediárias/centrais.","is_optimal":true,"immediate_outcome":"Marcela se sente compreendida e aliviada. Ela identifica a crença ''Sou inadequada'' como um tema de vida. Isso direciona o tratamento para um nível mais profundo, validando sua experiência emocional enquanto avança no modelo cognitivo.","long_term_effect":"","impact":{"rapport":9,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Insistir no pensamento alternativo: ''Vamos repeti-lo mais algumas vezes para você se acostumar. A sensação virá com o tempo.''","approach":"Repetição e reforço.","is_optimal":false,"immediate_outcome":"Marcela executa a tarefa de forma mecânica, mas o ceticismo aumenta. Ela pode sentir que sua experiência emocional está sendo ignorada, levando a um compliance superficial sem mudança genuína.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Descartar o pensamento alternativo e voltar a explorar apenas a dor emocional: ''Me conte mais sobre esse sentimento de ser um peso.''","approach":"Exploração emocional sem estrutura cognitiva.","is_optimal":false,"immediate_outcome":"A sessão se torna catártica, mas desestruturada. Marcela sai mais angustiada e sem novas ferramentas para manejar o sofrimento, possivelmente reforçando o foco no conteúdo negativo.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Minimizar a importância da sensação: ''Não se preocupe com o sentimento agora, o importante é a lógica.''","approach":"Racionalização extrema.","is_optimal":false,"immediate_outcome":"Marcela sente que sua experiência interna é invalidada. A aliança terapêutica é prejudicada, e ela pode parar de compartilhar seus verdadeiros sentimentos nas próximas sessões.","long_term_effect":"","impact":{"rapport":3,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":9,"session_title":"Lidando com a Crença Central e Planejando Ações de Autocuidado","session_phase":"advanced","session_content":{"narrative":"Com base na sessão anterior, você e Marcela mapearam a crença central ''Sou inadequada''. Ela conecta essa crença a experiências de infância (exigência extrema dos pais) e padrões atuais (perfeccionismo no trabalho, evitação social). O humor de Marcela oscila entre tristeza e uma certa clareza. Ela relata: ''É doloroso ver esse padrão, mas de alguma forma faz sentido''. Você psicoeduca sobre como a depressão ativa e fortalece essas crenças adormecidas. O foco da sessão é duplo: 1) Começar a desafiar a crença central não como ''verdade absoluta'', mas como ''uma hipótese aprendida''; 2) Planejar ações de autocuidado e domínio que sejam inconsistentes com a crença ''sou inadequada''. Marcela sugere retomar um hobby antigo (pintura), mas imediatamente se sabota: ''Vou fazer tudo errado''. Você a ajuda a quebrar a atividade em passos mínimos e não-ameaçadores (''comprar um pincel e uma tela pequena'', ''pintar por 5 minutos sem julgamento'').","session_goals":["Iniciar o trabalho de reestruturação da crença central ''Sou inadequada'' de forma compassiva.","Planejar e comprometer-se com atividades de domínio e prazer graduais, antagônicas à depressão."],"key_observations":["Paciente demonstra insight psicológico significativo ao conectar padrões passados e presentes.","A crença central ainda é poderosa, mas agora está ''sobre a mesa'' como um alvo terapêutico explícito.","O perfeccionismo surge como um mecanismo de coping disfuncional que mantém a depressão."],"critical_decision_point":"Como você intervém para quebrar esse ciclo de previsão negativa e evitação?"},"expert_commentary":"A opção A é a intervenção de TCC mais pura e eficaz. Ela desloca o sucesso do produto (a pintura) para o processo (testar uma hipótese e praticar autocuidado), alinhando-se com a ideia de ''experiência comportamental'' como ferramenta primária de mudança. Conforme Leahy (2017), ''a evitação mantém a depressão; a ativação comportamental a desafia''. A opção B é um erro comum de bem-intencionados, mas coloca o terapeuta como ''torcedor'', aumentando a pressão. A opção C é muito cautelosa e pode ser pouco eficaz. A opção D, embora relevante, é mal-timed; a análise histórica é importante, mas não deve substituir a ação no presente que gera nova aprendizagem.","learning_focus":"Habilidade de usar reestruturação cognitiva e planejamento de atividades para desafiar crenças centrais diretamente, promovendo ativação comportamental compassiva.","decision_options":[{"option_letter":"A","intervention":"Reenquadrar a tarefa e a crença: ''O objetivo não é pintar uma obra-prima. O objetivo é testar a hipótese de que você é 100% inadequada. Apenas comprar o material já é um ato de cuidado que contradiz essa crença. Podemos focar só nesse primeiro passo?''","approach":"Reestruturação cognitiva focada no processo (não no resultado) e no valor comportamental como evidência contrária.","is_optimal":true,"immediate_outcome":"Marcela respira aliviada. A pressão por performance é reduzida e a tarefa se torna um experimento válido, independente do resultado final. Isso fortalece a agência e enfraquece a crença de maneira prática.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Aumentar a motivação com incentivo: ''Claro que você vai pintar! Você é capaz, tenho certeza. Vai ser lindo!''","approach":"Apoio motivacional otimista.","is_optimal":false,"immediate_outcome":"Isso coloca mais pressão em Marcela. Se ela falhar, a decepção será maior (consigo mesma e com o terapeuta). Reforça a ideia de que seu valor depende do sucesso da tarefa, não do processo de tentativa.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Reduzir a tarefa para algo ainda menor: ''Então não compre. Apenas pesquise preços de tinta online.''","approach":"Gradação excessiva para evitar ansiedade.","is_optimal":false,"immediate_outcome":"Embora bem-intencionada, essa opção pode reforçar a crença de que ela é tão frágil que não consegue nem sair de casa. Pode não gerar evidência suficientemente forte para desafiar a inadequação.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Explorar apenas a origem da previsão negativa: ''De onde vem essa certeza de que vai falhar? Vamos pensar na sua infância...''","approach":"Análise histórica no momento da ação.","is_optimal":false,"immediate_outcome":"Muda o foco da ação presente para a análise do passado no momento crítico. Pode ser uma forma de evitação intelectual, adiando a experiência comportamental corretiva que é necessária.","long_term_effect":"","impact":{"rapport":7,"insight":7,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":10,"session_title":"Revisando o Plano de Ativação e Enfrentando a Evitação","session_phase":"middle","session_content":{"narrative":"A sessão começa com Lucas, 32 anos, relatando que conseguiu realizar duas das três atividades agendadas da semana (ir à academia e preparar uma refeição), mas evitou o encontro com amigos. Ele descreve um aumento da ansiedade antecipatória no dia do encontro, seguida de alívio ao cancelar, mas depois de uma intensificação da ruminação e da autocrítica (''sou um fracasso social''). Seu humor permanece deprimido, com anedonia persistente em contextos sociais. Ele menciona que a ideia de ''ter que ser divertido'' o paralisa. Você observa que, apesar do progresso nas atividades instrumentais, a evitação social permanece um núcleo importante da depressão, funcionando como um mecanismo de manutenção do transtorno. A sessão é dedicada a revisar o registro de atividades e pensamentos automáticos associados à situação evitada, explorando a conexão entre evitação, humor e autoconceito.","session_goals":["Revisar a tarefa de ativação comportamental da semana, validando sucessos e analisando obstáculos.","Identificar e desmontar o ciclo de evitação-ansiedade-alívio-depressão em situações sociais."],"key_observations":["O paciente demonstra capacidade de seguir com atividades instrumentais, mas a evitação social persiste como um padrão central.","O alívio de curto prazo ao evitar reforça negativamente o comportamento, mas gera consequências depressogênicas de longo prazo (ruminação, autocrítica)."],"critical_decision_point":"Como você procede para trabalhar essa crença central de desvalorização social?"},"expert_commentary":"A opção A é ótima porque integra insight cognitivo com ação, princípio central da TCC. Como Beck et al. (1979) destacam, ''as crenças disfuncionais são mais facilmente modificadas quando o paciente é encorajado a agir de modo contrário a elas''. Um experimento comportamental oferece dados empíricos que desafiam a crença de forma mais potente que o debate verbal. A estruturação (encontro breve) reduz a barreira da ansiedade, aumentando a probabilidade de adesão. É crucial manter o foco no ''teste'' e na coleta de evidências, não no ''desempenho''.","learning_focus":"Desenho e implementação de experimentos comportamentais para testar crenças centrais e reduzir evitação.","decision_options":[{"option_letter":"A","intervention":"Propor um experimento comportamental para a próxima semana: combinar um encontro breve e estruturado (ex.: tomar um café por 30 minutos) para testar a previsão catastrófica.","approach":"Abordagem baseada em TCC clássica, focada em coleta de evidências comportamentais.","is_optimal":true,"immediate_outcome":"Lucas, embora ansioso, aceita o desafio como um ''teste de realidade''. Isso gera um objetivo concreto e move o foco da ruminação para a ação e observação, promovendo aprendizagem corretiva.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Questionar socraticamente a evidência que sustenta essa crença, pedindo exemplos passados onde ele ''estragou o clima''.","approach":"Abordagem cognitiva pura, focada na reestruturação verbal.","is_optimal":false,"immediate_outcome":"Lucas tem dificuldade em acessar memórias específicas e fica mais defensivo, afirmando ''é só uma sensação que eu tenho''. O trabalho fica muito abstrato e não gera avanço prático.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Validar o sentimento como compreensível dada a depressão, e sugerir adiar o enfrentamento social até que ele se sinta mais confiante.","approach":"Abordagem excessivamente centrada na validação e no alívio imediato.","is_optimal":false,"immediate_outcome":"Lucas sente-se aliviado no momento, mas a evitação é reforçada. A mensagem implícita é de que a crença é válida e ele não é capaz, reduzindo a autoeficácia e estagnando o progresso.","long_term_effect":"","impact":{"rapport":8,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Interpretar a crença como um reflexo de um esquema de incompetência social formado na infância, explorando suas origens.","approach":"Abordagem psicodinâmica, fora do escopo da TCC focada no presente.","is_optimal":false,"immediate_outcome":"A discussão torna-se histórica e pouco focada na solução do problema atual. Lucas pode se sentir mais compreendido em um nível profundo, mas não sai com ferramentas para mudar seu padrão atual, prejudicando o momentum terapêutico.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":11,"session_title":"Resultado do Experimento e Lida com a Autocrítica Pós-Social","session_phase":"advanced","session_content":{"narrative":"Lucas comparece à sessão relatando que realizou o experimento: encontrou-se com um amigo para um café de 40 minutos. Ele descreve ter ficado muito ansioso antes, mas durante o encontro a ansiedade diminuiu. No entanto, após o evento, ele mergulhou em uma análise minuciosa e crítica de ''tudo que disse de errado'', focando em um momento de silêncio que interpretou como ''estranho''. Seu humor piorou nas horas seguintes. Ele traz o registro do experimento, que mostra que a previsão catastrófica (''vou estragar tudo'') não se confirmou, mas uma nova camada de processamento pós-evento surgiu. Você valida a coragem de Lucas e o fato objetivo de que ele não ''estragou o clima'' (o amigo até combinou outro encontro). A sessão se concentra em analisar esse padrão de autocrítica pós-social e seu papel em anular ganhos comportamentais, mantendo os sintomas depressivos de acordo com o modelo cognitivo.","session_goals":["Analisar os dados do experimento comportamental, destacando a discrepância entre previsão e realidade.","Identificar e intervir no padrão de processamento pós-eventos sociais (ruminação e autocrítica)."],"key_observations":["O paciente foi capaz de realizar a ação enfrentada (exposição), mas o benefício foi neutralizado por um processo cognitivo posterior de hipervigilância e autojulgamento.","A crença central de desvalorização adaptou-se, mudando de ''vou estragar o evento'' para ''eu fui inadequado durante o evento'', mantendo o núcleo depressivo."],"critical_decision_point":"Como você responde a essa justificativa aparentemente racional para a autocrítica?"},"expert_commentary":"A opção A é ótima porque oferece tanto compreensão (psicoeducação) quanto uma ferramenta comportamental concreta (Tempo de Preocupação). Nolen-Hoeksema (1991) demonstrou que a ruminação é um fator de manutenção crucial na depressão. Delimitar temporalmente esse processo é uma intervenção de primeira linha na TCC. A distinção entre avaliação útil e ruminação ajuda a desafiar a crença do paciente sobre a ''utilidade'' de seu comportamento, preparando o terreno para intervenções cognitivas mais profundas posteriormente. É um passo necessário antes de introduzir conceitos como autocompaixão.","learning_focus":"Psicoeducação sobre ruminação e implementação de técnicas de manejo de pensamentos repetitivos (estratégias de controle de estímulo).","decision_options":[{"option_letter":"A","intervention":"Psicoeducar sobre a diferença entre avaliação útil (focada em comportamento futuro) e ruminação autocrítica (focada no self e no passado), e introduzir a técnica de ''Tempo de Preocupação'' para delimitar esse processo.","approach":"Abordagem psicoeducativa e de manejo de sintomas da TCC.","is_optimal":true,"immediate_outcome":"Lucas entende a função disfuncional da ruminação. Ao agendar um ''tempo para refletir'', ele ganha um senso de controle sobre o processo. Isso reduz a intrusividade dos pensamentos e abre espaço para uma avaliação mais balanceada posteriormente.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Desafiar diretamente a crença de que a autocrítica é necessária para melhorar, perguntando: ''Em que medida se criticar tanto após um evento tem realmente te ajudado a melhorar socialmente?''.","approach":"Questionamento socrático direto sobre a utilidade da crença.","is_optimal":false,"immediate_outcome":"Lucas fica reflexivo e pode verbalmente concordar que não ajuda, mas a intervenção é muito cognitiva e não oferece uma ferramenta concreta para lidar com a automaticidade do processo no momento em que ele ocorre.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Sugerir que ele pratique a autocompaixão, repetindo frases como ''Foi bom ter saído, está tudo bem'' sempre que a autocrítica surgir.","approach":"Abordagem baseada em Terapia Focada em Compaixão, útil mas potencialmente prematura.","is_optimal":false,"immediate_outcome":"Lucas tenta, mas relata que as frases soam ''falsas'' e que a voz crítica é mais forte. Sem desmontar primeiro a crença na utilidade da crítica, a autocompaixão pode ser rejeitada como um ''jeito fraco'' de ser.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Explorar o significado emocional mais profundo por trás da necessidade de se criticar (ex.: medo de ser rejeitado se não for perfeito).","approach":"Abordagem exploratória de significados, desviando do foco no manejo do sintoma atual.","is_optimal":false,"immediate_outcome":"A discussão torna-se interessante, mas longa e pouco estruturada. Lucas pode ganhar insight sobre origens, mas não sai com uma estratégia prática para interromper o ciclo que está minando seus ganhos terapêuticos aqui e agora.","long_term_effect":"","impact":{"rapport":7,"insight":8,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"},{"session_number":12,"session_title":"Consolidando Novos Padrões e Planejando para Prevenção de Recaída","session_phase":"closing","session_content":{"narrative":"Lucas relata uma semana com menos oscilações de humor. Ele usou a técnica do ''Tempo de Preocupação'' duas vezes, conseguindo adiar a ruminação sobre uma interação no trabalho. Realizou outra atividade social (jantar em família) e, embora tenha notado pensamentos autocríticos depois, conseguiu aplicá-los à técnica. Ele traz espontaneamente uma reflexão: ''Parece que meu cérebro tem um piloto automático para o pior, mas agora estou aprendendo a colocar no manual''. Os sintomas depressivos (humor deprimido, anedonia, fadiga) apresentam redução moderada, mas persistente. A sessão é dedicada a consolidar os aprendizados, revisando o modelo cognitivo da sua depressão, os ciclos de evitação e ruminação que a mantinham, e as ferramentas que ele usou para quebrá-los. Inicia-se a discussão sobre a fase de encerramento da terapia, focando na autonomia e prevenção de recaída.","session_goals":["Revisar e consolidar o modelo de funcionamento da depressão e as habilidades de TCC aprendidas.","Iniciar o planejamento para prevenção de recaída, identificando sinais de alerta e planos de ação."],"key_observations":["O paciente demonstra internalização do modelo cognitivo, usando metáforas próprias para descrever seus processos. Isso indica boa generalização do aprendizado.","A redução sintomática é consistente, mas frágil. O foco agora deve ser em consolidar ganhos e preparar para lidar com futuros estressores sem recair no padrão depressivo."],"critical_decision_point":"Como você estrutura um plano de prevenção de recaída que seja robusto o suficiente para esse cenário de desesperança?"},"expert_commentary":"A opção A é ótima e segue diretrizes consagradas da TCC para prevenção de recaída (Beck, 2011). A chave é a externalização do plano: criar um recurso concreto e acessível fora do estado mental depressivo. Incluir um passo comportamental simples (caminhada) como primeira ação é crucial, pois atividades que aumentam a ativação podem facilitar o acesso subsequente a técnicas cognitivas. Este plano transforma uma preocupação abstrata (''e se eu esquecer'') em uma solução prática, empoderando o paciente e solidificando os ganhos terapêuticos.","learning_focus":"Elaboração colaborativa de um plano estruturado de prevenção de recaída, promovendo autonomia e generalização do tratamento.","decision_options":[{"option_letter":"A","intervention":"Criar, em colaboração, um ''Plano de Ação para Momentos Difíceis'' por escrito. Inclui: 1) Sinais de alerta; 2) Passos concretos e simples (ex.: ''Fazer uma caminhada de 10 min'' antes de tentar reestruturar pensamentos); 3) Contatos de apoio; 4) Releitura de cartões com suas principais habilidades aprendidas.","approach":"Abordagem estruturada e proativa da TCC para prevenção de recaída, focada em planejamento comportamental.","is_optimal":true,"immediate_outcome":"O plano escrito serve como um ''manual de instruções'' externo ao estado depressivo, contornando a dificuldade de acesso a memórias e recursos quando o humor piora. Aumenta a autoeficácia de Lucas e fornece um roteiro claro, reduzindo a sensação de desamparo.","long_term_effect":"","impact":{"rapport":8,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Assegurá-lo de que, como ele internalizou as técnicas, elas virão naturalmente quando necessário, e que ele pode sempre retornar para algumas sessões de ''reforço'' se precisar.","approach":"Abordagem de tranquilização e oferta de suporte futuro, mas pouco estruturada.","is_optimal":false,"immediate_outcome":"Lucas se sente temporariamente aliviado, mas a resposta não aborda sua preocupação real sobre a amnésia induzida pelo estado depressivo. O plano fica vago e dependente da iniciativa dele em um momento de baixa energia e desesperança, o que é justamente o problema.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Explorar o medo por trás da pergunta (''e se eu esquecer tudo''), ligando-o a uma crença mais profunda de fragilidade ou incompetência.","approach":"Abordagem focada em crenças profundas, desviando do objetivo prático de criar um plano de ação.","is_optimal":false,"immediate_outcome":"Embora possa gerar insight, isso consome o tempo da sessão sem produzir o produto concreto (o plano) que é fundamental para a prevenção de recaída. Lucas pode sair sem uma ferramenta tangível para lidar com uma crise futura.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Sugerir que ele marque sessões de acompanhamento mensais indefinidamente, para monitorar qualquer sinal de recaída.","approach":"Abordagem de dependência terapêutica, não promotora de autonomia.","is_optimal":false,"immediate_outcome":"Isso pode minar a autoeficácia de Lucas e criar uma dependência do terapeuta como principal recurso de coping, indo contra o objetivo final da TCC, que é tornar o paciente seu próprio terapeuta. Além disso, pode não ser viável logisticamente.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Depressao Maior","difficulty_level":"intermediate"}]'::jsonb
WHERE title ILIKE '%Jornada%' AND (
  title ILIKE '%009%' OR 
  title ILIKE '%0009%'
);

-- Journey 010
UPDATE clinical_journeys 
SET sessions = '[{"session_number":1,"session_title":"Mapeando o Labirinto: Primeiro Contato com as Obsessões","session_phase":"initial","session_content":{"narrative":"Você recebe Lucas, 28 anos, estudante de engenharia. Ele parece tenso e evita contato visual. Relata que sua vida está sendo \"sequestrada\" por pensamentos intrusivos e rituais. Com hesitação, descreve obsessões de contaminação por germes e substâncias químicas, levando a compulsões de lavagem das mãos e de objetos pessoais que consomem mais de 4 horas diárias. Ele também menciona pensamentos agressivos intrusivos sobre machucar acidentalmente familiares, que o aterrorizam e o levam a rituais mentais de repetição de frases ''protetoras''. Lucas relata que seus estudos estão prejudicados e que ele evita encontros sociais por medo de contaminação. Ele demonstra alto insight, reconhecendo que seus pensamentos e comportamentos são excessivos, mas sente uma ansiedade avassaladora se não os executar. A sessão é focada em estabelecer rapport, realizar uma avaliação inicial detalhada e começar a psicoeducação sobre o TOC.","session_goals":["Estabelecer aliança terapêutica e validar o sofrimento do paciente.","Realizar avaliação inicial dos sintomas, incluindo conteúdo das obsessões, compulsões, tempo de consumo e prejuízos funcionais."],"key_observations":["Paciente apresenta alto insight (DSM-5-TR: ''com insight bom ou razoável''), o que é prognóstico positivo.","Sintomas claramente enquadrados nos critérios do DSM-5-TR para TOC (F42): presença de obsessões e/ou compulsões, reconhecidas como excessivas, consumindo tempo (>1h/dia) e causando sofrimento significativo.","Ansiedade é o afeto central que sustenta o ciclo obsessivo-compulsivo."],"critical_decision_point":"O que você faz?"},"expert_commentary":"A opção A é ótima porque aborda diretamente a ''fusão pensamento-ação'' (crença de que ter um pensamento é moralmente equivalente a realizar o ato) e a ''importância excessiva dada aos pensamentos'', centrais no modelo cognitivo do TOC (Clark & Beck, 2011). Psicoeducar sobre a ego-distonia alivia a culpa e o autor julgamento, fortalecendo a aliança. Evitar o tema (C) ou fornecer reasseguramento (D) são armadilhas comuns que mantêm o transtorno. O questionamento precoce (B) pode ser útil mais tarde, mas primeiro é necessário normalizar e desmontar as crenças disfuncionais sobre os pensamentos.","learning_focus":"Psicoeducação inicial e manejo da fusão pensamento-ação para estabelecer base segura para a terapia.","decision_options":[{"option_letter":"A","intervention":"Normalizar e psicoeducar sobre a natureza ego-distônica das obsessões no TOC.","approach":"Psicoeducação e Validação","is_optimal":true,"immediate_outcome":"Você explica, citando conceitos de autores como David A. Clark no livro ''Cognitive Therapy for OCD'', que pensamentos intrusivos são comuns, mas no TOC ganham significado catastrófico. Enfatiza que o conteúdo é ego-distônico (contrário aos seus valores), e que a angústia que ele sente é justamente a prova de que não deseja aquilo. Lucas se acalma visivelmente, sentindo-se compreendido e menos ''monstruoso''.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Questionar racionalmente a probabilidade de ele agir conforme os pensamentos.","approach":"Questionamento Socrático Precoce","is_optimal":false,"immediate_outcome":"Você pergunta: ''Qual a evidência real de que você faria isso?''. Lucas tenta argumentar logicamente, mas a dúvida obsessiva (''e se?'') persiste. Ele concorda intelectualmente, mas a ansiedade não diminui significativamente, pois a intervenção não atacou a fusão pensamento-ação, núcleo da sua angústia.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Minimizar o conteúdo, focando apenas nas compulsões de lavagem.","approach":"Evitação do Tema Difícil","is_optimal":false,"immediate_outcome":"Você diz: ''Vamos focar no que está atrapalhando mais sua rotina, que é a lavagem''. Lucas concorda, mas fica com a impressão de que seu maior medo foi ignorado ou considerado muito vergonhoso para discussão. O rapport é prejudicado e um núcleo central do TOC fica fora da terapia.","long_term_effect":"","impact":{"rapport":4,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Garantir de forma tranquilizadora que ele nunca faria isso.","approach":"Reasseguramento Compulsivo","is_optimal":false,"immediate_outcome":"Você afirma com convicção: ''Claro que não, você é uma boa pessoa''. Lucas sente alívio imediato, mas breve. Em casa, a dúvida retorna (''Será que o terapeuta realmente me conhece?''), e ele sente necessidade de buscar mais reasseguramento, reforçando um ciclo compulsivo. A intervenção, embora bem-intencionada, é contraproducente para o TOC.","long_term_effect":"","impact":{"rapport":7,"insight":2,"behavioral_change":1,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":2,"session_phase":"middle","session_title":"Desenhando o Mapa da Ansiedade: Hierarquia de Exposição","session_content":{"narrative":"Com base no rapport estabelecido e na psicoeducação da sessão anterior, Lucas parece mais confiante. Você revisa o modelo cognitivo do TOC, explicando o ciclo obsessão-ansiedade-compulsão-alívio temporário. Lucas consegue identificar seus próprios gatilhos e rituais com mais clareza. O foco desta sessão é construir, em colaboração, uma Hierarquia de Exposição e Prevenção de Resposta (EPR). Juntos, listam situações, objetos e pensamentos que disparam ansiedade, desde os moderados (ex: tocar na maçaneta do banheiro de casa) até os mais temidos (ex: usar um banheiro público sem lavar as mãos depois, ou ter o pensamento intrusivo sobre a família sem neutralizá-lo). Lucas classifica cada item com uma Subjective Units of Distress Scale (SUDS) de 0 a 100. Ele demonstra alguma hesitação, mas também um frágil otimismo. A sessão é estruturada e colaborativa.","session_goals":["Construir, em colaboração com o paciente, uma hierarquia de exposição detalhada e personalizada.","Reforçar o entendimento do modelo de TOC e o racional da terapia de EPR."],"key_observations":["Paciente engajado no processo de construção da hierarquia, sinal de adesão ao tratamento.","É possível observar a ''tendência à fuga'' quando itens muito altos na hierarquia são mencionados, mas ele consegue se manter na tarefa com apoio.","A hierarquia cobre tanto exposições situacionais (contaminação) quanto imaginais (pensamentos intrusivos)."],"critical_decision_point":"Como você responde?"},"expert_commentary":"A opção A é a abordagem padrão-ouro da EPR. Como destacado por Jonathan Abramowitz em ''Exposure Therapy for Anxiety'', a colaboração e o início por itens sub-máximos são cruciais para o sucesso e a adesão. Validar o medo mantém o rapport. A inundação prematura (B) é eticamente questionável e arriscada. Acomodar (C) ou evitar (D) o item mais difícil reforça a patologia. É essencial manter o item no mapa da hierarquia, mas deixar claro que o caminho até ele será gradual, construindo autoeficácia.","learning_focus":"Construção colaborativa e manejo de ansiedades durante o planejamento da Hierarquia de Exposição e Prevenção de Resposta (EPR).","decision_options":[{"option_letter":"A","intervention":"Validar o medo, reafirmar o princípio da EPR e propor começar por um item de dificuldade baixa/média.","approach":"Validação + Princípio do Passo a Passo","is_optimal":true,"immediate_outcome":"Você diz: ''É completamente normal sentir esse medo. O objetivo da hierarquia é justamente mapear isso. Nunca começaríamos por aqui. Vamos escolher um item na faixa de SUDS 40-50 para nossa primeira prática na próxima sessão, para você construir confiança.'' Lucas se acalma, sente que sua ansiedade foi respeitada e que a terapia é desafiadora, mas manejável. A adesão é mantida.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Insistir que enfrentar o maior medo logo no início pode ser mais eficaz.","approach":"Inundação (Flooding) Prematura","is_optimal":false,"immediate_outcome":"Você argumenta, citando estudos de eficácia, que a inundação pode ser rápida. Lucas fica extremamente ansioso, questiona se você entende a gravidade do que está propondo. Ele pode concordar por submissão, mas o risco de abandonar a terapia ou de ter uma experiência traumática que sabote o tratamento é alto.","long_term_effect":"","impact":{"rapport":2,"insight":3,"behavioral_change":1,"symptom_reduction":0}},{"option_letter":"C","intervention":"Retirar o item do topo da hierarquia para aliviar a ansiedade imediata.","approach":"Acomodação da Evitação","is_optimal":false,"immediate_outcome":"Você diz: ''Tudo bem, vamos tirar esse por enquanto.'' Lucas sente alívio imediato, mas internaliza a mensagem de que alguns medos são intocáveis. Isso reforça a crença de que a ansiedade é intolerável e que a evitação é a única solução, enfraquecendo o modelo terapêutico.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar de tópico e focar apenas nas exposições situacionais de contaminação.","approach":"Evitação do Núcleo Cognitivo","is_optimal":false,"immediate_outcome":"Você propõe trabalhar só com a lavagem por enquanto. Lucas aceita, mas o núcleo mais angustiante do seu TOC (os pensamentos agressivos intrusivos) permanece fora do escopo da terapia. O progresso fica limitado e o risco de recaída é maior, pois as crenças disfuncionais centrais não são desafiadas.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":3,"session_phase":"middle","session_title":"Primeiros Passos na Exposição: Enfrentando o Gatilho","session_content":{"narrative":"Na sessão anterior, vocês decidiram começar por um item de dificuldade média (SUDS ~50): tocar no lixo da cozinha de casa e depois resistir à compulsão de lavar as mãos por, inicialmente, 5 minutos. Lucas chegou à sessão visivelmente ansioso, mas trouxe o ''diário de exposição'' preenchido com a prática realizada em casa. Ele relata que conseguiu realizar a tarefa, mas que a ansiedade subiu para 80 no pico e que os 5 minutos foram ''uma eternidade''. Ele descreve uma forte vontade de lavar as mãos, pensamentos catastróficos sobre doenças e um grande alívio quando o tempo acabou. No entanto, ele também nota que, após a primeira prática, a ansiedade de pensar em repetir a tarefa no dia seguinte foi um pouco menor. A sessão é dedicada a revisar essa primeira experiência de EPR, normalizar as dificuldades, analisar as crenças que surgiram durante a exposição e planejar o próximo passo.","session_goals":["Revisar e processar a primeira experiência de Exposição e Prevenção de Resposta (EPR).","Reforçar a aprendizagem de que a ansiedade diminui com a habituação e planejar a próxima exposição."],"key_observations":["Paciente demonstrou adesão e coragem ao realizar a tarefa de exposição prescrita.","Relato clássico de pico de ansiedade seguido de habituação incompleta (devido ao tempo limitado) e alívio pós-prevenção de resposta.","A auto-observação de que a ansiedade antecipatória diminuiu é um dado comportamental positivo crucial para motivar continuidade."],"critical_decision_point":"Como você conduz o processamento desta experiência?"},"expert_commentary":"A opção A é ideal porque transforma uma experiência percebida como ''fracasso'' (a ansiedade não sumiu) em um poderoso dado de psicoeducação. Explicar a curva da habituação e o papel da prevenção de resposta prolongada é central para a EPR (Foa & Kozak, 1986). A opção B é um reforço vazio sem aprendizagem. A opção C retrocede desnecessariamente, perdendo uma oportunidade de consolidar ganhos. A opção D, mesmo que válida para checar adesão (rituais sutis são comuns), foi feita de forma não-colaborativa, prejudicando a aliança. É melhor checar isso de forma curiosidade: ''Algum pensamento ou ação mental veio para tentar neutralizar a ansiedade?''.","learning_focus":"Processamento de experiências de exposição e psicoeducação sobre habituação para consolidar aprendizagem e manter a adesão.","decision_options":[{"option_letter":"A","intervention":"Psicoeducar sobre a curva da habituação e propor aumentar o tempo de prevenção de resposta gradualmente.","approach":"Psicoeducação Baseada em Dados + Planejamento Gradual","is_optimal":true,"immediate_outcome":"Você desenha a curva da ansiedade, explicando que a habituação (diminuição da resposta de medo) leva tempo e que interromper com a lavagem logo após 5 minutos impede que ele vivencie a queda natural. Propõe repetir o mesmo item, mas estendendo o tempo de prevenção de resposta para 10, depois 15 minutos. Lucas entende o racional e, embora receoso, concorda em tentar, baseado no pequeno sucesso da ansiedade antecipatória reduzida.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Focar exclusivamente no sucesso de ter completado a tarefa, elogiando muito.","approach":"Reforço Positivo sem Processamento Cognitivo","is_optimal":false,"immediate_outcome":"Você diz: ''Parabéns, você foi muito corajoso!''. Lucas se sente bem no momento, mas a dúvida central sobre a eficácia do método permanece. Sem entender o processo de habituação, sua motivação para repetir tarefas igualmente angustiantes pode diminuir, pois ele não vê a ''lógica'' por trás do sofrimento.","long_term_effect":"","impact":{"rapport":8,"insight":4,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Concordar que talvez o item tenha sido muito difícil e propor voltar para um mais fácil.","approach":"Retrocesso Excessivo por Desconforto","is_optimal":false,"immediate_outcome":"Você sugere: ''Vamos tentar algo mais leve, como tocar no interruptor''. Lucas sente alívio, mas internaliza que ''fracassou''. A hierarquia perde sua função de guia progressivo, e a terapia pode estagnar em itens que não geram mais aprendizagem significativa, por medo de eliciar ansiedade intensa.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Questionar se ele realmente segurou a ansiedade ou se fez rituais mentais durante os 5 minutos.","approach":"Confrontação Desconfiada","is_optimal":false,"immediate_outcome":"Você pergunta de forma cética: ''Tem certeza de que não fez nenhum ritual mental?''. Lucas se sente interrogado e desacreditado. Ele pode mentir para evitar julgamento ou ficar defensivo. O rapport é prejudicado, e a atmosfera colaborativa da terapia é quebrada.","long_term_effect":"","impact":{"rapport":3,"insight":5,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":4,"session_title":"Mapeando o Medo e a Rede de Rituais","session_phase":"middle","session_content":{"narrative":"A sessão começa com Lucas relatando um aumento significativo da ansiedade após a tarefa de casa da sessão anterior, que envolvia registrar seus pensamentos obsessivos. Ele chega visivelmente agitado, com as mãos trêmulas. Lucas detalha sua obsessão central: o medo catastrófico de contaminar sua família com produtos de limpeza, levando-os a uma morte lenta e dolorosa. Ele descreve uma complexa rede de rituais compulsivos que consomem mais de 4 horas diárias, incluindo lavagens específicas de mãos (sempre em múltiplos de 3), verificação meticulosa de torneiras e maçanetas, e a evitação completa do armário de limpeza. Ele menciona que sua esposa, Carla, começou a se afastar emocionalmente, frustrada com as restrições que o TOC impôs à rotina familiar. Lucas demonstra insight parcial, reconhecendo que seus medos são ''exagerados'', mas a ansiedade e a necessidade de neutralização são avassaladoras. Ele traz seu diário, cheio de anotações angustiadas, mas também com alguns momentos de dúvida sobre a lógica de seus rituais.","session_goals":["Estruturar uma hierarquia de exposição inicial baseada nos relatos do paciente.","Validar o sofrimento do paciente enquanto o orienta para o modelo cognitivo do TOC."],"key_observations":["Paciente apresenta alto sofrimento e prejuízo funcional significativo (DSM-5-TR F42.2).","Insight é bom (reconhece que as obsessões são produto da própria mente), mas a crença na necessidade do ritual permanece forte.","O relato da reação da esposa sugere impacto social e familiar, um fator de manutenção potencial."],"critical_decision_point":"Como você responde e conduz este momento crucial?"},"expert_commentary":"A opção A é ótima porque segue o princípio de ''validar o sofrimento, desafiar a solução disfuncional''. Como destacam Abramowitz et al. (2019), a psicoeducação sobre a natureza do ''viés de responsabilidade'' e da ''intolerância à incerteza'' no TOC é fundamental antes da ERP. A metáfora do ''bully'' é uma ferramenta cognitiva poderosa, criando um distanciamento entre o paciente e a doença, facilitando a adesão ao tratamento comportamental. Evitar a garantia (B) é crucial, pois ela é um ritual cognitivo que mantém o ciclo obsessivo-compulsivo.","learning_focus":"Psicoeducação avançada e formulação de caso colaborativa no TOC.","decision_options":[{"option_letter":"A","intervention":"Normalizar a dúvida e usar a metáfora do ''bully'' do TOC","approach":"Psicoeducação e reestruturação cognitiva metafórica","is_optimal":true,"immediate_outcome":"Você explica que a dúvida (''e se?'') é o combustível do TOC, comparando-o a um valentão que sempre pede mais provas. Você valida o medo, mas redireciona o foco para a necessidade de desafiar essa tirania, não de obter certeza. Lucas se acalma um pouco, sentindo-se compreendido, e aceita colaborar na construção de uma hierarquia.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Fornecer garantia lógica e racional sobre a improbabilidade do medo","approach":"Argumentação lógica e tranquilização","is_optimal":false,"immediate_outcome":"Você tenta tranquilizá-lo com dados sobre a toxicidade dos produtos e a robustez do sistema imunológico. Lucas concorda intelectualmente, mas sua ansiedade não diminui. Ele diz: ''Eu sei de tudo isso, mas o medo não some''. A sessão avança, mas o padrão de busca por garantia é reforçado.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Focar imediatamente na técnica de Exposição e Prevenção de Resposta (ERP)","approach":"Técnica comportamental direta","is_optimal":false,"immediate_outcome":"Você diz: ''A única forma é enfrentar. Na próxima sessão, vamos tocar na maçaneta do armário e não lavar as mãos''. Lucas fica aterrorizado, sente-se pressionado e desrespeitado em seu ritmo. A aliança terapêutica é abalada, e ele demonstra resistência para o resto da sessão.","long_term_effect":"","impact":{"rapport":3,"insight":5,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Explorar as origens infantis do seu medo de contaminação","approach":"Abordagem psicodinâmica prematura","is_optimal":false,"immediate_outcome":"Você pergunta se alguém na infância adoeceu gravemente. Lucas fica confuso, diz que não vê relação, e a ansiedade presente não é manejada. A sessão se perde em conjecturas históricas sem abordar os mecanismos de manutenção do TOC, e o progresso comportamental fica estagnado.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":5,"session_title":"Primeiros Passos na Hierarquia: Enfrentando a Intolerância à Incerteza","session_phase":"middle","session_content":{"narrative":"Com base na decisão anterior de usar a metáfora do ''bully'', Lucas chega mais engajado. Ele relata que, durante a semana, conseguiu identificar momentos em que o ''bully do TOC'' falava mais alto. Juntos, vocês constroem uma hierarquia de exposição com 10 itens, partindo de situações de ansiedade 3/10 (ex.: tocar no controle remoto após a esposa usá-lo) até 10/10 (ex.: limpar o banheiro com produto e depois preparar o jantar sem lavar as mãos). Lucas concorda em começar pelo item 4: ''Segurar a maçaneta externa da porta do armário de limpeza por 30 segundos e depois sentar no sofá sem lavar as mãos'' (ansiedade estimada em 5/10). Durante a sessão, ele realiza a primeira exposição in vivo. A ansiedade sobe para 7/10. Ele fica inquieto, suando, e repetidamente olha para as próprias mãos. A compulsão de lavar é intensa, mas ele consegue, com seu apoio e instruções de respiração, permanecer sentado e tolerar a ansiedade, que após 15 minutos diminui para 4/10. Ele se surpreende: ''Eu não morri, ninguém adoeceu... mas ainda está muito desconfortável''.","session_goals":["Realizar a primeira exposição in vivo com prevenção de resposta.","Monitorar e normalizar a curva de ansiedade durante a ERP."],"key_observations":["Paciente demonstra coragem e adesão ao plano, um prognóstico positivo.","A curva de ansiedade (pico e habituação) ocorreu conforme o esperado, um aprendizado comportamental crucial.","A fala ''mas ainda está muito desconfortável'' indica que a tolerância à incerteza está sendo construída, mas não resolvida."],"critical_decision_point":"Como você responde à tentativa de neutralização de Lucas?"},"expert_commentary":"A opção A é essencial. A Prevenção de Resposta (RP) é o componente mais crítico da ERP. Permitir qualquer neutralização (B), por mais sutil, reforça a crença de que a ansiedade é intolerável e perigosa. Como Foa et al. (2012) demonstram, a eficácia da ERP depende da violação das expectativas catastróficas. A resposta ótima educa o paciente sobre os padrões sutis do TOC (a ''trapaça''), fortalecendo seu papel de observador e combatente, não de vítima passiva.","learning_focus":"Implementação rigorosa e sábia da Prevenção de Resposta (RP) na ERP.","decision_options":[{"option_letter":"A","intervention":"Reforçar a prevenção de resposta e explorar a ''trapaça do TOC''","approach":"Consolidação dos princípios da ERP com reestruturação cognitiva","is_optimal":true,"immediate_outcome":"Você responde: ''Lucas, essa é uma jogada clássica do bully. Ele aceita a exposição, mas pede uma ''garantia de limpeza normal''. Se você fizer isso, estará dando o troféu de volta para ele. Podemos tolerar essa dúvida juntos agora?'' Lucas suspira, reconhece o padrão, e concorda em não limpar. A aprendizagem sobre a prevenção de resposta é profundamente internalizada.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Flexibilizar e permitir a ''limpeza rápida'' como um passo intermediário","approach":"Acomodação para manter a adesão","is_optimal":false,"immediate_outcome":"Você diz: ''Se for muito rápido e não seguir seu ritual, pode ser um meio-termo''. Lucas faz a limpeza e se acalma imediatamente. No entanto, na semana seguinte, ele relata que a ansiedade retornou mais forte, e ele começou a incorporar ''limpezas rápidas'' em seus rituais, invalidando o progresso da ERP.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Confrontá-lo de forma rígida: ''Isso é um ritual, você está sabotando o tratamento''","approach":"Confrontação punitiva","is_optimal":false,"immediate_outcome":"Lucas se sente envergonhado e criticado. Ele se retrai, diz ''tudo bem, eu não faço nada'', mas a aliança terapêutica é danificada. Ele pode até não limpar na hora, mas a probabilidade de realizar rituais encobertos ou abandonar o tratamento aumenta.","long_term_effect":"","impact":{"rapport":3,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Desviar o foco e marcar a próxima exposição","approach":"Evitação do processo cognitivo","is_optimal":false,"immediate_outcome":"Você ignora o comentário e diz: ''Ótimo progresso! Na próxima semana, vamos para o item 5''. Lucas sai confuso, sem saber como lidar com pensamentos de contaminação residual. A dúvida persiste e mina a confiança no processo, tornando as próximas exposições mais difíceis.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":6,"session_title":"Generalização e Lida com Recaídas Cognitivas","session_phase":"advanced","session_content":{"narrative":"Lucas chega relatando uma semana de altos e baixos. Ele conseguiu realizar várias exposições da hierarquia sozinho, incluindo tocar em sapatos que estavam na rua (item 6). No entanto, um evento desencadeou uma forte recaída: sua filha pequena teve um resfriado com febre. A obsessão de tê-la contaminado com ''produtos químicos que baixaram a imunidade'' tomou conta dele, levando a uma compulsão de verificação extrema (medir a febre dela a cada hora) e lavagens prolongadas. Ele está exausto e desmoralizado: ''Eu estava me sentindo tão bem, e agora parece que voltei à estaca zero. Será que esse tratamento realmente funciona para algo tão real?''. Ele demonstra que aprendeu as técnicas, mas a crença disfuncional subjacente (superestimação de ameaça e responsabilidade) foi reativada por um estressor real.","session_goals":["Normalizar a recaída como parte do processo e não como fracasso.","Aplicar reestruturação cognitiva a um evento desencadeante realista.","Planejar a generalização dos ganhos para situações imprevistas."],"key_observations":["Paciente aplicou habilidades de ERP de forma independente, indicando aprendizagem.","A recaída foi desencadeada por um evento de saúde real na família, um teste comum ao tratamento.","O discurso ''será que funciona para algo tão real?'' mostra uma fusão pensamento-evento típica do TOC, onde a coincidência é interpretada como causalidade.","A desmoralização é um risco para a desistência do tratamento."],"critical_decision_point":"Como você estrutura sua resposta para transformar esta recaída em um aprendizado terapêutico?"},"expert_commentary":"A opção A é a mais eficaz. Ela adere ao princípio de ''normalizar e capitalizar'' as recaídas. No TOC, situações de estresse real são testes de generalização inevitáveis. A resposta transforma a crise em um caso de ensino, aplicando o modelo cognitivo-comportamental ao evento específico. Isso fortalece a autoconfiança do paciente como seu próprio terapeuta, um objetivo central do tratamento. Evitar minimizar (B) ou punir (C) é crucial para manter a aliança e o progresso a longo prazo. A recaída é uma oportunidade de aprendizagem, não um sinal de falha do tratamento ou do paciente.","learning_focus":"Manejo de recaídas e promoção de generalização e autonomia no tratamento do TOC.","decision_options":[{"option_letter":"A","intervention":"Reenquadrar a recaída como um ''treino de alto nível'' e analisar o evento com ferramentas cognitivas","approach":"Reestruturação cognitiva e normalização baseada em modelo","is_optimal":true,"immediate_outcome":"Você responde: ''Lucas, isso não é voltar à estaca zero. É o treino mais importante: aplicar as regras do jogo em uma partida real. Vamos analisar: a febre da sua filha (evento real) ativou o ''bully'' (pensamento de contaminação), e você negociou com ele (rituais). Na próxima vez, podemos usar a mesma exposição? Tolerar a dúvida de que você NÃO causou o resfriado?'' Lucas se engaja na análise, percebe o padrão, e o desespero dá lugar a um plano de ação.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Minimizar o evento e focar apenas nos sucessos da semana","approach":"Reforço positivo seletivo","is_optimal":false,"immediate_outcome":"Você diz: ''Não foque nisso, veja quantas exposições você fez! Isso que importa''. Lucas concorda na sessão, mas sai sentindo que você não entendeu a gravidade de sua recaída. A crença disfuncional não é trabalhada, e ele fica sozinho com o medo, aumentando o risco de uma recaída mais grave.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Aumentar a dose de exposições para ''compensar'' a recaída","approach":"Abordagem comportamental rígida e punitiva","is_optimal":false,"immediate_outcome":"Você propõe: ''Precisamos ser mais agressivos. Sua tarefa será limpar o banheiro e depois abraçar sua filha sem lavar''. Lucas fica aterrorizado e se recusa, sentindo que o tratamento é desumano e não leva em conta seu contexto emocional. A adesão cai drasticamente.","long_term_effect":"","impact":{"rapport":2,"insight":4,"behavioral_change":1,"symptom_reduction":0}},{"option_letter":"D","intervention":"Explorar se há um ganho secundário ou resistência por trás da recaída","approach":"Interpretação psicodinâmica inapropriada","is_optimal":false,"immediate_outcome":"Você pergunta: ''O que esta recaída pode estar protegendo você de sentir?''. Lucas fica confuso e defensivo, respondendo: ''Protegendo? Eu quero é me livrar disso!''. A conversa se torna meta-cognitiva e desconectada do sofrimento presente, aumentando a frustração de Lucas.","long_term_effect":"","impact":{"rapport":4,"insight":2,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":7,"session_title":"Confrontando a Fusão Pensamento-Ação","session_phase":"middle","session_content":{"narrative":"O paciente, Rafael, chega à sétima sessão visivelmente ansioso. Ele relata que a exposição à contaminação (tocar na maçaneta do consultório sem lavar as mãos na sessão anterior) foi extremamente difícil, mas que conseguiu resistir ao ritual de limpeza por quase uma hora em casa. No entanto, um novo tema obsessivo emergiu com força: a ideia de que, ao pensar em algo ruim acontecendo com sua mãe, ele estaria aumentando a probabilidade real do evento ocorrer (fusão pensamento-ação). Ele passou a evitar certos pensamentos e a realizar rituais mentais de ''cancelamento'', repetindo frases positivas. Rafael expressa culpa e medo, dizendo: ''Se eu pensar, é como se eu estivesse desejando''. A sessão se concentra em psicoeducação sobre a natureza intrusiva e egodistônica dos pensamentos no TOC, diferenciando pensamento de ação ou desejo. Trabalhamos na ideia de que a tentativa de suprimir o pensamento (evitação experiencial) só aumenta sua frequência e o sofrimento, conforme descrito por Clark & Beck (2010).","session_goals":["Psicoeducar sobre a fusão pensamento-ação (FTA)","Normalizar a ocorrência de pensamentos intrusivos sem julgamento moral","Iniciar a desmontagem da crença de que pensar é equivalente a causar"],"key_observations":["O paciente demonstra insight sobre a irracionalidade, mas a crença é emocionalmente arraigada.","A ansiedade migrou de um tema (contaminação) para outro (pensamentos agressivos), padrão comum no TOC.","Há um componente moral e de responsabilidade excessiva na sua interpretação dos pensamentos."],"critical_decision_point":"Como você responde e conduz o próximo passo terapêutico?"},"expert_commentary":"A fusão pensamento-ação é um processo cognitivo central em subtipos de TOC (Shafran, Thordarson & Rachman, 1996). A abordagem ótima integra reestruturação cognitiva (explicar a FTA) com ERP comportamental/cognitivo. O experimento de escrever o pensamento é uma ERP clássica que promove a discriminação crucial entre ter um pensamento e realizar uma ação, desafiando a crença de onipotência do pensamento. Evitar o tema ou apenas racionalizar mantém o ciclo obsessivo.","learning_focus":"Aplicação de Exposição e Prevenção de Resposta (ERP) a obsessões puramente cognitivas (rituais mentais).","decision_options":[{"option_letter":"A","intervention":"Propor um experimento comportamental de ''exposição ao pensamento''.","approach":"TCC - Exposição e Prevenção de Resposta (ERP) para pensamentos.","is_optimal":true,"immediate_outcome":"Você orienta Rafael a escrever repetidamente o pensamento temido (''Minha mãe vai adoecer'') em uma folha, sem realizar rituais de cancelamento, e a observar a ansiedade diminuir naturalmente (habituação). Isso ataca diretamente a FTA, demonstrando que o pensamento não tem poder causal.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Reforçar a lógica e debater a crença com mais vigor.","approach":"Reestruturação Cognitiva pura.","is_optimal":false,"immediate_outcome":"Você apresenta mais argumentos racionais contra a FTA. Rafael concorda intelectualmente, mas sua ansiedade não diminui. A sessão fica em um impasse discursivo, e ele sai sentindo-se incompreendido, pois ''a sensação não some''.","long_term_effect":"","impact":{"rapport":4,"insight":6,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Validar o medo e sugerir distrações quando o pensamento surgir.","approach":"Suporte e manejo de ansiedade.","is_optimal":false,"immediate_outcome":"Rafael se sente acolhido, mas a sugestão de distração é interpretada como um novo ritual de esquiva. Ele passa a se distrair compulsivamente, o que reduz a ansiedade a curto prazo mas fortalece a crença de que o pensamento é perigoso e deve ser evitado.","long_term_effect":"","impact":{"rapport":8,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar de foco e retornar às exposições de contaminação, onde havia mais progresso.","approach":"Evitação do tema difícil.","is_optimal":false,"immediate_outcome":"Você redireciona a sessão para a hierarquia de contaminação. Rafael coopera, mas o núcleo da nova obsessão (FTA) não é abordado, permitindo que ela se fortaleça fora da terapia. O progresso fica fragmentado.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":8,"session_title":"A Resistência e o Custo dos Rituais","session_phase":"middle","session_content":{"narrative":"Rafael inicia a sessão relatando um misto de sucessos e fracassos. Ele realizou o experimento de escrever o pensamento sobre a mãe em casa, descrevendo a ansiedade como ''uma onda que subiu muito, ficou no pico e depois foi baixando''. No entanto, em um dia de estresse no trabalho, ele cedeu a um ritual mental prolongado. A narrativa se aprofunda na função dos rituais: Rafael descreve o alívio imediato e intenso que eles proporcionam, seguido por uma profunda vergonha e exaustão. Ele começa a verbalizar o custo do TOC em sua vida: ''Perco horas, não consigo me concentrar no que importa, estou sempre cansado''. Utilizando a metáfora do ''bully'' interno (Abramowitz, 2018), você o ajuda a externalizar o transtorno. Juntos, revisam o modelo cognitivo-comportamental do TOC, destacando como a interpretação catastrófica do pensamento intrusivo (avaliação) leva à ansiedade e aos rituais (compulsões), que por sua vez reforçam a crença original.","session_goals":["Explorar a função e o custo dos rituais (alívio vs. manutenção do ciclo)","Reforçar a adesão à ERP através do registro de tentativas","Ampliar a motivação para a mudança focando nos valores prejudicados pelo TOC"],"key_observations":["O paciente está desenvolvendo uma linguagem para descrever sua experiência (''onda de ansiedade''), indicando maior awareness emocional.","A recaída em um ritual ocorreu em contexto de estresse generalizado, um gatilho comum.","Há um embrião de ''fadiga do TOC'', que pode ser um motivador terapêutico potente se canalizado."],"critical_decision_point":"Como você trabalha para fortalecer a resistência aos rituais e a tolerância à ansiedade?"},"expert_commentary":"A recaída é uma oportunidade de aprendizado, não um fracasso. A abordagem ótima (A) integra princípios da ACT à TCC tradicional para o TOC, focando na flexibilidade psicológica (Twohig et al., 2015). Ajudar o paciente a conectar a tolerância à ansiedade com seus valores pessoais cria uma motivação intrínseca mais poderosa do que apenas ''seguir ordens do terapeuta''. As outras opções ou são iatrogênicas (B), superficiais (C) ou arriscam criar novas compulsões (D).","learning_focus":"Manejo de recaídas e integração de estratégias de aceitação e valores para aumentar a adesão à ERP.","decision_options":[{"option_letter":"A","intervention":"Trabalhar a aceitação da ansiedade e o foco nos valores.","approach":"Integração de ACT (Terapia de Aceitação e Compromisso) à TCC.","is_optimal":true,"immediate_outcome":"Você introduz a ideia de ''escolher sentir a ansiedade em nome do que é importante''. Questiona: ''O que o TOC te impede de fazer ou ser?''. Rafael identifica ''ser presente para a família'' como um valor. Você o encoraja a ver a ansiedade como um preço temporário a pagar para recuperar sua vida, não como um sinal de perigo. Isso aumenta sua resiliência.","long_term_effect":"","impact":{"rapport":8,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Aumentar drasticamente a dificuldade das exposições para ''quebrar'' a resistência.","approach":"ERP de alta intensidade.","is_optimal":false,"immediate_outcome":"Você propõe uma exposição massiva (ex: pensar repetidamente na morte da mãe enquanto olha para uma foto dela). Rafael se sente sobrecarregado e desrespeitado. Ele pode não comparecer à próxima sessão, rompendo a aliança terapêutica e a adesão ao tratamento.","long_term_effect":"","impact":{"rapport":2,"insight":4,"behavioral_change":1,"symptom_reduction":0}},{"option_letter":"C","intervention":"Minimizar a recaída e elogiar apenas os sucessos.","approach":"Reforço positivo seletivo.","is_optimal":false,"immediate_outcome":"Você diz ''Não se preocupe, o importante é que você tentou''. Rafael se sente momentaneamente melhor, mas a mensagem implícita é que recaídas são fracassos a serem ignorados. Isso impede uma análise funcional útil e pode fazer com que ele esconda futuras dificuldades.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Focar em técnicas de relaxamento para reduzir a ansiedade antes de enfrentar os rituais.","approach":"Controle da ansiedade como pré-requisito.","is_optimal":false,"immediate_outcome":"Você ensina respiração diafragmática. Rafael usa a técnica, mas acaba incorporando-a como um novo ritual de ''preparação'' ou mesmo de ''cancelamento'' sutil. A ansiedade pode diminuir temporariamente, mas a crença na necessidade de controlá-la se fortalece.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":9,"session_title":"Generalização e Prevenção de Recaída","session_phase":"advanced","session_content":{"narrative":"Na nona sessão, Rafael chega com um relatório escrito de suas atividades da semana. Ele descreve várias situações onde pensamentos intrusivos surgiram (no trânsito, antes de dormir) e ele praticou ''observar e deixar passar'', sem se engajar em rituais. Ele também realizou uma exposição planejada: usou o banheiro de um shopping sem realizar os rituais de limpeza prolongados. Seu humor está mais estável e ele relata ''mais espaço na cabeça'' para outras coisas. Vocês revisam o progresso desde a sessão 7, destacando a quebra do elo entre pensamento e ação (FTA) e o aumento da tolerância à incerteza. A sessão se volta para a generalização dos ganhos e a preparação para o futuro. Você apresenta o modelo de vulnerabilidade ao estresse, explicando que períodos de cansaço, doença ou mudanças podem temporariamente aumentar a intrusividade dos pensamentos. Juntos, elaboram um ''Plano de Ação para Momentos Difíceis'', um documento concreto que Rafael levará consigo.","session_goals":["Consolidar os ganhos terapêuticos e generalizar as habilidades aprendidas","Elaborar um plano de prevenção de recaída personalizado","Preparar o paciente para a eventual conclusão da terapia (futuro próximo)"],"key_observations":["O paciente está assumindo um papel ativo e de ''pesquisador'' de sua própria experiência, sinal de internalização do modelo terapêutico.","A autoeficácia de Rafael aumentou visivelmente.","É crucial antecipar e normalizar futuras flutuações nos sintomas para evitar desmoralização."],"critical_decision_point":"Como você responde a esta questão crucial sobre a natureza crônica e o manejo do TOC?"},"expert_commentary":"A pergunta do paciente é um marco terapêutico. A resposta ótima (A) alinha-se com as evidências: o TOC tem um curso crônico e flutuante. A meta realista é a remissão sustentada e a autogestão eficaz, não a eliminação absoluta dos pensamentos intrusivos (que são normais). A metáfora da condição crônica (Abramowitz, 2018) é honesta e empoderadora. Prometer cura (B) é antiético e iatrogênico. Evitar o tema (C) ou fomentar dependência (D) prejudica a autonomia e a prevenção de recaída.","learning_focus":"Psicoeducação para prevenção de recaída e estabelecimento de expectativas realistas para o manejo de longo prazo do TOC.","decision_options":[{"option_letter":"A","intervention":"Validar o realismo e reformular o objetivo: de ''cura'' para ''autogestão eficaz''.","approach":"Psicoeducação avançada e reestruturação de expectativas.","is_optimal":true,"immediate_outcome":"Você responde: ''Você está certo. O TOC é uma condição crônica, como a diabetes. O objetivo da terapia não é fazer os pensamentos sumirem para sempre – eles podem voltar – mas sim você se tornar o expert no seu próprio TOC, saber como não alimentá-lo e retomar sua vida rapidamente quando ele bater à porta. Você já tem as ferramentas para isso.'' Rafael assente, com uma expressão de determinação realista.","long_term_effect":"","impact":{"rapport":9,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Assegurar que com prática contínua, os sintomas desaparecerão completamente.","approach":"Promessa de cura total.","is_optimal":false,"immediate_outcome":"Você diz ''Se você continuar firme, uma hora seu cérebro se reprograma e isso some''. Rafael fica momentaneamente esperançoso, mas essa expectativa irreal o deixará devastado e sentindo-se fracassado quando, inevitavelmente, um pensamento intrusivo ressurgir no futuro, podendo levar a uma recaída grave.","long_term_effect":"","impact":{"rapport":7,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Desviar da pergunta e focar no sucesso atual.","approach":"Evitação da conversa difícil.","is_optimal":false,"immediate_outcome":"Você diz ''Vamos focar no quanto você evoluiu!''. Rafael percebe a evasão e internaliza que a perspectiva é tão ruim que nem o terapeuta quer falar sobre ela. Sua ansiedade sobre o futuro aumenta, e a confiança no plano de prevenção de recaída diminui.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Sugerir que talvez seja necessário manter terapia de suporte indefinidamente.","approach":"Dependência terapêutica.","is_optimal":false,"immediate_outcome":"Você diz ''Por isso a terapia de manutenção é importante, podemos continuar nos vendo mensalmente''. Embora o acompanhamento possa ser benéfico, a forma como é colocado sugere que Rafael não poderá seguir sozinho. Isso pode minar sua autonomia recém-adquirida e criar uma dependência desnecessária.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":10,"session_title":"Confrontando a Evitação: A Hierarquia em Ação","session_phase":"middle","session_content":{"narrative":"Na décima sessão, você encontra Lucas, um homem de 28 anos com TOC de contaminação (F42.2). Nas sessões anteriores, vocês mapearam suas obsessões (medo de contrair doenças graves ao tocar em maçanetas, dinheiro e corrimãos) e compulsões (lavagens rituais e evitação massiva). Juntos, construíram uma hierarquia de exposição e prevenção de resposta (EPR), graduada de 0 a 100. Hoje, o plano é iniciar os exercícios a partir de um item de dificuldade média (tocar na capa de um livro da sala de espera, SUA 45). Lucas chega visivelmente ansioso, mas motivado. Ele relata que, durante a semana, conseguiu observar seus pensamentos intrusivos sem se engajar em rituais mentais de ''neutralização'', uma técnica de reestruturação cognitiva trabalhada antes. No entanto, sua evitação comportamental permanece alta. Ele evita pegar o celular se achar que caiu no chão. O foco desta sessão é realizar a primeira exposição ''ao vivo'' (in vivo) dentro do setting terapêutico, um passo crucial para a generalização do aprendizado.","session_goals":["Realizar a primeira exposição in vivo a um item da hierarquia (SUA 45).","Reforçar o uso da prevenção de resposta (não lavar as mãos) por um período predeterminado."],"key_observations":["Lucas demonstra motivação, mas sua ansiedade antecipatória é fisiológica (mãos trêmulas, respiração acelerada).","Ele já internalizou o modelo cognitivo, identificando a superestimação de ameaça e o pensamento mágico por trás de seus rituais."],"critical_decision_point":"O que você faz?"},"expert_commentary":"A opção A é ótima porque equilibra validação empática com a fidelidade ao protocolo de EPR, que é o tratamento de primeira linha para TOC (Abramowitz, 2018). Validar (''É normal ficar nervoso, é sinal de que estamos no lugar certo'') reduz a resistência. Guiar passo a passo (''Vamos primeiro colocar a mão a 10 cm...'') quebra a tarefa em elementos manejáveis. O objetivo não é eliminar a ansiedade, mas ensinar ao paciente que ele pode tolerá-la e que ela diminui naturalmente (processo de habituação), desafiando a crença disfuncional de que a ansiedade é intolerável ou perigosa.","learning_focus":"Implementação colaborativa e guiada da Exposição e Prevenção de Resposta (EPR), manejando a resistência antecipatória com validação e psicoeducação.","decision_options":[{"option_letter":"A","intervention":"Validar a ansiedade, mas manter a proposta do item planejado, guiando-o com instruções passo a passo e ancorando-o na técnica de aceitação da ansiedade.","approach":"EPR com validação e suporte à tolerância ao desconforto.","is_optimal":true,"immediate_outcome":"Lucas, com suporte, toca o livro. A ansiedade sobe para 70 e depois diminui para 40 em 15 minutos, sem lavar as mãos. Ele experimenta a habituação e um grande senso de autoeficácia.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Ceder ao pedido dele e adiar a exposição, usando a sessão para revisar apenas os aspectos cognitivos do medo.","approach":"Evitação terapêutica, focando apenas em reestruturação cognitiva.","is_optimal":false,"immediate_outcome":"A aliança permanece intacta, mas o ciclo de evitação é reforçado. Lucas não tem a experiência corretiva de enfrentamento, e a credibilidade da hierarquia pode ser prejudicada.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Insistir rigidamente no plano original, minimizando seu desconforto: ''Lucas, nós combinamos isso. Tem que enfrentar para melhorar. Vamos lá.''","approach":"EPR autoritária e não colaborativa.","is_optimal":false,"immediate_outcome":"Lucas pode se sentir pressionado e executar a ação com ressentimento ou, pior, recusar-se, danificando a aliança terapêutica. A experiência fica associada a coerção.","long_term_effect":"","impact":{"rapport":3,"insight":4,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar imediatamente para um item mais fácil não planejado (olhar para uma foto), sem uma discussão clínica sobre a esquiva.","approach":"Reformulação impulsiva da hierarquia.","is_optimal":false,"immediate_outcome":"A exposição ocorre, mas em um nível muito baixo, gerando pouca aprendizagem de habituação. Pode passar a mensagem de que a evitação é uma estratégia aceitável para lidar com a ansiedade antecipatória.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":11,"session_title":"Lidando com a Resposta à Exposição e Rituais Encobertos","session_phase":"middle","session_content":{"narrative":"Na sessão 11, Lucas chega relatando um misto de conquista e angústia. Ele conseguiu tocar no livro e não lavou as mãos por uma hora, conforme combinado. No entanto, após a sessão, ele se pegou realizando um ''ritual encoberto'': repetiu mentalmente a frase ''isso é só um livro, não tem vírus'' diversas vezes para aliviar a ansiedade. Além disso, tentou fazer uma exposição caseira (tocar no corrimão do prédio, SUA 60), mas a ansiedade foi tão intensa que ele acabou lavando as mãos compulsivamente após 2 minutos, sentindo-se um fracasso. A narrativa de Lucas ilustra dois desafios comuns na fase média da EPR: 1) a emergência de compulsões mentais (rituais encobertos) que sabotam a prevenção de resposta, e 2) a dificuldade em generalizar e tolerar a ansiedade em exposições autoguiadas. Seu humor está mais disfórico, com pensamentos do tipo ''nunca vou conseguir vencer isso''.","session_goals":["Psicoeducar sobre rituais encobertos e sua interferência no processo de habituação.","Reestruturar cognições disfuncionais sobre ''fracasso'' e replanejar exposições autoguiadas de forma mais graduada."],"key_observations":["Lucas está aplicando as técnicas, mas encontra barreiras complexas (rituais cognitivos) que exigem refinamento da intervenção.","Sua autoavaliação é dicotômica (''sucesso total'' vs. ''fracasso total''), um padrão cognitivo típico no TOC."],"critical_decision_point":"Como você responde e direciona a sessão?"},"expert_commentary":"A opção A é ótima porque aborda diretamente os dois núcleos do problema relatado. Rituais encobertos são compulsões e devem ser alvo da prevenção de resposta tanto quanto os comportamentais (Foa et al., 2012). A psicoeducação sobre eles é crucial. Além disso, a reestruturação da cognição dicotômica (''tudo ou nada'') é um componente central da terapia cognitiva para TOC (Clark & Beck, 2011). Normalizar os contratempos e usá-los para recalibrar a hierarquia transforma uma experiência de ''fracasso'' em uma oportunidade de aprendizado colaborativo, mantendo a motivação e a adesão.","learning_focus":"Identificação e manejo de rituais encobertos (compulsões mentais) e integração de reestruturação cognitiva para lidar com cognições disfuncionais sobre o progresso na terapia.","decision_options":[{"option_letter":"A","intervention":"Explicar que rituais encobertos são uma forma sutil de compulsão que mantém o TOC, e propor um exercício de ''exposição ao pensamento'' sem neutralização. Reestruturar a cognição dicotômica, normalizando o ''deslize'' como parte do aprendizado.","approach":"Integração de EPR para rituais cognitivos e reestruturação cognitiva.","is_optimal":true,"immediate_outcome":"Lucas entende que a prevenção de resposta também se aplica a rituais mentais. Ele reformula o ''fracasso'' como um dado para ajustar a hierarquia (talvez o corrimão seja um SUA 75, não 60). A motivação é restaurada.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Focar apenas no ''sucesso'' (tocar no livro) e encorajá-lo a repetir a mesma exposição na semana, ignorando a discussão sobre os rituais encobertos e a frustração.","approach":"Reforço positivo sem abordar as dificuldades emergentes.","is_optimal":false,"immediate_outcome":"Lucas se sente invalidado em sua experiência negativa. Os rituais encobertos continuam não identificados e ativos, minando o progresso a longo prazo.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Criticar a lavagem das mãos após o corrimão como uma quebra grave do acordo, pressionando-o a se comprometer com mais ''força de vontade'' na próxima vez.","approach":"Confrontação punitiva e subestimação da ansiedade.","is_optimal":false,"immediate_outcome":"Lucas se sente envergonhado e menos propenso a relatar futuros ''deslizes''. A aliança terapêutica é danificada, e a terapia pode se tornar um fonte de estresse adicional.","long_term_effect":"","impact":{"rapport":2,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Sugerir abandonar as exposições autoguiadas por enquanto e voltar a fazer todas as exposições apenas no consultório, onde você pode supervisionar.","approach":"Superproteção e retirada da autonomia do paciente.","is_optimal":false,"immediate_outcome":"A generalização do tratamento é prejudicada. Lucas não desenvolve autoeficácia para lidar com os gatilhos no mundo real, mantendo uma dependência do terapeuta.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"},{"session_number":12,"session_title":"Consolidação e Prevenção de Recaída","session_phase":"advanced","session_content":{"narrative":"Na décima segunda sessão, Lucas apresenta um progresso notável. Ele tem realizado exposições a itens da parte média-alta de sua hierarquia (como usar um banheiro público, SUA 70) com prevenção de resposta bem-sucedida, e os rituais encobertos diminuíram significativamente. Sua ansiedade geral está menor e ele reporta ter recuperado horas do seu dia que antes eram consumidas por rituais. No entanto, um evento estressante recente (uma discussão familiar) desencadeou um ligeiro aumento na frequência de pensamentos intrusivos sobre contaminação, embora ele tenha conseguido não ceder a compulsões maiores. Lucas expressa medo: ''Fiquei assustado, pensei que estava voltando à estaca zero.'' Esta sessão ocorre em um momento de transição: a fase mais intensa de EPR está concluída, e o foco agora se desloca para a consolidação dos ganhos, o preparo para o encerramento e a prevenção de recaída. É hora de revisar o que funcionou, antecipar desafios futuros e fortalecer sua identidade como alguém que ''gerencia'' o TOC, e não mais é ''controlado'' por ele.","session_goals":["Consolidar os aprendizados e o progresso feito até o momento.","Elaborar um Plano de Prevenção de Recaída, antecipando gatilhos futuros e estratégias de coping."],"key_observations":["Lucas demonstra habilidades de coping adquiridas, conseguindo navegar por um aumento sintomático sem recair totalmente.","O medo de ''voltar à estaca zero'' é uma preocupação comum e um alvo importante para a psicoeducação sobre a natureza flutuante do TOC."],"critical_decision_point":"Como você estrutura esta discussão e a construção do plano?"},"expert_commentary":"A opção A é ótima porque segue os princípios estabelecidos de prevenção de recaída em terapias comportamentais e cognitivas. O objetivo realista para o TOC não é a erradicação dos pensamentos intrusivos (que são universais), mas a mudança na relação com eles e a eliminação dos rituais que os mantêm (DSM-5-TR). Um plano escrito, co-criado, transforma o paciente no especialista de sua própria recuperação, promovendo autonomia. Como Hiss, Foa e Kozak (1994) destacaram, um programa de prevenção de recaída que inclui psicoeducação, antecipação de situações de risco e revisão de técnicas é fundamental para manter os ganhos terapêuticos a longo prazo no TOC.","learning_focus":"Consolidação de ganhos, psicoeducação para prevenção de recaída e transição da terapia para a autogestão do paciente, promovendo autonomia e resiliência.","decision_options":[{"option_letter":"A","intervention":"Psicoeducar sobre a diferença entre ''cura'' e ''controle'' no TOC, normalizando a flutuação dos sintomas sob estresse. Guiá-lo a listar seus gatilhos de risco, sinais de alerta precoce e o ''kit de ferramentas'' de estratégias (EPR, reestruturação cognitiva, aceitação) que ele já domina.","approach":"Psicoeducação para prevenção de recaída e empoderamento baseado em habilidades adquiridas.","is_optimal":true,"immediate_outcome":"Lucas sai com um plano concreto e escrito, sentindo-se preparado e menos temeroso. Ele internaliza que recaídas parciais são oportunidades de aplicar suas habilidades, não sinais de fracasso.","long_term_effect":"","impact":{"rapport":9,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Minimizar suas preocupações, assegurando-o de que, como ele progrediu tanto, é muito improvável que os sintomas voltem.","approach":"Garantias irreais e subestimação do risco de recaída.","is_optimal":false,"immediate_outcome":"Lucas fica temporariamente aliviado, mas se um futuro surto sintomático ocorrer, ele pode se sentir traído pela terapia e despreparado para lidar com isso, aumentando o risco de uma recaída grave.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Focar a sessão inteiramente em revisitar técnicas de exposição complexas, criando novos itens de hierarquia extremamente difíceis para ''imunizá-lo'' completamente.","approach":"Superenfase em EPR sem trabalhar os aspectos psicológicos do encerramento e da autonomia.","is_optimal":false,"immediate_outcome":"O plano de prevenção de recaída não é feito. Lucas pode associar o fim da terapia a uma pressão por desempenho máximo, aumentando a ansiedade e não desenvolvendo uma mentalidade de autogestão a longo prazo.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Adiar a discussão sobre o plano e focar em explorar as raízes profundas do TOC na infância de Lucas, sugerindo que entender isso é a chave para evitar recaídas.","approach":"Mudança para uma abordagem psicodinâmica no momento inadequado.","is_optimal":false,"immediate_outcome":"Desvia o foco do trabalho comportamental-cognitivo consolidado. Pode confundir o paciente e deixá-lo sem um plano prático para os desafios iminentes após o encerramento.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno Obsessivo-Compulsivo","difficulty_level":"intermediate"}]'::jsonb
WHERE title ILIKE '%Jornada%' AND (
  title ILIKE '%010%' OR 
  title ILIKE '%0010%'
);

-- Journey 011
UPDATE clinical_journeys 
SET sessions = '[{"session_number":1,"session_title":"Acolhimento e Construção da Linha do Tempo do Trauma","session_phase":"initial","session_content":{"narrative":"Você recebe Lucas, 32 anos, bombeiro civil, referenciado após testemunhar o colapso fatal de um colega durante um incêndio há oito meses. Lucas relata insônia, pesadelos recorrentes com imagens do acidente, irritabilidade e evitação de qualquer notícia ou local que lembre o trabalho. Ele se mostra vigilante, com postura rígida, e descreve um sentimento de ''embotamento'' e distanciamento da família. Durante a sessão, você valida seu sofrimento, explica o modelo cognitivo do TEPT e propõe a construção conjunta de uma ''linha do tempo do trauma'' para organizar os eventos e suas reações. Lucas concorda, mas ao começar a descrever o dia do acidente, sua voz falha e ele desvia o olhar, tensionando os músculos da mandíbula. Ele menciona, de passagem, um sentimento intenso de culpa por ''não ter feito o suficiente''.","session_goals":["Estabelecer rapport e psicoeducação sobre TEPT","Iniciar a organização narrativa do evento traumático (linha do tempo)"],"key_observations":["Paciente apresenta hipervigilância e embotamento afetivo claros","Menção espontânea à culpa, um potencial cognição pós-traumática central","Resposta de congelamento/evitação ao abordar detalhes do trauma"],"critical_decision_point":"O que você faz?"},"expert_commentary":"A opção A é ótima porque segue o princípio de ''nomear para dominar'' e a técnica de validação emocional, crucial no TEPT. Como ressalta Foa et al. (2019) na Terapia de Exposição Prolongada, a validação reduz a vergonha e facilita a abordagem de memórias aversivas. A exploração cognitiva (B) é necessária, mas só após estabelecido um ambiente seguro e alguma habituação emocional. As opções C e D, embora comuns, sabotam os mecanismos de tratamento.","learning_focus":"Validação emocional e manejo da evitação no início da narrativa traumática","decision_options":[{"option_letter":"A","intervention":"Validar a dificuldade e focar na emoção presente","approach":"Abordagem centrada na emoção e validação","is_optimal":true,"immediate_outcome":"Você diz: ''É muito difícil tocar nisso. Posso perceber o peso dessa culpa aqui agora.'' Lucas suspira, faz contato visual e concorda, dizendo que carrega isso todos os dias. Isso normaliza sua reação e fortalece a aliança para trabalhar a culpa.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"B","intervention":"Pedir para ele detalhar o pensamento de culpa","approach":"Exploração cognitiva direta","is_optimal":false,"immediate_outcome":"Você pergunta: ''O que exatamente você acha que poderia ter feito diferente?'' Lucas se fecha, responde ''Não sei, tudo'', e a evitação aumenta, interrompendo o fluxo da narrativa. A exploração prematura pode ser retraumatizante.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Mudar de tópico para aliviar o desconforto","approach":"Evitação do terapeuta","is_optimal":false,"immediate_outcome":"Você diz: ''Vamos voltar a isso depois. Conte-me mais sobre seu dia antes do acidente.'' Lucas parece aliviado no momento, mas internaliza que o tópico é muito perigoso, reforçando seu padrão de evitação e prejudicando a exposição gradual.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Minimizar a culpa com racionalização","approach":"Reestruturação cognitiva prematura","is_optimal":false,"immediate_outcome":"Você argumenta: ''Mas você fez o melhor que pôde na situação.'' Lucas responde com irritação: ''O senhor não estava lá.'', sentindo-se invalidado. A intervenção, embora bem-intencionada, ignora a necessidade de primeiro acessar e validar a experiência emocional.","long_term_effect":"","impact":{"rapport":3,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":2,"session_title":"Exposição à Memória e Identificação de Cognições","session_phase":"middle","session_content":{"narrative":"Com base na aliança fortalecida na sessão anterior, você revisa a linha do tempo e propõe a primeira sessão de Exposição à Memória Traumática (EMT), focada no momento mais angustiante: ver o colega soterrado. Você conduz Lucas em uma respiração diafragmática e o guia na narrativa viva do evento, com os olhos fechados. Lucas relata, com voz trêmula, os detalhes sensoriais (o cheiro de queimado, o som do desabamento). Ao final, sua SUD (Unidades Subjetivas de Perturbação) cai de 90 para 70. No processamento, ele verbaliza a cognição: ''Sou um fracasso como bombeiro''. Você também nota que ele descreveu o evento de forma desconectada (''como se estivesse vendo um filme''), um sinal de dissociação peritraumática. Ele pergunta, ansioso: ''Contar isso de novo vai mesmo ajudar?''","session_goals":["Realizar a primeira EMT para promover habituação","Identificar cognições traumáticas centrais (ex: ''Sou um fracasso'')"],"key_observations":["Houve redução inicial da SUD, indicando início de habituação","Cognição negativa ''Sou um fracasso'' identificada claramente","Relato de despersonalização (''ver um filme'') durante o trauma"],"critical_decision_point":"Como você processa esta primeira exposição e responde à sua dúvida?"},"expert_commentary":"A opção A é ótima porque integra validação, normalização e psicoeducação baseada nos dados da própria sessão (SUD). Shapiro (2018), no modelo do TEPT, enfatiza a importância de vincular a redução da angústia ao processamento adaptivo da memória. A reestruturação (B) é etapa seguinte. Adiar a EMT (C) é contraproducente, pois a evitação é o núcleo da patologia. Focar na dissociação (D) é importante, mas deve ser feito após validar a experiência global do paciente.","learning_focus":"Processamento pós-exposição e uso de dados da sessão para psicoeducação e engajamento","decision_options":[{"option_letter":"A","intervention":"Normalizar a exaustão, elogiar a coragem e conectar a redução da SUD ao processo de habituação","approach":"Psicoeducação baseada em dados e reforço","is_optimal":true,"immediate_outcome":"Você diz: ''É normal se sentir esgotado. Foi um ato de coragem. E note que sua angústia caiu de 90 para 70 só em uma vez - isso mostra que seu cérebro está começando a processar, não só a reviver.'' Lucas parece mais esperançoso e compreende a lógica do tratamento.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Focar apenas na cognição ''Sou um fracasso'' e desafiar com evidências","approach":"Reestruturação cognitiva imediata","is_optimal":false,"immediate_outcome":"Você questiona: ''Que evidências você tem de que é um fracasso?'' Lucas, ainda emocionalmente vulnerável, rebate: ''A única evidência que importa está morta.'' A intervenção falha por não consolidar a experiência da exposição antes de desafiar pensamentos.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Concordar que foi difícil e sugerir adiar a próxima EMT","approach":"Acomodação da evitação","is_optimal":false,"immediate_outcome":"Você diz: ''Foi intenso mesmo. Podemos trabalhar outras coisas na próxima sessão.'' Lucas concorda com alívio, mas o adiamento reforça a crença de que a memória é intolerável, prejudicando a curva de habituação e o progresso.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Ignorar a dúvida e focar no relato dissociativo (''ver um filme'')","approach":"Foco clínico rígido no sintoma","is_optimal":false,"immediate_outcome":"Você pergunta: ''Fale mais sobre essa sensação de ver um filme.'' Lucas se confunde, sentindo que sua preocupação prática foi ignorada. A aliança terapêutica é tensionada, e uma oportunidade de psicoeducação crucial é perdida.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":3,"session_title":"Integrando a Dissociação e Trabalhando a Culpa","session_phase":"middle","session_content":{"narrative":"Lucas chega relatando que teve menos pesadelos na semana, mas que evitou passar pelo quartel do corpo de bombeiros. Na segunda EMT, a SUD inicial foi menor (75), caindo para 55. A narrativa foi mais fluida e conectada. No processamento, você explora a cognição ''Sou um fracasso'' e a liga ao relato dissociativo da sessão anterior. Lucas reflete: ''Talvez eu tenha me sentido um fracasso porque congelei... na hora, foi tudo como um sonho ruim.'' Você propõe uma técnica de reestruturação cognitiva, usando a perspectiva do ''colega soterrado'' para desafiar a culpa. Lucas se mostra receptivo, mas ao imaginar o que o colega diria, fica emocionado e cala. Ele então pergunta, com certa vergonha: ''Isso significa que eu sou fraco por ter ''desligado'' na hora?''","session_goals":["Processar a dissociação peritraumática e conectá-la à cognição de culpa","Iniciar a reestruturação cognitiva da autocrítica severa"],"key_observations":["Redução consistente da SUD entre sessões, indicando habituação","Paciente começa a fazer conexões entre sintoma (dissociação) e cognição (culpa)","Emoção de vergonha associada à resposta dissociativa surge como novo alvo"],"critical_decision_point":"Como você responde a esta nova camada de culpa/vergonha?"},"expert_commentary":"A opção A é ótima porque ataca diretamente a cognição de vergonha com informação científica poderosa e desculpabilizante. Van der Kolk (2014) destaca que entender as respostas traumáticas como biológicas, e não morais, é libertador para o paciente. A exploração (B) é válida, mas secundária. A validação pura (C) é insuficiente. O exemplo (D) pode ser útil, mas deve ser complementado com a explicação neurobiológica para ser eficaz.","learning_focus":"Psicoeducação sobre respostas neurobiológicas ao trauma para reduzir culpa e vergonha secundárias","decision_options":[{"option_letter":"A","intervention":"Psicoeducar sobre a dissociação como uma reação neurobiológica automática de sobrevivência","approach":"Normalização baseada na neurociência do trauma","is_optimal":true,"immediate_outcome":"Você explica: ''A dissociação não é fraqueza, é um ''circuito de emergência'' do cérebro diante de um estresse extremo. Foi o que seu sistema fez para você sobreviver àqueles momentos. Muitos sobreviventes de trauma experienciam isso.'' Lucas relaxa a postura, assimilando a informação com um ''nunca tinha pensado por esse lado''.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Explorar as crenças subjacentes sobre ''força'' e ''fraqueza''","approach":"Exploração cognitiva de crenças nucleares","is_optimal":false,"immediate_outcome":"Você pergunta: ''O que significa ser ''fraco'' para você?'' A discussão se aprofunda em valores rígidos, mas Lucas, ainda preso à vergonha, tem dificuldade de se engajar. A psicoeducação necessária para desbloquear a vergonha é postergada.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Validar apenas o sentimento sem corrigir a cognição","approach":"Validação sem psicoeducação corretiva","is_optimal":false,"immediate_outcome":"Você diz: ''É realmente difícil carregar essa vergonha.'' Lucas concorda, mas a crença disfuncional de que é ''fraco'' permanece intacta. Perde-se uma oportunidade crucial de intervenção que poderia aliviar significativamente seu sofrimento.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Contar sobre outro paciente com reação similar para normalizar","approach":"Normalização por exemplo (com cautela)","is_optimal":false,"immediate_outcome":"Você comenta: ''Já atendi outros bombeiros que passaram por algo parecido.'' Lucas parece um pouco menos sozinho, mas pergunta: ''E eles também se sentiram fracos?'' A intervenção é incompleta e pode desviar o foco do processo individual para comparações.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":4,"session_title":"Revisitando o Trauma: Introdução à Exposição Narrativa","session_phase":"middle","session_content":{"narrative":"João, um motorista de ônibus de 42 anos, chega à sessão visivelmente tenso. Ele relata que, na semana anterior, após a psicoeducação sobre reações de estresse, conseguiu identificar um padrão: sempre que vê um acidente de trânsito leve, mesmo na TV, seu coração dispara e ele tem a sensação de ''estar lá de novo''. Ele descreve brevemente o trauma principal: há dois anos, atropelou um pedestre que atravessou a rua correndo em um dia de chuva, não conseguindo frear a tempo. O paciente demonstra vergonha e culpa intensa, repetindo ''eu poderia ter feito algo diferente''. O foco da sessão é construir uma linha do tempo de vida (timeline) para contextualizar o evento traumático dentro de sua história, uma técnica da Terapia de Exposição Narrativa. João reluta inicialmente, mas consegue listar memórias positivas de infância e momentos difíceis anteriores, como a perda do pai. Quando chega próximo ao evento do atropelamento, ele fica em silêncio, evita o contato visual e sua respiração fica ofegante.","session_goals":["Construir uma linha do tempo de vida para contextualizar o trauma","Iniciar a exposição à memória traumática de forma estruturada e segura"],"key_observations":["Paciente demonstra hipervigilância e reatividade fisiológica ao discorrer sobre o trauma","Culpa e vergonha são emoções centrais na narrativa do evento","Capacidade de engajamento na técnica, apesar da evidente angústia"],"critical_decision_point":"O que você faz?"},"expert_commentary":"A opção A é ótima porque segue o princípio da ''exposição graduada'' e do ''controle do estímulo'' (Foa et al., 2007). Em TEPT, a exposição deve ser feita de forma que o paciente não seja retraumatizado. Interromper para uma técnica de aterramento (grounding) ensina ao paciente que ele pode modular sua angústia e que a memória não é incontrolável. Isso fortalece a autoeficácia, um componente crucial para o processamento emocional do trauma. A opção B ignora a janela de tolerância, arriscando uma dissociação. A C reforça a evitação, mantendo o sintoma. A D é uma interpretação inadequada no momento de alta ativação emocional.","learning_focus":"Psicoeducação e Regulação Emocional","decision_options":[{"option_letter":"A","intervention":"Validar a dificuldade e guiá-lo em um exercício de ancoragem no presente.","approach":"Abordagem de regulação emocional e estabilização antes de prosseguir.","is_optimal":true,"immediate_outcome":"Você diz: ''Isso é muito difícil, e é normal a memória vir com tanta força. Vamos respirar juntos aqui, no meu consultório. Sinta os pés no chão.'' João consegue se acalmar parcialmente, sente-se contido pela sua postura e concorda em fazer uma pausa na narrativa detalhada, focando apenas em fatos gerais por hoje. A aliança terapêutica se fortalece.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"B","intervention":"Incentivá-lo gentilmente a ''passar por isso'' e descrever o que vê, garantindo que está seguro agora.","approach":"Exposição prolongada padrão, insistindo na descrição da memória.","is_optimal":false,"immediate_outcome":"João tenta, mas a angústia se torna incontrolável. Ele descreve fragmentos caóticos (''chuva, o barulho, o rosto'') e entra em um estado de dissociação moderada, ficando com o olhar vidrado. A sessão termina com ele exausto e com medo de retornar, sentindo-se sobrecarregado.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Mudar completamente de assunto para aliviar a pressão, perguntando sobre sua semana.","approach":"Evitação do conteúdo traumático para reduzir o desconforto imediato.","is_optimal":false,"immediate_outcome":"João fica confuso com a mudança abrupta. Embora aliviado no momento, ele internaliza que o tema é intocável e que você não pode ajudá-lo a enfrentá-lo. A evitação é reforçada, e o progresso na exposição é interrompido.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Interpretar a culpa dele, dizendo: ''Parece que você se sente responsável por algo que estava fora do seu controle.''","approach":"Interpretação psicodinâmica prematura.","is_optimal":false,"immediate_outcome":"João reage com irritação: ''Claro que eu era responsável, eu estava dirigindo! O senhor não estava lá.'' Ele se fecha, sentindo que sua experiência e sua culpa estão sendo invalidadas. O rapport é abalado.","long_term_effect":"","impact":{"rapport":3,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":5,"session_title":"Processando a Memória: Detalhamento e Distinção Passado-Presente","session_phase":"middle","session_content":{"narrative":"João inicia a sessão relatando que, após a última sessão, praticou a técnica de ancoragem em casa quando se sentiu ansioso. Ele demonstra um pouco mais de confiança. Retomando o trabalho da linha do tempo, vocês se concentram na narração detalhada do evento traumático, mas desta vez com um roteiro mais estruturado. Você o guia a descrever o que aconteceu antes, durante e depois do atropelamento, focando em fatos, pensamentos, emoções e sensações físicas (protocolo de Exposição Narrativa/Prolongada). João consegue narrar com mais fluência, mas sua voz falha ao descrever o momento do impacto. Ele menciona pensamentos intrusivos recorrentes: ''Eu sou um assassino'' e flashbacks do rosto da vítima. Um avanço importante ocorre quando ele identifica que o som da chuva forte ainda o dispara. Você utiliza a psicoeducação para explicar a natureza das memórias traumáticas não processadas.","session_goals":["Realizar a exposição prolongada à memória traumática de forma controlada","Trabalhar a distinção cognitiva entre ''então'' (perigo passado) e ''agora'' (segurança presente)","Identificar e desafiar cognições iniciais relacionadas à culpa"],"key_observations":["Paciente mostra maior capacidade de tolerância afetiva do que na sessão anterior","Cognição central de culpa (''Eu sou um assassino'') é claramente identificada","Reatividade a estímulos condicionados (chuva) é reconhecida pelo paciente"],"critical_decision_point":"Como você responde para trabalhar essa cognição traumática?"},"expert_commentary":"A opção A é ideal porque integra a exposição com a reestruturação cognitiva, abordando diretamente a cognição traumática (um dos pilares do TEPT no DSM-5-TR: ''Cognições ou humor negativos persistentes e distorcidos''). A pergunta socrática convida o paciente a ser um investigador de seu próprio pensamento, promovendo insight e flexibilidade cognitiva. A opção B (reassurance) é bem-intencionada, mas ineficaz para modificar crenças profundas. A C subutiliza o momento clínico rico. A D é iatrogênica, pois o perdão é um processo que vem após a reavaliação da culpa, não um comando.","learning_focus":"Reestruturação Cognitiva de Cognições Traumáticas","decision_options":[{"option_letter":"A","intervention":"Explorar a evidência: ''Vamos examinar esse pensamento. O que um ''assassino'' faz? E o que você, João, fez naquele dia?''","approach":"Reestruturação Cognitiva Socrática integrada à narrativa do trauma.","is_optimal":true,"immediate_outcome":"Você guia João a diferenciar um ato intencional de homicídio de um acidente em condições adversas. Ele começa a separar a intenção do resultado, reconhecendo que sua culpa é pelo desfecho trágico, não por uma ação maligna. Isso gera um alívio significativo e um primeiro passo para reprocessar o significado do evento.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Oferecer apoio incondicional: ''João, você não é um assassino. Foi um acidente terrível, e você é uma boa pessoa.''","approach":"Suporte e reassurance direto.","is_optimal":false,"immediate_outcome":"João ouve, mas responde: ''O senhor diz isso porque é seu trabalho.'' A reassurance externa não é internalizada porque não modifica a crença central. Ele se sente acolhido, mas a cognição distorcida permanece intacta, limitando o progresso.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Pedir para ele repetir a narração do evento, focando apenas nas sensações físicas, sem abordar o pensamento.","approach":"Exposição pura, evitando o componente cognitivo.","is_optimal":false,"immediate_outcome":"João obedece, mas a angústia retorna sem a elaboração do significado. A sessão se torna uma repetição exaustiva sem ganho cognitivo. Ele pode sair sentindo que a terapia apenas o faz reviver a dor sem entender ou superá-la.","long_term_effect":"","impact":{"rapport":5,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Sugerir que ele deve perdoar a si mesmo para seguir em frente.","approach":"Foco prematuro no perdão.","is_optimal":false,"immediate_outcome":"João reage com frustração: ''Como posso me perdoar? Uma pessoa morreu.'' A sugestão é experimentada como pressão e uma minimização de sua culpa real. Isso pode criar uma nova barreira, fazendo-o acreditar que seu sofrimento é ''errado'' ou que ele é incapaz de se recuperar.","long_term_effect":"","impact":{"rapport":4,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":6,"session_title":"Integração e Enfrentamento de Estímulos Condicionados","session_phase":"advanced","session_content":{"narrative":"João chega relatando um pequeno, mas significativo, progresso: conseguiu dirigir em uma garagem fechada durante uma chuva fraca sem ter um ataque de pânico completo, usando as técnicas de respiração. Ele traz à tona que o pensamento ''eu sou um assassino'' ainda aparece, mas agora ele consegue ''responder'' mentalmente com ''foi um acidente''. A sessão é dedicada a consolidar os ganhos e planejar a exposição in vivo aos estímulos condicionados. Juntos, vocês elaboram uma hierarquia de situações temidas relacionadas ao trauma, desde ouvir o som de chuva em um app (menos ansiogênico) até passar pelo local do acidente (mais ansiogênico). João também revela que evita noticiários e que se isolou de amigos que são motoristas. Ele demonstra motivação para retomar atividades, mas teme uma recaída. A narrativa do trauma é revisitada brevemente, e nota-se uma redução na reatividade emocional e na dissociação.","session_goals":["Construir uma hierarquia de exposição in vivo para estímulos condicionados","Consolidar a narrativa integrada do trauma e os insights cognitivos","Planejar atividades de retomada de vida (reengajamento)"],"key_observations":["Há evidências de habituação dentro das sessões e generalização para fora (dirigir na chuva fraca)","Paciente começa a desenvolver ''respostas'' adaptativas às cognições intrusivas","A evitação social e de atividades persiste como um dos principais prejuízos funcionais"],"critical_decision_point":"Como você maneja essa antecipação ansiosa e o medo do fracasso?"},"expert_commentary":"A opção A é a mais eficaz na fase de exposição in vivo. Ela combina validação (normalizar o medo) com ação concreta (plano de coping), o que é essencial para superar a ''evitação fóbica'' característica do TEPT. Como descrito por Cahill & Foa (2007), a psicoeducação sobre a curva da ansiedade reduz o ''medo do medo''. Co-criar o plano empodera o paciente e aumenta a autoeficácia. A opção B é uma reassurance vazia. A C, embora pareça segura, pode ser uma armadilha de subdosagem terapêutica. A D é uma intervenção descontextualizada do marco terapêutico atual (TCC focada no trauma).","learning_focus":"Planejamento de Exposição In Vivo e Prevenção de Respostas de Evitação","decision_options":[{"option_letter":"A","intervention":"Normalizar o medo, revisar a psicoeducação sobre a ansiedade em forma de onda, e co-criar um plano de coping detalhado para cada passo.","approach":"Preparação comportamental e validação, enfatizando o controle e a previsibilidade.","is_optimal":true,"immediate_outcome":"Você responde: ''Esse medo é esperado. A ansiedade sobe, mas também desce. Vamos planejar: você ouve o som por apenas 2 minutos, com a técnica de respiração à mão, e depois me liga para me contar como foi.'' João se sente equipado e apoiado, não apenas desafiado. A adesão ao plano aumenta.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Encorajá-lo a ser corajoso e enfrentar, minimizando o risco: ''Confie no processo, você já mostrou que consegue. Não vai piorar.''","approach":"Reassurance otimista sem planejamento concreto.","is_optimal":false,"immediate_outcome":"João tenta, mas a insegurança permanece. Se ele tiver uma reação forte, pode interpretar como uma falha pessoal (''eu não fui corajoso o suficiente'') e uma quebra da sua promessa (''disse que não pioraria''), prejudicando a confiança e possivelmente desistindo do plano.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Rever a hierarquia e propor um item ainda mais fácil, como apenas olhar para uma foto de chuva.","approach":"Excessiva cautela que pode reforçar a evitação.","is_optimal":false,"immediate_outcome":"João fica aliviado no curto prazo, mas internaliza que sua capacidade de enfrentamento é menor do que realmente é. O progresso fica estagnado em um nível muito básico, prolongando desnecessariamente o tratamento.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Explorar psicodinamicamente o medo de piorar: ''O que ''piorar'' significaria para você? Parece haver um medo mais profundo.''","approach":"Exploração analítica do medo, desviando do planejamento comportamental.","is_optimal":false,"immediate_outcome":"A conversa se afasta do plano prático e entra em um terreno abstrato que confunde João no momento. Ele sai da sessão sem um plano claro para a semana, sentindo-se menos preparado e mais ansioso sobre o que fazer.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":7,"session_title":"Revisitando o Trauma: Introdução à Exposição Narrativa","session_phase":"middle","session_content":{"narrative":"A sessão começa com João, um motorista de ônibus que sofreu um grave acidente há um ano, relatando um aumento nos pesadelos após a última sessão, onde começou a falar sobre o evento. Ele parece ansioso, mas também demonstra um compromisso genuíno com o tratamento. Você valida sua coragem e revisa o modelo cognitivo do TEPT, conectando a evitação (tanto comportamental quanto cognitiva) com a manutenção dos sintomas. Juntos, vocês revisam a psicoeducação sobre a exposição prolongada, explicando sua base na habituação e na processamento emocional do trauma. Você propõe a criação de uma hierarquia de estímulos temidos, começando por itens menos angustiantes, como ouvir o som de freios. João reluta um pouco, mas concorda em tentar. O clima é de colaboração cautelosa, com João expressando medo de ''não aguentar'' reviver as memórias.","session_goals":["Introduzir e normalizar o protocolo de Exposição Prolongada (PE)","Construir uma hierarquia de estímulos temidos inicial e colaborativa"],"key_observations":["Paciente apresenta aumento sintomático inicial ao abordar o trauma, o que é esperado","Demonstra ambivalência: compromisso com a terapia mas medo do processo","A aliança terapêutica parece suficientemente sólida para avançar"],"critical_decision_point":"O que você faz?"},"expert_commentary":"A opção A é a mais aderente ao protocolo de Exposição Prolongada de Foa et al. (2007). O princípio é ''corrigir sem fugir'': validar a emoção, conter a ativação dentro de limites manejáveis e manter o curso da tarefa terapêutica. Isso demonstra ao paciente que memórias e afetos intensos podem ser tolerados e processados dentro do contexto seguro da terapia. Interromper completamente (B) ou forçar uma exposição prematura (C) são erros comuns. A citação de Foa é pertinente: ''A evitação mantém o medo; a confrontação o diminui''.","learning_focus":"Habilidade em implementar a fase inicial de exposição de forma estruturada e responsiva, balanceando validação emocional com progressão terapêutica.","decision_options":[{"option_letter":"A","intervention":"Validar a angústia, anotar o item como ponto alto da hierarquia, e retornar ao exercício de construção de forma estruturada.","approach":"Exposição Prolongada (Foa et al.) - Manejo da ativação dentro da estrutura do protocolo.","is_optimal":true,"immediate_outcome":"João se acalma ao sentir que o terapeuta mantém o controle da situação. A hierarquia fica mais precisa e pessoal, e ele aprende que pode tocar em memórias difíceis sem desintegrar-se.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"B","intervention":"Interromper imediatamente a hierarquia e conduzir um exercício de grounding para acalmá-lo.","approach":"Estabilização e regulação emocional prioritária.","is_optimal":false,"immediate_outcome":"João se acalma, mas a mensagem implícita é que o material é demasiadamente perigoso para ser abordado. Isso pode reforçar a evitação e dificultar o progresso na exposição.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Aproveitar o momento para incentivá-lo a descrever a cena em detalhes, aqui e agora.","approach":"Exposição implosiva e não estruturada.","is_optimal":false,"immediate_outcome":"João fica sobrecarregado, possivelmente dissociando ou tendo um pico de ansiedade extrema. A aliança é prejudicada por uma percepção de que o terapeuta foi insensível e apressado.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Minimizar o detalhe, dizendo ''não precisamos falar disso agora'' e rapidamente passar para outro item da lista.","approach":"Evitação por parte do terapeuta.","is_optimal":false,"immediate_outcome":"João percebe o desconforto do terapeuta e internaliza que aquele é um segredo inominável. A evitação é modelada e reforçada, estagnando o processamento.","long_term_effect":"","impact":{"rapport":3,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":8,"session_title":"A Primeira Narrativa: Contando a História no Presente","session_phase":"middle","session_content":{"narrative":"Com base na decisão da sessão anterior, João chegou preparado, mas extremamente tenso. A hierarquia está definida e hoje é a primeira sessão de exposição imaginária (recontagem da memória traumática). Você conduz um breve exercício de respiração antes de começar. Você o instrui a narrar o evento do acidente na primeira pessoa e no tempo presente, com o máximo de detalhes sensoriais possível, incluindo os pensamentos e emoções de então. João começa, sua voz trêmula. Ele descreve o dia, o trânsito, e chega ao momento do passageiro cortando a frente do ônibus. Sua narrativa é entrecortada por longas pausas e ele frequentemente olha para você, buscando confirmação. A SUA (Subjective Units of Distress) dele sobe rapidamente. Aproximando-se do clímax (o impacto e os gritos), ele para de falar, com os punhos cerrados.","session_goals":["Realizar a primeira recontagem narrativa da memória traumática","Monitorar e ajudar o paciente a tolerar a angústia (SUDS) durante a exposição"],"key_observations":["Paciente demonstra alta angústia mas segue as instruções, indicando aliança forte","A narrativa é fragmentada, com omissões esperadas na primeira tentativa","O paciente busca validação não-verbal do terapeuta constantemente"],"critical_decision_point":"O que você faz?"},"expert_commentary":"A opção A é tecnicamente sólida. O manual de PE (Foa, Hembree, & Rothbaum, 2007) enfatiza a importância do terapeuta ser um ''treinador compassivo'', incentivando a permanência na memória até que a angústia comece a diminuir. Parar (B ou D) durante o pico de SUDS reforça a fobia à memória em si. Fazer muitas perguntas (C) tira a agência do paciente. Como ressalta Shapiro (2018) no EMDR, o processamento adaptativo requer que o paciente tenha ''um pé no trauma e um pé no presente seguro'', papel que o terapeuta mantém com sua postura estável.","learning_focus":"Habilidade em guiar a exposição imaginária, gerenciando a alta angústia do paciente sem resgatá-lo prematuramente, promovendo a habituação.","decision_options":[{"option_letter":"A","intervention":"Manter uma postura calma e encorajadora, lembrando-o dos objetivos e instruindo-o gentilmente a continuar, focando nos detalhes sensoriais do que aconteceu logo após o impacto.","approach":"Exposição Prolongada - Facilitação da habituação dentro da janela tolerável.","is_optimal":true,"immediate_outcome":"João, sentindo-se apoiado e contido, consegue retomar a narrativa. A SUDS começa a diminuir ligeiramente no final da sessão, proporcionando uma experiência corretiva de domínio e habituação.","long_term_effect":"","impact":{"rapport":7,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Permitir que ele pare a narrativa e mudar para uma discussão sobre os pensamentos automáticos de descontrole que surgiram no momento.","approach":"Terapia Cognitiva focada no ''aqui e agora''.","is_optimal":false,"immediate_outcome":"João se alivia no curto prazo, mas a evitação da memória é reforçada. A sessão de exposição é interrompida, prejudicando o processo de habituação e enviando a mensagem de que a memória é, de fato, intolerável.","long_term_effect":"","impact":{"rapport":6,"insight":6,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Fazer perguntas dirigidas e muito específicas para ''puxar'' a narrativa dele: ''E então, o que você viu? Qual foi o primeiro som?''","approach":"Interrogatório direto.","is_optimal":false,"immediate_outcome":"João pode responder, mas de forma mecânica e desconectada. A sensação de controle sobre a narrativa é retirada dele, podendo levar a uma dissociação ou a um sentimento de revitimização.","long_term_effect":"","impact":{"rapport":5,"insight":5,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Encerrar a exposição prematuramente e dedicar o resto da sessão a técnicas de relaxamento profundo.","approach":"Priorização excessiva do conforto imediato.","is_optimal":false,"immediate_outcome":"O medo do medo é intensificado. João aprende que sua angústia é tão perigosa que nem mesmo o terapeuta pode manejá-la, fortalecendo a crença de incapacidade e aumentando a evitação futura.","long_term_effect":"","impact":{"rapport":4,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":9,"session_title":"Processando e Integrando: Da Narrativa ao Significado","session_phase":"advanced","session_content":{"narrative":"João inicia a sessão relatando que, apesar do cansaço após a última sessão, teve menos pesadelos naquela noite. Ele reflete sobre a recontagem, dizendo: ''Foi horrível, mas eu sobrevivi de novo aqui com você.'' Vocês realizam uma nova recontagem da memória, que agora flui com menos bloqueios e uma SUDS que sobe, mas estabiliza em um platô e começa a declinar no final. Após a exposição, você inicia a fase de processamento cognitivo. João fala sobre a culpa que sente: ''Eu deveria ter freado mais rápido, poderia ter desviado.'' Ele também expressa raiva do passageiro que causou o acidente. Suas crenças sobre o mundo como um lugar seguro e sobre si mesmo como competente foram abaladas.","session_goals":["Realizar uma segunda recontagem para consolidar a habituação","Iniciar a reestruturação cognitiva de crenças relacionadas ao trauma (culpa, segurança)"],"key_observations":["Primeiros sinais de habituação (SUDS decrescente) e processamento (menos pesadelos)","Crenças negativas centrais (culpa, desconfiança) tornam-se explícitas e acessíveis","O paciente começa a fazer conexões espontâneas entre a exposição e a melhora dos sintomas"],"critical_decision_point":"Como você procede com a reestruturação cognitiva deste ponto?"},"expert_commentary":"A opção A é a mais eficaz. A reestruturação cognitiva no TEPT, conforme descrita por Resick et al. (2016) na Terapia de Processamento Cognitivo (CPT), visa modificar crenças ''assimiladas'' (o mundo é perigoso) e ''sobre-acomodadas'' (nunca posso confiar em ninguém). A culpa de João é uma crença assimilada (''o evento prova que sou incompetente''). A questionamento socrático guia o paciente a descobrir suas próprias inconsistências cognitivas, levando a uma reavaliação mais duradoura. Reafirmar (B) ou debater (D) são menos eficazes, pois não promovem a autorreflexão. Ignorar (C) deixa o núcleo do trauma intacto.","learning_focus":"Habilidade em conduzir reestruturação cognitiva de crenças traumáticas profundas, utilizando questionamento socrático para promover insight e mudança duradoura.","decision_options":[{"option_letter":"A","intervention":"Validar a dor da culpa e, usando a técnica da socrática, explorar as evidências a favor e contra a crença ''sou incompetente'', contextualizando-a no evento traumático.","approach":"Terapia Cognitiva para TEPT (Resick et al.) - Reestruturação de crenças assimiladas/sobre-acomodadas.","is_optimal":true,"immediate_outcome":"João engaja-se na análise, percebendo que está aplicando um padrão de perfeição impossível a uma situação de emergência. Começa a distinguir entre ''responsabilidade'' (como motorista) e ''culpa'' (como único culpado), aliviando o afeto negativo.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Oferecer reafirmação direta e tranquilizadora: ''João, você não é um lixo. Foi um acidente, você fez o melhor que pôde.''","approach":"Apoio e reassurance.","is_optimal":false,"immediate_outcome":"João pode se sentir momentaneamente confortado, mas a crença disfuncional não é desafiada internamente. Ele pode concordar verbalmente, mas a mudança cognitiva não é internalizada, mantendo a vulnerabilidade à culpa.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Desviar do tema da culpa, focando apenas nas emoções de raiva do passageiro, que parecem mais confortáveis para ele explorar.","approach":"Evitação do núcleo disfuncional.","is_optimal":false,"immediate_outcome":"A raiva é processada, mas a crença central de auto-culpa permanece intocada e continuará a alimentar sintomas como a intrusão e o humor negativo.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Confrontar a crença de forma vigorosa, apresentando uma lista lógica de razões pelas quais ele não é culpado.","approach":"Persuasão racional e debate.","is_optimal":false,"immediate_outcome":"João pode se sentir invalidado e debatido, possivelmente resistindo e apresentando contra-argumentos (''mas se eu...''). A aliança é tensionada e ele pode não internalizar as razões apresentadas pelo terapeuta.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":10,"session_title":"Revisitando a Memória Traumática","session_phase":"middle","session_content":{"narrative":"A sessão começa com Lucas, 34 anos, relatando um sonho perturbador relacionado ao assalto a mão armada que sofreu há dois anos. Ele demonstra um humor mais estável, fruto do trabalho de psicoeducação e regulação emocional das sessões anteriores. O foco hoje é iniciar a exposição prolongada à memória traumática, conforme planejado. Lucas concorda em descrever o evento, mas sua fisiologia muda rapidamente: respiração ofegante, mãos trêmulas e voz embargada. Ele consegue narrar os primeiros momentos (entrar no banco) antes de se calar, olhando fixamente para um ponto da sala. O silêncio é carregado de ansiedade. Você observa que ele está utilizando algumas técnicas de aterramento espontaneamente, pressionando os pés no chão. O desafio é equilibrar a exposição necessária com a manutenção da janela de tolerância de Lucas, evitando a re-traumatização.","session_goals":["Iniciar a exposição prolongada à memória traumática em um ambiente seguro","Monitorar e auxiliar na regulação do afeto durante a evocação"],"key_observations":["Paciente apresenta reatividade fisiológica intensa (hiperarousal) ao narrar o trauma","Demonstra internalização de técnicas de aterramento, usando-as de forma autônoma","A narrativa é fragmentada e interrompida por ''brancos'' na memória, um sintoma comum do TEPT"],"critical_decision_point":"O que você faz?"},"expert_commentary":"A exposição prolongada (PE) requer um equilíbrio delicado entre encorajar a confrontação com a memória e garantir que o paciente não seja inundado. Como ressalta Foa et al. (2019), a ''habituação dentro da sessão'' é um mecanismo crucial. A opção ótima (A) segue esse princípio: primeiro regula a resposta de medo excessiva (SUDS alta), criando uma experiência corretiva de que a angústia é manejável. Só então retoma a exposição. Isso fortalece a autoeficácia e a aliança, elementos preditores de sucesso na PE. Forçar a exposição sem regulação (B) ou evitá-la (C) são erros comuns que podem estagnar o tratamento.","learning_focus":"Gerenciamento da janela de tolerância durante técnicas de exposição a traumas.","decision_options":[{"option_letter":"A","intervention":"Validar a angústia e guiá-lo em um exercício de respiração diafragmática para baixar a ativação, antes de perguntar se ele consegue continuar descrevendo o que viu.","approach":"Integração de regulação emocional com exposição, priorizando a estabilização dentro da janela de tolerância.","is_optimal":true,"immediate_outcome":"Lucas recupera o controle fisiológico, sente-se contido pela aliança terapêutica e consegue retomar a narrativa por mais alguns detalhes, consolidando um senso de domínio sobre a memória.","long_term_effect":"","impact":{"rapport":9,"insight":7,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Incentivá-lo firmemente a ''passar por isso'' e continuar falando, lembrando-o de que a evitação mantém o medo.","approach":"Exposição pura, focada apenas na habituação, sem validação emocional no momento crítico.","is_optimal":false,"immediate_outcome":"Lucas se força a continuar, mas dissocia rapidamente. A sessão termina com ele se sentindo inundado e desregulado, podendo aumentar a resistência para as próximas exposições.","long_term_effect":"","impact":{"rapport":3,"insight":4,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Mudar completamente de assunto para um tópico neutro, afastando-se da memória traumática para aliviar seu desconforto imediato.","approach":"Evitação terapêutica, reforçando o comportamento de fuga.","is_optimal":false,"immediate_outcome":"O alívio imediato é percebido, mas a mensagem implícita é que o trauma é intocável. Isso prejudica o progresso e solidifica a crença de que a memória é perigosa demais para ser abordada.","long_term_effect":"","impact":{"rapport":5,"insight":2,"behavioral_change":1,"symptom_reduction":0}},{"option_letter":"D","intervention":"Interpretar o silêncio, sugerindo que ele pode estar sentindo raiva do agressor ou culpa por ter sobrevivido.","approach":"Psicodinâmica prematura, introduzindo conteúdo interpretativo durante alta ativação emocional.","is_optimal":false,"immediate_outcome":"Lucas fica confuso e sobrecarregado pela sugestão, desconectando-se ainda mais do processo de exposição. A intervenção não ajuda na regulação nem na elaboração da memória.","long_term_effect":"","impact":{"rapport":4,"insight":3,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":11,"session_title":"Elaborando os Detalhes e Emoções Congeladas","session_phase":"middle","session_content":{"narrative":"Com base na sessão anterior onde a regulação foi priorizada, Lucas chega relatando que pensou sobre o trauma durante a semana, mas com menos medo. Ele se mostra mais confiante para revisitar a memória. O trabalho hoje é aprofundar a narrativa, focando nos detalhes sensoriais (o som da arma engatilhada, o cheiro do local) e nas emoções ''congeladas'' do momento. Lucas descreve com mais fluência, mas ao chegar no ápice – o momento em que achou que seria morto –, sua voz falha novamente. Desta vez, em vez de pânico, ele expressa uma profunda tristeza e desamparo, chorando. É a primeira vez que acessa essa emoção primária relacionada ao trauma, que antes era mascarada pela hipervigilância e irritabilidade. Surge uma crença: ''Eu estava completamente sozinho, ninguém podia me ajudar''.","session_goals":["Facilitar a elaboração emocional e cognitiva da memória traumática","Identificar e começar a desafiar crenças negativas intrínsecas ao evento"],"key_observations":["Mudança na resposta emocional: do medo/pânico para a tristeza/desamparo, indicando processamento emocional","Emergência de uma crença negativa sobre si mesmo (''estava sozinho'') típica do TEPT (DSM-5-TR, critério D2)","Maior tolerância afetiva, permitindo que a emoção seja expressa e contida na sessão"],"critical_decision_point":"O que você faz?"},"expert_commentary":"O acesso à emoção primária (tristeza/desamparo) e à crença negativa associada é um marco no tratamento do TEPT. Segundo Resick et al. (2017), na Terapia Cognitiva para TEPT, o terapeuta deve ''explorar o significado'' do evento para o paciente. A opção ótima (A) faz exatamente isso: primeiro valida (sintoniza com a emoção), depois investiga colaborativamente a crença. Isso honra a experiência subjetiva enquanto planta a semente da reavaliação. O reasseguramento (B) ou o questionamento frio (D) falham em fazer essa ponte. O momento é de ''elaboração'', não apenas de ''exposição'' (C). A meta é integrar a memória traumática à narrativa autobiográfica, alterando seu significado.","learning_focus":"Integração de técnicas de exposição com reestruturação cognitiva de crenças traumáticas.","decision_options":[{"option_letter":"A","intervention":"Refletir e validar a emoção (''Foi um momento de profundo desamparo''), e então, com curiosidade, explorar se há evidências no próprio evento que contradizem ou matizam essa crença de total solidão.","approach":"Terapia Cognitiva para TEPT, acolhendo a emoção e iniciando a reestruturação cognitiva de forma colaborativa.","is_optimal":true,"immediate_outcome":"Lucas se sente compreendido. Ao explorar, ele lembra que o caixa do banco tentou acalmá-lo com o olhar e que, minutos depois, pessoas vieram ajudá-lo. Isso cria uma fissura na crença rígida, introduzindo nuance e preparando o terreno para uma reavaliação cognitiva.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Confortá-lo rapidamente, dizendo ''Mas você não estava sozinho, eu estou aqui agora, e muitas pessoas se importam com você''.","approach":"Reasseguramento direto e consolo, focando no presente.","is_optimal":false,"immediate_outcome":"O consolo é bem-intencionado, mas pode invalidar a experiência passada e impedir o processamento da crença traumática. Lucas pode concordar superficialmente, mas a crença original (''naquela hora, estava sozinho'') permanece intacta.","long_term_effect":"","impact":{"rapport":7,"insight":3,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Pedir para ele descrever com ainda mais detalhes técnicos o que aconteceu exatamente após esse pensamento, mantendo o foco na cadeia de eventos.","approach":"Exposição narrativa pura, ignorando a janela de oportunidade para trabalho cognitivo.","is_optimal":false,"immediate_outcome":"A intervenção é mecânica e perde o momento rico de elaboração emocional e cognitiva. Lucas pode retomar a narrativa de forma dissociada, sem conectar os detalhes ao significado emocional que acabou de emergir.","long_term_effect":"","impact":{"rapport":5,"insight":5,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Questionar a racionalidade da crença de imediato: ''Mas isso é realmente verdade? Você literalmente não estava sozinho, havia outras pessoas no banco''.","approach":"Questionamento cognitivo direto e desafiador, sem validação prévia.","is_optimal":false,"immediate_outcome":"Lucas se sente invalidado e criticado. Ele pode reagir defensivamente, argumentando que a sensação era de solidão absoluta, ou pode se calar, encerrando o processamento. A aliança terapêutica é abalada.","long_term_effect":"","impact":{"rapport":4,"insight":6,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"},{"session_number":12,"session_title":"Consolidando Novos Significados e Planejando a Vida Pós-Trauma","session_phase":"advanced","session_content":{"narrative":"Lucas inicia a sessão comentando que a reflexão sobre ''não estar totalmente sozinho'' o fez revisitar mentalmente o evento de uma forma nova, com menos carga de desamparo. Ele relata que os pesadelos diminuíram de frequência. O trabalho das últimas sessões permitiu uma dessensibilização significativa e o início de uma reavaliação cognitiva. Agora, o foco se desloca para consolidação e futuro. Vocês revisam juntos a narrativa completa do trauma, agora mais coesa e menos fragmentada, e Lucas é capaz de discorrer sobre ela com uma distância emocional maior. Ele menciona espontaneamente um desejo de ''virar a página'' e retomar atividades que abandonou, como encontrar amigos em bares, mas ainda sente um ''friho na barriga'' ao pensar nisso. A sessão caminha para a discussão sobre como integrar as conquistas da terapia à vida cotidiana e enfrentar os últimos resquícios de evitação.","session_goals":["Consolidar as novas perspectivas e significados atribuídos ao evento traumático","Planejar e ensaiar behavioralmente a confrontação com situações evitadas remanescentes"],"key_observations":["Paciente demonstra capacidade de meta-cognição, refletindo sobre suas próprias mudanças de pensamento","Sintomas de revivência (pesadelos) mostram redução clara, indicando eficácia do processamento","A evitação (critério C do DSM-5-TR) persiste como o principal sintoma a ser trabalhado, agora em um grau mais comportamental e situacional"],"critical_decision_point":"O que você faz?"},"expert_commentary":"Na fase avançada do TEPT, o foco muda da processamento do passado para a (re)construção do futuro. A pergunta de Lucas (''Como saber se estou pronto?'') é central. A opção ótima (A) adere ao princípio de ''domínio graduado'' e ''experimentos comportamentais'' da TCC. Como descreve Beck (2021), esses métodos testam crenças antigas e constroem novas aprendizagens na vida real. Criar um plano gradual transforma uma meta ameaçadora em passos manejáveis, aumentando a probabilidade de sucesso e de autoeficácia. Ignorar a graduação (B) ou adiar a ação (C) são erros. Introduzir uma nova abordagem (D) neste momento quebra a coerência do tratamento e desempodera o paciente.","learning_focus":"Transição do processamento do trauma para a retomada de valores e vida ativa através de planejamento comportamental graduado.","decision_options":[{"option_letter":"A","intervention":"Normalizar a ansiedade residual e propor um experimento comportamental conjunto: criar um plano gradual (ex: ir a um bar tranquilo em horário de pouco movimento, por 30 minutos) e ensaiar mentalmente a situação, focando em estratégias de coping.","approach":"Terapia Cognitivo-Comportamental integrada, usando planejamento gradual, ensaio e previsão de obstáculos para construir autoeficácia.","is_optimal":true,"immediate_outcome":"Lucas se sente empoderado por ter um plano concreto e realista. A ansiedade é reenquadrada como um desafio a ser gerenciado, não um sinal de perigo. Ele concorda em tentar o primeiro passo antes da próxima sessão, fortalecendo seu senso de agência.","long_term_effect":"","impact":{"rapport":8,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Encorajá-lo a ''ir com tudo'' e enfrentar o bar no sábado à noite, argumentando que só assim ele vai superar o medo de vez.","approach":"Enfrentamento massivo e não-graduado, subestimando a ansiedade residual.","is_optimal":false,"immediate_outcome":"A pressão pode levar Lucas a tentar e, se a ansiedade for alta demais, ter uma experiência negativa que reforça a evitação (''não estou pronto mesmo''). Ou ele pode simplesmente não ir, sentindo-se fracassado.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Sugerir que ele ainda não está pronto e que é melhor adiar essa meta, focando primeiro em continuar processando as memórias em sessão.","approach":"Superproteção terapêutica, reforçando indiretamente a evitação.","is_optimal":false,"immediate_outcome":"A mensagem é de que o mundo ainda é perigoso e ele é frágil. Lucas pode se sentir desmoralizado e a generalização das conquistas da terapia para a vida real é adiada.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Analisar o significado simbólico do ''bar'' para ele, questionando se remete a perda de liberdade ou masculinidade após o trauma.","approach":"Mudança para uma abordagem psicodinâmica interpretativa no estágio avançado de um tratamento TCC.","is_optimal":false,"immediate_outcome":"A intervenção é desconexa do trabalho feito até agora e desvia o foco do planejamento comportamental prático. Lucas pode ficar confuso e a aliança de trabalho, construída na colaboração concreta, pode se enfraquecer.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Transtorno de Estresse Pos-Traumatico","difficulty_level":"intermediate"}]'::jsonb
WHERE title ILIKE '%Jornada%' AND (
  title ILIKE '%011%' OR 
  title ILIKE '%0011%'
);

-- Journey 012
UPDATE clinical_journeys 
SET sessions = '[{"session_number":1,"session_title":"Mapeando o Medo e Construindo a Aliança","session_phase":"initial","session_content":{"narrative":"O paciente, Lucas Mendes, 24 anos, estudante de engenharia, chega à sessão visivelmente tenso, evitando contato visual e falando em tom baixo. Ele relata que a busca por terapia foi motivada por um episódio recente em que \"travo completamente\" durante uma apresentação de trabalho na faculdade, sentindo-se humilhado. Lucas descreve um padrão de ansiedade intensa e antecipatória em situações sociais onde acredita que pode ser avaliado, como falar em grupos, comer em público ou interagir com figuras de autoridade. Ele menciona evitar festas e trabalhos em grupo, o que está impactando seu desempenho acadêmico e sua sensação de solidão. Durante a narrativa, ele demonstra hipervigilância aos próprios sintomas físicos (taquicardia, sudorese, tremor nas mãos) e um forte medo de que os outros percebam sua ansiedade e o julguem negativamente, como \"fraco\" ou \"estranho\". A sessão é focada em escuta ativa e validação, começando a construir um vínculo terapêutico seguro.","session_goals":["Estabelecer rapport e compreender a história do problema","Identificar situações temidas, pensamentos automáticos e comportamentos de segurança/evitação"],"key_observations":["Paciente apresenta critérios claros para Fobia Social (DSM-5-TR F40.10), com medo marcante de avaliação negativa","Uso frequente de comportamentos de segurança (ex: evitar contato visual, falar baixo) mesmo na sessão","Insight inicial presente, mas focado nas consequências (fracasso acadêmico) mais do que nos mecanismos cognitivos"],"critical_decision_point":"O que você faz?"},"expert_commentary":"A opção A é ótima porque segue o princípio de ''normalizar antes de desafiar'' (Beck, 2021). Na fase inicial, é vital construir uma colaboração segura, onde o paciente se sinta compreendido, não julgado. Validar a experiência (\"é muito comum\") reduz a vergonha, que é um componente central da fobia social. A exploração colaborativa do pensamento automático coleta dados concretos para a conceituação cognitiva, estabelecendo o modelo de que pensamentos influenciam emoções e comportamentos. Como aponta Hofmann & Otto (2008), a psicoeducação sobre a natureza do transtorno é um primeiro passo terapêutico essencial.","learning_focus":"Construção de Aliança Terapêutica e Coleta Colaborativa de Dados para Conceituação","decision_options":[{"option_letter":"A","intervention":"Normalizar e explorar com curiosidade","approach":"Psicoeducação e exploração colaborativa","is_optimal":true,"immediate_outcome":"Você diz: ''É muito comum na ansiedade social temermos até as pequenas interações. Pode me contar o que exatamente você imagina que poderia dar ''errado'' nessa situação?'' Lucas se abre, descrevendo o pensamento automático ''Vou gaguejar, ele vai me achar um idiota''. Isso fornece um primeiro núcleo cognitivo crucial para o trabalho futuro.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Focar imediatamente na distorção cognitiva","approach":"Questionamento socrático direto","is_optimal":false,"immediate_outcome":"Você pergunta: ''Qual a evidência real de que o atendente pensaria isso?'' Lucas fica na defensiva, sentindo-se invalidado e corrigido. Ele responde com um ''Não sei, só sinto'', e se fecha, dificultando a coleta de informações.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Minimizar a situação para aliviar a ansiedade","approach":"Reasseguração não específica","is_optimal":false,"immediate_outcome":"Você diz: ''Ah, mas ir na padaria é algo simples, não precisa se preocupar com isso.'' Lucas concorda superficialmente, mas internamente sua crença de que ''meu medo é bobo e incompreensível'' se fortalece, aumentando a vergonha e reduzindo a disposição para compartilhar outros medos.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar rapidamente para outra área menos constrangedora","approach":"Evitação do terapeuta","is_optimal":false,"immediate_outcome":"Percebendo o desconforto, você diz: ''Vamos deixar isso de lado por agora e falar sobre a apresentação na faculdade.'' A aliança não é profundamente testada, e uma oportunidade de modelar a aceitação do desconforto é perdida. Lucas aprende, implicitamente, que temas difíceis devem ser evitados.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":2,"session_title":"Desvendando o Triângulo Cognitivo e Introduzindo a Exposição","session_phase":"middle","session_content":{"narrative":"Com base no rapport estabelecido, você inicia a sessão revisando brevemente o diário de pensamentos que Lucas concordou em tentar preencher. Ele trouxe dois registros: um sobre hesitar em fazer uma pergunta em aula (pensamento: ''Vão achar minha pergunta óbvia e que eu não estudo'') e outro sobre recusar um convite para um café (pensamento: ''Não vou ter assunto, vai ficar um silêncio constrangedor''). Juntos, vocês analisam as conexões entre Situação -> Pensamento Automático -> Emoção/Reação Física -> Comportamento (evitação). Lucas demonstra compreensão intelectual do modelo. Você então introduz o conceito de exposição gradual, explicando-a como a maneira mais eficaz, baseada em evidências, para reduzir o medo (Foa & Kozak, 1986). Lucas parece interessado mas apreensivo. Ele concorda em começar a construir uma ''Hierarquia do Medo'', uma lista de situações temidas classificadas por nível de ansiedade subjetiva (0-100).","session_goals":["Solidificar a compreensão do modelo cognitivo-comportamental aplicado às suas experiências","Construir colaborativamente uma Hierarquia de Evitação/Medo para planejar intervenções comportamentais"],"key_observations":["Paciente engajado na tarefa de casa, indicando adesão inicial ao modelo","Consegue identificar pensamentos automáticos com mais facilidade, mas ainda tem dificuldade em identificar crenças intermediárias/subjacentes","A menção à exposição gera ansiedade antecipatória, mas também um vislumbre de esperança"],"critical_decision_point":"Como você procede?"},"expert_commentary":"A opção A é ideal porque honra o princípio da ''exposição gradual e repetida'' (Barlow et al., 2022). A eficácia da exposição depende de ser suficientemente desafiadora para gerar ansiedade, mas não tão avassaladora a ponto de levar à evitação ou à inundação emocional. Desmembrar tarefas é uma habilidade central na TCC para fobias. Validar a ansiedade de Lucas (''Isso é importante'') mantém a aliança e modela a aceitação do desconforto. Como Clark & Wells (1995) destacam, pacientes com fobia social frequentemente superestimam drasticamente o custo social de ações menores, tornendo a gradação fina essencial.","learning_focus":"Habilidade de Construir uma Hierarquia de Exposição Gradual e Colaborativa","decision_options":[{"option_letter":"A","intervention":"Desmembrar a situação em degraus menores e validar a ansiedade","approach":"Quebra da tarefa e validação","is_optimal":true,"immediate_outcome":"Você responde: ''Percebo que essa sugestão ainda parece muito alta. Isso é importante, mostra que precisamos encontrar degraus mais suaves. Vamos quebrar isso: e se a pergunta fosse feita por e-mail primeiro? Ou se você apenas ficasse na sala após a aula, sem falar, só para se acostumar?'' Lucas relaxa, sentindo que o processo é colaborativo e adaptado ao seu ritmo. Juntos, vocês criam 3-4 novos itens intermediários.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Encorajar a enfrentar o medo para ''superar logo''","approach":"Pressão por exposição intensa","is_optimal":false,"immediate_outcome":"Você diz: ''Às vezes precisamos dar um salto de fé. Se você conseguisse fazer isso, o resto ficaria mais fácil.'' Lucas concorda por pressão, mas sua ansiedade dispara. Ele pode até tentar e falhar de forma desorganizada, reforçando sua sensação de incapacidade, ou pode abandonar a terapia por sentir que a demanda é excessiva.","long_term_effect":"","impact":{"rapport":3,"insight":4,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Abandonar a sugestão e voltar para itens muito baixos","approach":"Evitação do terapeuta por medo de sobrecarregar","is_optimal":false,"immediate_outcome":"Você diz: ''Tudo bem, então vamos deixar isso de lado. Tem mais alguma coisa na linha dos 30-40?'' A hierarquia fica com uma grande lacuna entre itens fáceis e o topo muito difícil. O plano de exposição perde eficácia, pois não há uma escada gradual real para subir, o que pode levar à estagnação.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Analisar apenas os pensamentos sobre fazer a pergunta","approach":"Foco exclusivo no cognitivo, adiando o comportamental","is_optimal":false,"immediate_outcome":"Você propõe: ''Vamos antes trabalhar os pensamentos que tornam essa situação tão ameaçadora.'' Embora útil, isso sinaliza para Lucas que a exposição pode ser adiada indefinidamente até que ele ''se sinta pronto'' (o que nunca acontecerá na fobia social). O momentum para a mudança comportamental é perdido, e a crença de que a ansiedade deve estar baixa para agir é reforçada.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":5,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":3,"session_title":"Primeiros Passos na Exposição e Trabalhando com Comportamentos de Segurança","session_phase":"middle","session_content":{"narrative":"A sessão começa com Lucas relatando uma tentativa malsucedida de realizar o primeiro item da hierarquia (\"Cumprimentar um colega conhecido no corredor\"). Ele viu o colega, mas \"congelou\", desviou o olhar e passou reto. Ele está desanimado e autocrítico (''Nem isso eu consigo''). Você o ajuda a analisar a tentativa não como uma falha, mas como um dado experimental. Juntos, identificam que, no momento, ele estava focado internamente em seus sintomas (''meu coração está acelerado'') e no pensamento ''Ele vai perceber que estou nervoso''. Você introduz o conceito de ''comportamentos de segurança'' (Clark & Wells, 1995), ações subtis para prevenir o temido resultado (ex: evitar contato visual, falar rápido, ensaiar mentalmente), que paradoxalmente mantêm a ansiedade. Lucas identifica que seu ''congelamento'' e desvio de olhar eram comportamentos de segurança. Você propõe um experimento comportamental na sessão: uma exposição simulada (role-play) a um cumprimento, primeiro com seus comportamentos de segurança habituais, e depois tentando abandoná-los intencionalmente.","session_goals":["Descatastrofizar ''recaídas'' e reformulá-las como aprendizagem","Introduzir e identificar comportamentos de segurança","Realizar uma primeira exposição simulada (in vivo na sessão) para testar predições"],"key_observations":["Paciente apresenta pensamento dicotômico (''sucesso/falha'') típico da ansiedade social","Demonstra capacidade de auto-observação após psicoeducação sobre foco atencional interno","Ansiedade visível, mas disposição para tentar o role-play indica manutenção da aliança terapêutica"],"critical_decision_point":"Qual sua intervenção pós-exposição?"},"expert_commentary":"A opção A é ótima porque conduz uma ''exposição comportamental com prevenção de resposta'' (não usar comportamentos de segurança) seguida por uma ''reestruturação cognitiva baseada em evidências''. O processamento pós-exposição é tão vital quanto a exposição em si (Craske et al., 2014). Focar nos dados observáveis (''o que aconteceu de fato?'') contrasta com a avaliação emocional do paciente (''foi horrível''). Validar o esforço (''parabéns'') reforça a coragem, não o desempenho. A pergunta chave é se o temido desfecho social ocorreu, desafiando a crença de que a ansiedade visível leva inevitavelmente à avaliação negativa. Este é um núcleo do tratamento da fobia social.","learning_focus":"Processamento Cognitivo Pós-Exposição e Identificação de Evidências Corretivas","decision_options":[{"option_letter":"A","intervention":"Focar no dado comportamental e na tolerância à ansiedade","approach":"Análise cognitiva baseada no experimento","is_optimal":true,"immediate_outcome":"Você pergunta: ''Primeiro, parabéns por ter tentado algo tão difícil aqui comigo. Vamos aos fatos: o que de fato aconteceu? Você manteve o contato visual? (Sim). Eu reagi com desdém ou interrompi o cumprimento? (Não). A ansiedade ''vazou'', mas o temido desfecho social ocorreu? (Não).'' Você destaca que ele tolerou a ansiedade e que o resultado foi neutro/positivo, não a catástrofe prevista. Isso fornece evidência corretiva.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Oferecer reasseguração direta sobre seu desempenho","approach":"Reasseguração tranquilizadora","is_optimal":false,"immediate_outcome":"Você diz: ''Não foi horrível não! Eu nem percebi o tremor, você está se cobrando muito.'' Lucas não acredita, interpretando como um elogio vazio ou piedade. A crença central de que os outros são críticos ou mentem para poupá-lo pode ser reforçada. A oportunidade de ele mesmo colher evidências é perdida.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Sugerir técnicas de relaxamento para controlar o tremor","approach":"Foco no controle de sintomas","is_optimal":false,"immediate_outcome":"Você responde: ''Vamos trabalhar algumas técnicas de respiração para controlar o tremor da próxima vez.'' Isso reforça a crença problemática de que os sintomas físicos devem ser controlados antes que a interação social seja bem-sucedida, desviando o foco do verdadeiro alvo: a tolerância à ansiedade e a mudança na atenção e nos comportamentos.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar de assunto para aliviar o constrangimento","approach":"Evitação do terapeuta","is_optimal":false,"immediate_outcome":"Incomodado com o desconforto de Lucas, você diz rapidamente: ''Bem, o importante foi tentar. Vamos anotar isso e passar para o planejamento da tarefa de casa?'' O momento de processamento emocional e cognitivo crucial pós-exposição é perdido. Lucas fica com a impressão de que sua performance foi de fato tão constrangedora que nem pode ser discutida.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":4,"session_title":"Explorando a Evitação e a Autocrítica","session_phase":"middle","session_content":{"narrative":"O paciente, Thiago, 24 anos, chega pontualmente para a quarta sessão. Ele relata que, na semana anterior, conseguiu ir a uma pequena reunião de trabalho, mas passou os últimos 20 minutos no banheiro, sentindo-se \"paralisado\" pelo medo de que alguém percebesse sua ansiedade. Ele descreve um ciclo de antecipação catastrófica, sintomas físicos intensos (taquicardia, sudorese) durante a situação social e, posteriormente, uma autocrítica severa, rotulando-se como \"fraco\" e \"estranho\". Thiago menciona que evita até mesmo fazer perguntas no mercado para não chamar atenção. O foco da sessão é mapear o padrão completo de seus pensamentos automáticos negativos (ex.: \"Vão me achar incompetente\"), as sensações corporais e os comportamentos de segurança (como ficar no celular ou perto da porta) que mantêm o ciclo da fobia. Ele demonstra boa adesão ao registro de pensamentos, trazendo alguns exemplos preenchidos, mas ainda com dificuldade de identificar as distorções cognitivas de forma mais precisa.","session_goals":["Identificar e descrever a sequência completa do episódio de ansiedade social (pensamento, emoção, corpo, comportamento).","Introduzir o conceito de comportamentos de segurança e sua função paradoxal de manutenção do medo."],"key_observations":["Thiago apresenta alta adesão às tarefas de casa, indicando motivação para a mudança.","Sua autocrítica pós-evento é um fator de manutenção significativo, potencialmente ligado a regras e suposições disfuncionais mais profundas (ex.: ''Preciso ser perfeito para ser aceito'').","Ele demonstra insight inicial sobre a conexão entre pensamento e sintoma físico."],"critical_decision_point":"Como você responde à autocrítica globalizante de Thiago (''ser defeituoso'')?"},"expert_commentary":"A opção A é ótima porque segue o princípio de ''colaboração empírica'' central na TCC (Beck, 2011). Primeiro, valida a emoção (rapport), depois convida para um exame conjunto da evidência (insight). Isso é crucial na Fobia Social, onde a autocrítica é um mecanismo de manutenção chave (DSM-5-TR). Desafiar a generalização ''defeituoso'' impede a cristalização dessa crença e abre caminho para trabalhar suposições como ''Para ser amado, preciso ser perfeito''. As outras opções falham por serem prematuras (B), invalidantes (C) ou muito confrontativas (D) para esta fase.","learning_focus":"Aplicação da reestruturação cognitiva para modificar autocríticas globalizantes e identificar crenças intermediárias.","decision_options":[{"option_letter":"A","intervention":"Validar a emoção da vergonha, mas desafiar a generalização, convidando-o a examinar a evidência contra a ideia de ''defeito'' e a reformular para um pensamento mais específico e útil.","approach":"Reestruturação Cognitiva (baseada em Beck, 2011)","is_optimal":true,"immediate_outcome":"Thiago se sente compreendido em sua dor, mas é guiado para um exame mais objetivo de seus pensamentos. Ele começa a diferenciar entre ''ter um problema de ansiedade'' e ''ser um defeito'', reduzindo a autocrítica global e abrindo espaço para trabalhar em crenças intermediárias.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Concordar que a situação é difícil, mas focar imediatamente em técnicas de relaxamento para controlar os sintomas na próxima vez.","approach":"Foco Sintomático e Psicoeducação","is_optimal":false,"immediate_outcome":"Thiago pode sentir que sua angústia emocional mais profunda não foi acolhida. A intervenção é prematura e desvia do trabalho cognitivo central necessário para modificar suas crenças nucleares de desvalor, podendo reforçar a ideia de que o problema é apenas fisiológico.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Minimizar a autocrítica, dizendo que ''todo mundo se sente assim às vezes'' e elogiando seu esforço de ter ido à reunião.","approach":"Suporte e Normalização","is_optimal":false,"immediate_outcome":"A normalização excessiva pode invalidar a experiência singular e intensa de Thiago. O elogio genérico, sem uma análise concreta do evento, não ajuda a desmontar a lógica distorcida de sua autocrítica, deixando a crença central intocada.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Questionar de forma direta e desafiadora: ''Que prova você tem de que é defeituoso? Isso é mesmo um fato?''","approach":"Questionamento Socrático Agressivo","is_optimal":false,"immediate_outcome":"O tom confrontativo pode ser percebido como hostil ou invalidante, especialmente em um paciente com alta sensibilidade à crítica. Thiago pode se retrair, fechar-se emocionalmente e a aliança terapêutica pode ser prejudicada, interrompendo o fluxo de autorrevelação.","long_term_effect":"","impact":{"rapport":3,"insight":5,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":5,"session_title":"Desmontando Comportamentos de Segurança e Planejando Experimentos","session_phase":"middle","session_content":{"narrative":"Com base na sessão anterior, onde a autocrítica de Thiago foi desafiada, ele chega relatando um \"alívio\" ao perceber que seus pensamentos eram \"exagerados\" e não fatos. O trabalho agora se aprofunda na análise funcional dos comportamentos de segurança que ele identificou (ex.: evitar contato visual, ensaiar frases mentalmente, fugir para o banheiro). Juntos, vocês discutem como esses comportamentos, embora aliviem a ansiedade a curto prazo, impedem que Thiago teste a veracidade de seus pensamentos catastróficos e reforçam a crença de que a situação social é perigosa. Ele demonstra curiosidade sobre essa ideia paradoxal. A sessão é dedicada a planejar um ''experimento comportamental'' de baixa hierarquia, como fazer uma pergunta simples a um atendente de livraria. O plano inclui: predição de ansiedade e do que poderia dar errado (pensamento automático), a ação planejada (fazer a pergunta sem comportamentos de segurança específicos, como manter contato visual breve), e como coletar evidências do resultado real.","session_goals":["Psicoeducar sobre a função paradoxal dos comportamentos de segurança na manutenção da fobia.","Elaborar colaborativamente um primeiro experimento comportamental, definindo ação, predições e método de coleta de dados."],"key_observations":["Thiago mostra maior flexibilidade cognitiva, conseguindo nomear alguns de seus comportamentos de segurança com certa distância.","Há um aumento na motivação para a ação (''Quero testar essa ideia''), mas também ansiedade antecipatória visível ao discutir o experimento.","Ele ainda superestima significativamente a probabilidade de consequências negativas (ex.: ''O atendente vai me ignorar ou falar grosso'')."],"critical_decision_point":"Como você intervém na proposta de Thiago, que incorpora novos comportamentos de segurança?"},"expert_commentary":"A opção A é a intervenção tecnicamente precisa. O modelo cognitivo da Fobia Social de Clark e Wells (1995) enfatiza que os comportamentos de segurança (como ensaio mental e planejamento de fuga) impedem a reavaliação das crenças de ameaça social. A psicoeducação sobre sua função paradoxal é essencial. A opção B, embora bem-intencionada, é iatrogênica, pois fortalece o ciclo de manutenção. A opção C é inconsistente, e a D destrói a colaboração. A exposição com prevenção de resposta é o padrão-ouro para desmontar esses mecanismos.","learning_focus":"Diferenciação entre enfrentamento adaptativo e comportamentos de segurança disfuncionais no planejamento de experimentos comportamentais.","decision_options":[{"option_letter":"A","intervention":"Reconhecer a intenção positiva (querer se sair bem), mas apontar gentilmente que ensaiar rigidamente e ter uma ''saída de emergência'' pronta são justamente os comportamentos de segurança que mantêm o medo. Sugerir modificar o plano para incluir apenas a pergunta simples, aceitando a possibilidade de ansiedade e imperfeição.","approach":"Exposição com Prevenção de Resposta (baseada em Clark & Wells, 1995)","is_optimal":true,"immediate_outcome":"Thiago compreende a diferença crucial entre ''enfrentar'' e ''enfrentar com redes de segurança'' que invalidam o teste. Ele concorda em ajustar o plano para um teste mais puro de sua crença, aumentando a potencial eficácia do experimento para gerar aprendizagem corretiva.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Aceitar a proposta dele como um ''primeiro passo'' válido, focando apenas em elogiar sua iniciativa de se expor.","approach":"Reforço Positivo Incondicional","is_optimal":false,"immediate_outcome":"Embora motive no curto prazo, reforça inadvertidamente o uso de comportamentos de segurança. O experimento perde seu poder de desconfirmar crenças, pois qualquer sucesso será atribuído aos ''treinos'' e ''saídas'', não à inocuidade real da situação social. O progresso terapêutico será mais lento.","long_term_effect":"","impact":{"rapport":8,"insight":4,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Concordar com o ensaio mental, mas desencorajar a ''saída de emergência'', sugerindo que ele tente ficar na situação um pouco mais.","approach":"Compromisso Parcial","is_optimal":false,"immediate_outcome":"A intervenção é confusa e mista. Ao permitir o ensaio rígido (um comportamento de segurança cognitivo), você ainda está validando a necessidade de um desempenho perfeito. Thiago não experimentará a espontaneidade, e a ansiedade permanecerá alta, limitando a nova aprendizagem.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Rejeitar completamente a ideia dele como ''errada'' e impor um plano mais desafiador, como fazer um elogio a um estranho.","approach":"Prescrição Autoritária","is_optimal":false,"immediate_outcome":"Thiago se sente invalidado e subjugado. A aliança terapêutica, cuidadosamente construída, é danificada. A tarefa pode parecer assustadora e não colaborativa, levando a uma possível evitação ou abandono da tarefa de casa. O princípio da hierarquia é violado.","long_term_effect":"","impact":{"rapport":2,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":6,"session_title":"Analisando Resultados e Trabalhando com Imagens do Self","session_phase":"advanced","session_content":{"narrative":"Thiago chega para a sexta sessão visivelmente animado. Ele realizou o experimento na livraria, seguindo o plano revisado (perguntar onde ficava um livro, sem ensaiar excessivamente e mantendo-se na interação). Ele relata que a ansiedade subiu a 8/10, mas o atendente foi educado e respondeu normalmente. Apesar da evidência objetiva positiva, Thiago revela: \"Na hora, eu tinha a nítida imagem de mim mesmo, suando e com a voz trêmula, parecendo um idiota. Acho que foi isso que o atendente viu\". A sessão explora essa desconexão entre o resultado real e sua percepção interna baseada em uma \"imagem do self\" negativa e distorcida (como se fosse observado de fora, focando em sinais de ansiedade). Ele traz também que, após o evento, a autocrítica foi menor, mas ainda presente (\"Pelo menos não fugi\"). O trabalho agora avança para técnicas que abordam diretamente essa imagem mental negativa e a hipermetacognição (foco excessivo em si mesmo).","session_goals":["Analisar os resultados do experimento comportamental, contrastando predições catastróficas com evidências reais.","Introduzir o conceito de ''imagem do self'' na Fobia Social e iniciar técnicas para modificá-la (ex.: treino de atenção, retrato falado)."],"key_observations":["Thiago obteve sucesso comportamental objetivo, mas a experiência subjetiva foi de forte desconforto e distorção perceptiva.","A persistência da ''imagem do self'' negativa é um indicador de que as crenças nucleares de desvalor (''sou inadequado'') ainda estão ativas, apesar do progresso cognitivo e comportamental.","A redução da autocrítica pós-evento é um sinal positivo de que as reestruturações anteriores estão tendo efeito."],"critical_decision_point":"Como você maneja a resistência de Thiago em explorar a imagem negativa de si mesmo?"},"expert_commentary":"A opção A é a mais eficaz e clinicamente sofisticada. Trabalhar com imagens mentais negativas do self é um componente vital da TCC para Fobia Social (Hackmann et al., 2000). Normalizar reduz a vergonha secundária. O ''retrato falado'' é uma técnica validada que transforma uma experiência interna aversiva em um objeto manipulável na terapia, permitindo uma reestruturação cognitiva profunda ao nível da memória e da percepção. Ignorar (B) perpetua o problema. Confrontar (C) é muito arriscado nesta fase. Focar apenas no positivo (D) é invalidante e superficial.","learning_focus":"Manejo da resistência e aplicação de técnicas específicas para modificar imagens mentais negativas do self na Fobia Social.","decision_options":[{"option_letter":"A","intervention":"Normalizar a experiência (''É comum na fobia social ter essa imagem distorcida'') e propor uma técnica concreta e menos ameaçadora para trabalhá-la, como o ''retrato falado'', onde ele descreve a imagem em detalhes e depois você a redesenha com base nas evidências reais da situação.","approach":"Normalização e Técnica Específica de Modificação de Imagem (Hackmann, Clark, & McManus, 2000)","is_optimal":true,"immediate_outcome":"A normalização reduz a vergonha. Oferecer uma técnica estruturada (retrato falado) transforma um material ameaçador em um objeto de trabalho colaborativo. Thiago se engaja, permitindo desmontar a imagem e conectar suas sensações internas distorcidas com a realidade externa observada, gerando um insight poderoso.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Respeitar sua resistência e seguir para o planejamento do próximo experimento, como ele sugeriu.","approach":"Acomodação da Evitação","is_optimal":false,"immediate_outcome":"A evitação terapêutica é reforçada. Um mecanismo central de manutenção da fobia (a imagem negativa do self) permanece intocado, limitando severamente o progresso futuro. Os experimentos comportamentais podem continuar gerando sucesso superficial, mas o sofrimento interno e a percepção distorcida persistirão.","long_term_effect":"","impact":{"rapport":7,"insight":3,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Confrontar a resistência diretamente: ''Se evitarmos isso aqui, é o mesmo que você fazer na vida real. Precisamos enfrentar essa imagem''.","approach":"Confrontação Direta e Desafio","is_optimal":false,"immediate_outcome":"A analogia pode ser percebida como crítica e pressionadora. Thiago, já constrangido, pode se sentir atacado e fechar-se ainda mais. A aliança terapêutica é arriscada, e ele pode concordar verbalmente para evitar conflito, sem um engajamento genuíno no trabalho emocional.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Focar exclusivamente nos aspectos positivos do experimento, elogiando sua coragem e ignorando o comentário sobre a imagem.","approach":"Reforço Positivo Seletivo","is_optimal":false,"immediate_outcome":"Thiago sente que o terapeuta não captou a profundidade de seu sofrimento interno. A mensagem implícita é que suas experiências internas perturbadoras não são importantes, apenas os comportamentos observáveis. Isso pode prejudicar o rapport e deixar um núcleo central do transtorno sem intervenção.","long_term_effect":"","impact":{"rapport":5,"insight":2,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":7,"session_title":"Reestruturação Cognitiva e Identificação de Pensamentos Automáticos","session_phase":"middle","session_content":{"narrative":"A sessão começa com Lucas relatando que tentou fazer um pedido no balcão de uma padaria, mas desistiu ao ver a fila. Ele descreve uma sensação intensa de que ''todos estariam olhando e julgando'' sua hesitação. Você valida seu esforço e o convida a explorar o momento exato em que decidiu sair da fila. Utilizando a técnica da seta descendente, você ajuda Lucas a desvendar a cadeia de pensamentos: ''Se eu gaguejar, o atendente vai ficar impaciente'' -> ''As pessoas atrás vão pensar que sou incompetente'' -> ''Vou passar uma vergonha enorme e nunca mais voltar aqui''. Você psicoeduca Lucas sobre o modelo cognitivo da Fobia Social, explicando como os pensamentos automáticos distorcidos (como leitura mental e catastrofização) alimentam a ansiedade e o comportamento de evitação, conforme descrito no DSM-5-TR. O clima é de descoberta, com Lucas mostrando-se intrigado ao perceber a lógica interna de seu medo.","session_goals":["Identificar e registrar pensamentos automáticos relacionados a situações sociais temidas.","Introduzir o modelo cognitivo, conectando pensamentos, emoções e comportamentos."],"key_observations":["Lucas demonstra boa capacidade de introspecção ao detalhar a sequência de pensamentos.","Há um componente forte de ''medo do julgamento negativo'' e ''medo de demonstrar sintomas de ansiedade'', nucleares na Fobia Social."],"critical_decision_point":"Como você responde para consolidar o trabalho cognitivo e manter a motivação?"},"expert_commentary":"A opção A é ótima porque segue o princípio de ''domínio graduado'' dentro do trabalho cognitivo. Primeiro, valida a experiência do cliente (fortalecendo rapport), depois oferece uma tarefa concreta e realizável (registro de pensamentos), que é a base para a reestruturação posterior. Como aponta Beck (2011) na terapia cognitiva, a psicoeducação e o registro são fases essenciais antes do confronto direto das cognições. Isso previne a desmoralização e promove autoeficácia.","learning_focus":"Habilidade de conduzir a identificação de pensamentos automáticos e propor tarefas de casa adequadas ao estágio do cliente.","decision_options":[{"option_letter":"A","intervention":"Normalizar a descoberta e estruturar o próximo passo.","approach":"Validação e colaboração na definição de uma tarefa de casa concreta.","is_optimal":true,"immediate_outcome":"Você diz: ''É comum ficar impressionado quando começamos a notar esses pensamentos. O poder está justamente em trazê-los à luz. Que tal, para a próxima, a gente focar em registrar apenas um ou dois desses pensamentos quando surgirem, sem tentar mudá-los ainda?'' Lucas concorda, sentindo que a tarefa é manejável e que há um plano.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Minimizar a preocupação dele e focar imediatamente na reestruturação.","approach":"Postura diretiva e otimista, pulando etapas.","is_optimal":false,"immediate_outcome":"Você responde: ''Não se preocupe, agora que identificamos, já podemos começar a contestar cada um deles!'' Lucas parece pressionado e desconecta-se um pouco, murmurando que acha muito rápido. A aliança terapêutica é levemente abalada.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Explorar profundamente a emoção de desesperança.","approach":"Mudança de foco para questões emocionais mais profundas.","is_optimal":false,"immediate_outcome":"Você pergunta: ''Esse sentimento de que é impossível mudar é familiar em outras áreas da sua vida?'' A sessão desvia para uma discussão mais existencial, perdendo o foco no treino cognitivo específico para a fobia. O progresso na habilidade-alvo é limitado.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Encerrar a sessão sem uma tarefa clara.","approach":"Postura passiva e não-diretiva.","is_optimal":false,"immediate_outcome":"Você valida o sentimento e diz: ''É compreensível. Vamos refletir sobre isso na próxima sessão.'' Lucas sai sem um direcionamento claro, e a sensação de sobrecarga não é trabalhada. A continuidade do trabalho fica comprometida.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":8,"session_title":"Experimentação Comportamental e Teste de Pensamentos","session_phase":"advanced","session_content":{"narrative":"Lucas trouxe seu registro de pensamentos, anotando a crença ''Vou fazer papel de bobo'' antes de uma reunião online no trabalho. Você elogia seu engajamento e propõe construir um experimento comportamental para testar a validade desse pensamento. Juntos, definem uma hipótese catastrófica (''Se eu falar e minha voz tremer, meus colegas vão rir e me achar incompetente'') e uma hipótese alternativa mais realista (''Eles provavelmente estão focados no conteúdo, e um pouco de nervosismo é normal''). A tarefa será: durante a reunião, Lucas fará um comentário breve e, depois, observará as reações. Você o treina em técnicas de atenção seletiva, para que ele não fique apenas ''escaneando'' sinais de julgamento. Lucas concorda, mas demonstra ansiedade antecipatória. A sessão avança para o planejamento detalhado do experimento, definindo o que ele fará, o que observará e como registrará os resultados.","session_goals":["Planejar e executar um experimento comportamental para testar uma crença específica da fobia social.","Treinar o redirecionamento da atenção em situações sociais."],"key_observations":["Lucas está aplicando o modelo cognitivo, mas sua ansiedade antecipatória ainda é um obstáculo significativo.","Há uma tendência a confundir ''experimento'' com ''exposição forçada'', necessitando de psicoeducação adicional."],"critical_decision_point":"Como você prepara Lucas para lidar com possíveis resultados negativos do experimento?"},"expert_commentary":"A opção A é a mais eficaz porque adota uma postura verdadeiramente científica e resiliente. Em TCC, experimentos comportamentais devem testar crenças, não buscar sucesso absoluto. Preparar o cliente para todos os resultados, inclusive os negativos, é crucial para a generalização do aprendizado e para desenvolver tolerância à incerteza, um núcleo da Fobia Social. Como Clark e Wells (1995) destacam, a percepção de ameaça social é mantida por processos cognitivos como a atenção seletiva para ameaças; testar ativamente essas percepções é fundamental.","learning_focus":"Habilidade de co-criar experimentos comportamentais válidos e preparar o cliente para processar cognitivamente qualquer resultado.","decision_options":[{"option_letter":"A","intervention":"Reframing do objetivo do experimento e preparação para todos os cenários.","approach":"Abordagem colaborativa e resiliente, focada no aprendizado.","is_optimal":true,"immediate_outcome":"Você responde: ''Excelente pergunta. O objetivo não é provar que nada de ruim *nunca* acontece, mas coletar dados reais. Se alguém fizer uma cara, é um dado. Aí vamos investigar: isso significa que você é incompetente? Que a reunião foi um desastre? Ou que uma pessoa pode ter reagido de forma impensada? Vamos preparar um plano para analisar qualquer resultado.'' Lucas se acalma, entendendo o experimento como um processo de aprendizado seguro.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Assegurar que isso é muito improvável.","approach":"Tentativa de tranquilização baseada em suposições.","is_optimal":false,"immediate_outcome":"Você diz: ''Não se preocupe, é muito raro alguém fazer isso em um ambiente profissional.'' Lucas não fica convencido, pois sua experiência interna contradiz essa afirmação. A ansiedade não é reduzida, e a credibilidade terapêutica pode ser afetada se a previsão não se confirmar.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Sugerir adiar o experimento até ele se sentir mais confiante.","approach":"Evitação da ansiedade e do risco.","is_optimal":false,"immediate_outcome":"Você propõe: ''Talvez ainda não seja o momento. Podemos trabalhar mais na reestruturação antes.'' Lucas sente alívio imediato, mas reforça sua crença de que a situação é intrinsecamente perigosa e deve ser evitada. O progresso na hierarquia de exposição estagna.","long_term_effect":"","impact":{"rapport":7,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Focar apenas na técnica de respiração para controlar a ansiedade.","approach":"Reducionismo para o controle de sintomas, sem abordar o núcleo cognitivo.","is_optimal":false,"immediate_outcome":"Você ensina um exercício de respiração e diz: ''Use isso se ficar nervoso.'' A preocupação central de Lucas (o julgamento) não é abordada. Ele pode executar a tarefa apenas ''sobrevivendo'' à ansiedade, sem testar verdadeiramente seu pensamento, limitando o insight.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":5,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":9,"session_title":"Consolidação de Ganhos e Prevenção de Recaída","session_phase":"closing","session_content":{"narrative":"Lucas chega animado. Ele realizou o experimento: fez seu comentário na reunião, sua voz tremeu levemente, e ninguém pareceu notar ou reagir de forma negativa. Ele registrou: ''A hipótese catastrófica não se confirmou. A alternativa realista foi mais precisa.'' Você explora com ele o que aprendeu (ex.: ''Minha atenção amplificava os sinais de perigo''; ''As pessoas estão mais focadas em si mesmas''). Em seguida, você introduz o conceito de ''crenças centrais'' (ex.: ''Sou inadequado''), conectando os pensamentos automáticos testados a esse esquema mais profundo. Juntos, revisam todo o percurso desde a primeira sessão, listando as técnicas aprendidas (registro cognitivo, experimentos, atenção seletiva) e as situações em que ele as usou com sucesso. O tom é de celebração, mas você nota um medo sutil em Lucas: o de ''voltar a ser como antes'' após o fim da terapia.","session_goals":["Consolidar os aprendizados e habilidades adquiridas ao longo da terapia.","Iniciar o trabalho de prevenção de recaída, identificando sinais de alerta e planos de ação."],"key_observations":["Lucas demonstra internalização das ferramentas cognitivo-comportamentais.","O medo de recaída é um sinal comum na fase de encerramento e deve ser normalizado e planejado."],"critical_decision_point":"Como você estrutura a prevenção de recaída para abordar esse medo de forma prática?"},"expert_commentary":"A opção A é a mais alinhada com os princípios de TCC para o encerramento. A prevenção de recaída é um componente estruturado e essencial. Ela transforma o medo abstrato em um plano de ação concreto, promovendo autoeficácia. Normalizar lapsos como oportunidades de aprendizado, e não como fracassos, é crucial (Marlatt & Gordon, 1985). O plano escrito serve como um ''kit de primeiros socorros'' cognitivo-comportamental, aumentando a probabilidade de que Lucas generalize e mantenha os ganhos a longo prazo.","learning_focus":"Habilidade de conduzir o encerramento terapêutico, consolidando ganhos e co-criando um plano de prevenção de recaída estruturado.","decision_options":[{"option_letter":"A","intervention":"Co-criar um ''Plano de Prevenção de Recaída'' concreto e normalizar lapsos.","approach":"Psicoeducação sobre a curva de aprendizagem e planejamento colaborativo.","is_optimal":true,"immediate_outcome":"Você normaliza: ''Um lapso não é uma recaída. É parte do processo.'' Juntos, criam um plano escrito: 1) Identificar os 3 principais ''sinais de alerta'' (ex.: evitar contato visual novamente). 2) Listar as 2 técnicas mais úteis para ele (ex.: registro de pensamentos, experimento pequeno). 3) Definir um passo de ação se as coisas piorarem (ex.: retomar os registros por uma semana, agendar uma sessão de reforço). Lucas se sente empoderado e com um ''manual de instruções'' para o futuro.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Oferecer sessões de manutenção indefinidas para segurança.","approach":"Postura superprotetora que pode minar a autoeficácia.","is_optimal":false,"immediate_outcome":"Você diz: ''Podemos marcar sessões mensais por tempo indeterminado, para você não se sentir sozinho.'' Lucas sente alívio imediato, mas isso pode reforçar a crença de que ele não é capaz de se autogerir sem o terapeuta, criando dependência e não resolvendo o medo subjacente.","long_term_effect":"","impact":{"rapport":8,"insight":5,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"C","intervention":"Minimizar o medo e focar apenas no sucesso atual.","approach":"Evitação da discussão sobre dificuldades futuras.","is_optimal":false,"immediate_outcome":"Você responde: ''Não pense nisso! Veja como você evoluiu.'' Lucas não expressa mais a preocupação, mas o medo não é trabalhado. Se um lapso ocorrer, ele pode interpretá-lo como um fracasso total e não utilizar as ferramentas que possui.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Explorar as origens profundas do medo de fracasso.","approach":"Mudança para uma abordagem exploratória não focalizada.","is_optimal":false,"immediate_outcome":"Você pergunta: ''De onde vem esse medo de perder todo o progresso? Isso lembra algo da sua infância?'' A sessão se aprofunda em questões históricas, desviando do foco pragmático de consolidar habilidades e planejar o futuro, deixando Lucas sem um plano de ação concreto.","long_term_effect":"","impact":{"rapport":7,"insight":7,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":10,"session_title":"Revisão da Exposição e Identificação de Crenças Nucleares","session_phase":"middle","session_content":{"narrative":"A sessão começa com a paciente, Sofia, relatando sua experiência com a tarefa de exposição da semana anterior: participar de uma reunião de trabalho virtual com a câmera ligada. Ela descreve uma ansiedade inicial intensa, mas relata que, após os primeiros minutos, conseguiu se concentrar no conteúdo. No entanto, Sofia menciona um \"pensamento intrusivo\" que a perturbou: ''Eles devem estar me julgando como a pessoa mais desinteressante da sala''. Ela minimiza seu progresso, focando apenas nesse momento. O terapeuta nota que Sofia está utilizando um processamento pós-evento (PPE) intenso, ruminando sobre detalhes mínimos da interação. A sessão avança para uma análise cognitiva mais profunda, conectando a situação específica a esquemas mais amplos. O terapeuta utiliza o registro de pensamentos automáticos de Sofia para identificar padrões, como a leitura mental (''eles pensam que sou chata'') e a personalização (''se a reunião foi monótona, a culpa é minha'').","session_goals":["Revisar a tarefa de exposição realizada, validando o progresso e analisando dificuldades","Identificar e conectar pensamentos automáticos a crenças intermediárias e nucleares subjacentes"],"key_observations":["Sofia demonstra PPE (Processamento Pós-Evento), um marcador comum na Fobia Social (DSM-5-TR)","Ela minimiza sucessos e maximiza percepções de julgamento, indicando distorções cognitivas como desqualificação do positivo e leitura mental","Há um afeto de vergonha e autocrítica associado à crença nuclear de ''sou inadequada socialmente''"],"critical_decision_point":"Como você procede para aprofundar a investigação cognitiva e engajar Sofia?"},"expert_commentary":"A opção A é a mais alinhada com a fase intermediária da TCC para Fobia Social. Beck (2011) enfatiza que a identificação de crenças nucleares é crucial para mudanças duradouras. A ''seta descendente'' é uma técnica clássica para acessar significados pessoais mais profundos. Embora provoque ansiedade inicial, conduzida com empatia, ela gera insight poderoso. Ignorar essa resistência (Opção D) ou apenas validar (B) não avança o caso. A refutação prematura (C) é ineficaz, pois, como observa Clark e Wells (1995), nas fobias sociais, as crenças são mantidas por processamento autorreferencial e não por falta de evidência lógica.","learning_focus":"Técnica de Seta Descendente para Acesso a Crenças Nucleares","decision_options":[{"option_letter":"A","intervention":"Utilizar a técnica da seta descendente, perguntando repetidamente ''E se isso fosse verdade, o que isso significaria sobre você?''","approach":"Abordagem Cognitiva (Técnica Específica)","is_optimal":true,"immediate_outcome":"Sofia, inicialmente resistente, engaja-se e chega à crença nuclear ''Sou fundamentalmente diferente e menos interessante que os outros, merecendo exclusão''. Isso fornece um alvo claro para intervenções futuras.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Validar sua frustração e sugerir retornar a uma técnica de relaxamento para acalmar a ansiedade antes de continuar.","approach":"Abordagem Centrada na Emoção/Validação","is_optimal":false,"immediate_outcome":"Sofia se acalma, mas a oportunidade de acessar o núcleo da crença é perdida. A sessão pode ficar estagnada em um nível superficial de manejo do afeto.","long_term_effect":"","impact":{"rapport":8,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Confrontar suavemente a distorção, listando evidências concretas de que ela contribuiu para a reunião.","approach":"Abordagem Cognitiva (Refutação Direta)","is_optimal":false,"immediate_outcome":"Sofia concorda intelectualmente, mas a crença emocional permanece intocada (''Sim, mas ainda *sinto* que sou chata''). A intervenção pode soar como uma minimização de sua experiência.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar de tópico e planejar a próxima exposição, evitando o desconforto atual.","approach":"Abordagem de Evitação/Agendamento","is_optimal":false,"immediate_outcome":"A aliança terapêutica é prejudicada, pois Sofia pode perceber que o terapeuta também evita o tema central. O progresso na reestruturação cognitiva é interrompido.","long_term_effect":"","impact":{"rapport":3,"insight":2,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":11,"session_title":"Testando a Crença Nuclear: O Experimento Comportamental","session_phase":"advanced","session_content":{"narrative":"Com base na sessão anterior, a crença nuclear identificada (''Sou fundamentalmente menos interessante e mereço exclusão'') é colocada em discussão. Sofia reconhece que essa crença opera como uma ''lente'' que distorce todas as suas interações. O terapeuta propõe co-criar um experimento comportamental para testar a validade dessa crença, em vez de apenas questioná-la logicamente. Juntos, delineiam uma situação de risco moderado: Sofia iniciará uma conversa breve com um colega no café do trabalho sobre um assunto neutro (ex.: uma série de TV). Eles definem previsões específicas e testáveis baseadas na crença (ex.: ''Ele vai dar respostas monossilábicas, olhar para o relógio e encontrar uma desculpa para sair em menos de 2 minutos''). Também planejam como coletar evidências de forma objetiva (contar o tempo, observar a linguagem corporal, notar o conteúdo da resposta). Sofia está ansiosa, mas engajada, percebendo a proposta como uma ''investigação científica'' de seu medo.","session_goals":["Desenvolver um experimento comportamental colaborativo para testar a crença nuclear identificada","Preparar a paciente para a execução da tarefa, manejando a ansiedade antecipatória"],"key_observations":["Sofia demonstra capacidade de metacognição (''operar como uma lente''), sinal de insight adquirido","A ansiedade está presente, mas é canalizada para a estrutura do experimento, o que a torna mais manejável","A colaboração no planejamento aumenta o senso de agência e adesão de Sofia"],"critical_decision_point":"Como você responde à solicitação de incluir um comportamento de segurança no experimento?"},"expert_commentary":"A opção A é clinicamente sólida. Hoffart et al. (2009) destacam que a eliminação de comportamentos de segurança é um componente crítico da TCC para Fobia Social, pois eles impedem a aprendizagem de que a situação social não é perigosa. A psicoeducação sobre seu papel mantenedor é essencial. A Opção B, embora empática, reforça a fobia. A C é complicada e pode ser um meio-termo ineficaz. A D, embora relevante, é mal-temporada; a análise do comportamento de segurança é melhor feita *antes* do planejamento do experimento ou *após* sua execução, como parte da revisão.","learning_focus":"Manejo de Comportamentos de Segurança em Experimentos Comportamentais","decision_options":[{"option_letter":"A","intervention":"Explicar que comportamentos de segurança, embora reconfortantes, impedem o teste real da crença, pois mantêm a ideia de que o perigo é real. Sugerir que ela execute o experimento sem ele.","approach":"Abordagem de Exposição com Prevenção de Resposta (baseado no modelo de Clark & Wells)","is_optimal":true,"immediate_outcome":"Sofia concorda, relutantemente, mas entende o racional. O experimento gera dados mais claros e poderosos, pois a ansiedade diminui naturalmente durante a interação, desconfirmando suas previsões catastróficas.","long_term_effect":"","impact":{"rapport":6,"insight":9,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Concordar que ela use o copo, pois é um passo inicial importante e reduz a ansiedade a um nível tolerável.","approach":"Abordagem Gradualista/De Acomodação","is_optimal":false,"immediate_outcome":"Sofia realiza a tarefa com mais conforto, mas atribui seu sucesso (''ele conversou normalmente'') ao copo de água (comportamento de segurança), não desconfirmando a crença central sobre si mesma. O aprendimento correcional é limitado.","long_term_effect":"","impact":{"rapport":8,"insight":5,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Propor um compromisso: ela faz o experimento duas vezes, uma com o copo e outra sem, para comparar os resultados.","approach":"Abordagem de Teste Comparativo","is_optimal":false,"immediate_outcome":"A proposta é criativa, mas pode ser confusa e onerosa. Sofia pode focar nas diferenças de ansiedade entre as tentativas, não no teste da crença nuclear sobre ser ''desinteressante''. Dilui o foco do experimento.","long_term_effect":"","impact":{"rapport":7,"insight":6,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"D","intervention":"Questionar por que ela precisa do copo, levando-a a explorar a crença por trás do comportamento de segurança.","approach":"Abordagem Cognitiva Pura (Análise do Comportamento de Segurança)","is_optimal":false,"immediate_outcome":"A análise é válida, mas interrompe o fluxo do planejamento prático. Pode parecer crítico e aumentar a resistência de Sofia, que apenas pediu uma adaptação para se sentir mais segura.","long_term_effect":"","impact":{"rapport":4,"insight":7,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"},{"session_number":12,"session_title":"Consolidação de Novas Crenças e Prevenção de Recaída","session_phase":"closing","session_content":{"narrative":"Sofia chega animada para a sessão. Ela realizou o experimento sem o copo de água. Suas previsões catastróficas não se confirmaram: a conversa durou 5 minutos, o colega fez perguntas de volta e até riu de um comentário dela. O terapeuta guia uma análise detalhada dos resultados, ajudando Sofia a formular uma nova crença mais adaptativa: ''Posso ser uma interlocutora comum e capaz, e as pessoas geralmente respondem ao que eu digo, não a uma avaliação global de mim''. Eles revisam todo o percurso terapêutico, desde a psicoeducação sobre ansiedade social até as exposições e a reestruturação cognitiva profunda. Sofia relata que se sente ''mais leve'' e que o ''barulho mental'' de julgamento diminuiu. O terapeuta introduz o conceito de recaída como parte do processo, normalizando a possibilidade de pensamentos antigos retornarem em situações de alto estresse.","session_goals":["Analisar os resultados do experimento comportamental e formular uma crença adaptativa nova","Revisar o progresso da terapia e consolidar aprendizados","Elaborar um plano de prevenção de recaída"],"key_observations":["Sofia apresenta afeto positivo e linguagem de agência (''eu consegui'', ''eu percebi'')","A nova crença é realista (''interlocutora comum'') e não grandiosa, o que aumenta sua credibilidade para ela","Há uma redução significativa nos sintomas de ansiedade antecipatória e PPE relatados"],"critical_decision_point":"Como você estrutura a resposta para normalizar a recaída e empoderar Sofia?"},"expert_commentary":"A Opção A é a mais eficaz para uma sessão de encerramento. Marlatt & Donovan (2005) enfatizam que a prevenção de recaída deve incluir a normalização de lapsos, a distinção entre lapso e recaída total, e a criação de um plano de ação. A metáfora do músculo é útil. A Opção B é uma armadilha comum (prometer cura total), a C é incompleta por ser puramente técnica, e a D pode ser iatrogênica, criando dependência. O objetivo final da TCC é tornar o paciente seu próprio terapeuta, e a Opção A serve exatamente a esse propósito.","learning_focus":"Psicoeducação para Prevenção de Recaída e Empoderamento do Paciente","decision_options":[{"option_letter":"A","intervention":"Utilizar a metáfora do ''músculo da ansiedade social'' e do ''treinamento'', explicando que recaídas são oportunidades de praticar as habilidades aprendidas, não falhas. Co-criar um ''plano de ação'' concreto para essa situação hipotética.","approach":"Abordagem de Normalização e Empoderamento com Planejamento Concreto","is_optimal":true,"immediate_outcome":"Sofia se sente aliviada e preparada. Ela sai da terapia com um ''kit de ferramentas'' cognitivo-comportamental e um plano escrito para situações de risco, aumentando sua autoeficácia e resiliência a longo prazo.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Assegurá-la de que, como ela fez tanto progresso, é muito improvável que os pensamentos voltem com a mesma intensidade.","approach":"Abordagem de Reafirmação Otimista","is_optimal":false,"immediate_outcome":"Pode acalmar Sofia no momento, mas estabelece uma expectativa irrealista. Se os sintomas retornarem, ela pode interpretar como uma falha pessoal catastrófica, minando a confiança no processo terapêutico.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Revisar rapidamente as técnicas de relaxamento e reestruturação cognitiva, sugerindo que ela ''simplesmente as use'' se isso acontecer.","approach":"Abordagem Técnica e Instrucional","is_optimal":false,"immediate_outcome":"A resposta é correta em conteúdo, mas falha em abordar o medo subjacente de ''falha''. Pode soar como uma solução simplista para um medo profundo de Sofia, não fortalecendo sua mentalidade de enfrentamento.","long_term_effect":"","impact":{"rapport":5,"insight":6,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"D","intervention":"Propor estender a terapia por mais algumas sessões para trabalhar especificamente esse medo de recaída.","approach":"Abordagem de Extensão da Terapia","is_optimal":false,"immediate_outcome":"Pode inadvertidamente sinalizar que Sofia não está ''pronta'' ou que o problema é maior do que parecia, aumentando sua dependência da terapia e diminuindo sua autoeficácia.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}}],"disorder":"Fobia Social","difficulty_level":"intermediate"}]'::jsonb
WHERE title ILIKE '%Jornada%' AND (
  title ILIKE '%012%' OR 
  title ILIKE '%0012%'
);

-- Journey 013
UPDATE clinical_journeys 
SET sessions = '[{"session_number":1,"session_title":"Mapeando o Pânico: A Primeira Crise","session_phase":"initial","session_content":{"narrative":"A sessão inicia com Thiago, 32 anos, engenheiro, visivelmente tenso. Ele relata que o transtorno começou há três meses com uma crise súbita no metrô: taquicardia, sudorese, tremores, sensação de asfixia e medo intenso de morrer. Desde então, teve mais quatro ataques, sempre em locais públicos ou quando se sente ''preso''. Ele descreve um medo persistente de ter novas crises, o que o levou a evitar o metrô, shopping centers e filas. Thiago fala rapidamente, com um tom de desespero, e menciona que já foi ao cardiologista, que descartou problemas físicos. Ele se sente ''fraco'' e ''envergonhado'' por não controlar seu próprio corpo. Durante o relato, você observa sinais de ansiedade antecipatória e um padrão de hipervigilância em relação às sensações corporais. O foco inicial é estabelecer uma aliança terapêutica sólida e começar a psicoeducação sobre o modelo cognitivo-comportamental do pânico.","session_goals":["Estabelecer rapport e validar a experiência do cliente","Realizar psicoeducação inicial sobre a natureza dos ataques de pânico e a ansiedade antecipatória"],"key_observations":["Cliente apresenta alto nível de ansiedade antecipatória e hipervigilância corporal","Relato clássico de ataques de pânico inesperados seguidos de comportamento de esquiva agorafóbica incipiente","Há alívio por ter um diagnóstico médico que descarta problemas cardíacos, mas também confusão sobre a origem ''psicológica'' dos sintomas"],"critical_decision_point":"Como você responde para promover esperança realista e engajamento no tratamento?"},"expert_commentary":"A pergunta do cliente sobre a ''cura'' é um momento crucial para o engajamento. A opção ótima (A) utiliza a psicoeducação, uma intervenção de primeira linha para o pânico (Barlow et al., 2017). Explicar o modelo do ''ciclo do pânico'' e o conceito de ''medo do medo'' valida a experiência, oferece um quadro compreensível e instila esperança baseada em mecanismos de mudança específicos. Isso contrasta com o reasseguramento vago (B), que pode minar a credibilidade, ou a confrontação prematura (C), que pode ser percebida como invalidante. A normalização é fundamental, pois, como descreve o DSM-5-TR, os ataques de pânico são ''ondas abruptas de medo intenso ou desconforto intenso'' que atingem um pico em minutos, e o transtorno é altamente tratável.","learning_focus":"Psicoeducação e validação como ferramentas para construir aliança e esperança realista","decision_options":[{"option_letter":"A","intervention":"Explicar o modelo de ''medo do medo'' e a possibilidade de dessensibilização","approach":"Psicoeducação baseada em evidências e normalização","is_optimal":true,"immediate_outcome":"Thiago se acalma visivelmente. Ele compreende que seu medo é uma reação aprendida e que o tratamento focará em quebrar esse ciclo. Concorda em começar um diário de sintomas.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"B","intervention":"Garantir de forma genérica que ''tudo vai ficar bem'' com o tempo","approach":"Reasseguramento vago e otimista","is_optimal":false,"immediate_outcome":"Thiago parece momentaneamente aliviado, mas depois expressa ceticismo, dizendo que ''palavras são fáceis''. A aliança terapêutica não se aprofunda.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Focar imediatamente nas distorções cognitivas sobre a palavra ''cura''","approach":"Confrontação cognitiva prematura","is_optimal":false,"immediate_outcome":"Thiago se sente invalidado e corrigido. Ele fecha a postura corporal e responde de forma monossilábica, dificultando o prosseguimento da sessão.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Desviar da pergunta e pedir para ele descrever outra crise em detalhes","approach":"Evitação do conteúdo emocional","is_optimal":false,"immediate_outcome":"Thiago fica confuso com a mudança de assunto. Ele obedece, mas o relato é mais superficial e a ansiedade aumenta, sem que seu medo central tenha sido abordado.","long_term_effect":"","impact":{"rapport":3,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":2,"session_title":"Desvendando o Ciclo: Pensamentos Catastróficos","session_phase":"middle","session_content":{"narrative":"Thiago chega mais calmo, trazendo o diário de sintomas. Ele registrou uma sensação de ''aperto no peito'' enquanto estava no carro em um engarrafamento, que não evoluiu para um ataque completo porque conseguiu sair da via. A análise do diário revela um padrão claro: a percepção de uma sensação física (ex.: batimento cardíaco acelerado) é seguida imediatamente por pensamentos catastróficos (''Vou ter um infarto'', ''Vou desmaiar e ninguém vai me ajudar''). Isso desencadeia mais ansiedade e mais sintomas, num ciclo. Thiago identifica que o pensamento mais frequente é ''Vou morrer''. Você apresenta o modelo cognitivo do pânico, ligando sensações, pensamentos, emoções e comportamentos. Ele demonstra compreensão intelectual, mas ainda com medo emocional. O desafio agora é começar a questionar a veracidade desses pensamentos catastróficos, introduzindo a reestruturação cognitiva de forma suave.","session_goals":["Identificar e conectar pensamentos automáticos catastróficos às sensações físicas e ao comportamento de esquiva","Introduzir a técnica de reestruturação cognitiva, começando pela busca de evidências"],"key_observations":["Cliente consegue fazer uma auto-observação metódica via diário, indicando boa adesão","Padrão de pensamento catastrófico típico do pânico (''medo de morrer'', ''medo de enlouquecer'') está bem estabelecido","Há uma dissociação entre a compreensão cognitiva do modelo e a crença emocional subjacente, que requer intervenções experienciais futuras"],"critical_decision_point":"Como você procede para ajudá-lo a desafiar essa crença de forma eficaz?"},"expert_commentary":"O cliente articula o núcleo do transtorno de pânico: a interpretação catastrófica de sensações corporais benignas (Clark, 1986). A intervenção ótima (A) vai além da disputa verbal (B, C) e utiliza um experimento comportamental, uma ferramenta poderosa da TCC. Ele permite que o cliente teste diretamente a crença (''aceleração cardíaca = infarto'') através da experiência, gerando uma aprendizagem emocional corretiva mais profunda. O reasseguramento repetitivo (B) pode, paradoxalmente, manter o transtorno, como parte dos ''comportamentos de segurança''. A busca de evidências (C) é um passo válido, mas muitas vezes insuficiente sozinha no pânico, onde a crença é mantida por um viés atencional e interpretativo forte. A normalização invalidante (D) rompe a aliança.","learning_focus":"Uso de experimentos comportamentais para desafiar crenças catastróficas de forma experiencial","decision_options":[{"option_letter":"A","intervention":"Propor um experimento comportamental simples: comparar a frequência cardíaca em repouso com a durante uma leve atividade física","approach":"Teste de hipótese comportamental (experimento de realidade)","is_optimal":true,"immediate_outcome":"Thiago fica intrigado. Ele mede sua FC em repouso (80 bpm) e depois de subir escadas (120 bpm). Percebe que a aceleração, por si só, não é perigosa. A crença na catástrofe começa a se enfraquecer.","long_term_effect":"","impact":{"rapport":7,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Repetir e insistir na informação médica do cardiologista, reassegurando-o","approach":"Reasseguramento factual e confrontação verbal","is_optimal":false,"immediate_outcome":"Thiago concorda verbalmente, mas diz ''Na minha cabeça eu sei, mas no corpo não entra''. A crença emocional não é afetada, e ele pode se tornar dependente do reasseguramento do terapeuta.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Pedir para ele listar todas as vezes que pensou nisso e não teve um infarto","approach":"Busca de evidências contra a catástrofe","is_optimal":false,"immediate_outcome":"Thiago consegue listar várias ocasiões, mas descarta cada uma com um ''e se...'' (e se da próxima for diferente?). A técnica puramente cognitiva é insuficiente para a crença emocional forte.","long_term_effect":"","impact":{"rapport":6,"insight":7,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"D","intervention":"Minimizar o medo, dizendo que ''todo mundo tem taquicardia às vezes''","approach":"Normalização invalidante","is_optimal":false,"immediate_outcome":"Thiago se sente incompreendido e trivializado. Ele retrai-se, acreditando que seu sofrimento único não está sendo levado a sério.","long_term_effect":"","impact":{"rapport":3,"insight":2,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":3,"session_title":"Confrontando as Sensações: Introdução à Exposição Interoceptiva","session_phase":"middle","session_content":{"narrative":"Após o sucesso do experimento com a frequência cardíaca, Thiago está mais confiante para questionar seus pensamentos. No entanto, ele relata que o ''medo da sensação em si'' persiste, especialmente a tontura e a falta de ar. Ele evita exercícios, café e situações que possam desencadear essas sensações. Você explica o conceito de exposição interoceptiva: induzir de forma segura e controlada as sensações temidas para que o corpo aprenda que elas não são perigosas. Thiago fica apreensivo, mas curioso. Vocês revisam juntos uma lista de exercícios (girar em uma cadeira, respirar por um canudo, prender a respiração) e discutem a Subjective Units of Distress Scale (SUDS). O objetivo desta sessão é realizar a primeira exposição, de baixa intensidade, no setting terapêutico, para quebrar o elo entre a sensação e a catástrofe.","session_goals":["Psicoeducar sobre a exposição interoceptiva e sua lógica (habituação e reavaliação de perigo)","Realizar um primeiro exercício de exposição interoceptiva de baixa intensidade na sessão"],"key_observations":["Cliente demonstra readiness para intervenções mais ativas, fruto do rapport e da psicoeducação anteriores","O foco do medo migrou ligeiramente dos pensamentos catastróficos para as próprias sensações físicas (condicionamento interoceptivo)","Há uma ansiedade antecipatória clara em relação ao exercício, mas também motivação para enfrentá-lo"],"critical_decision_point":"Como você maneja essa ansiedade antecipatória para garantir que a exposição seja realizada com sucesso?"},"expert_commentary":"Este é o momento crítico da exposição. A ansiedade antecipatória é esperada. A opção ótima (A) combina validação (aceitando o medo como parte do processo) com uma atitude colaborativa e corajosa (fazer junto). Isso modela que a sensação é segura e que se pode tolerar o desconforto. Adiar (B) reforça a esquiva, que é o mecanismo de manutenção central do transtorno. Pressão (C) pode retraumatizar. Acomodar excessivamente (D) não permite a habituação ao estímulo-alvo. A exposição interoceptiva é um tratamento de primeira linha para o pânico (Craske & Barlow, 2014). Seu sucesso depende de ser feita de forma colaborativa, repetida e sem comportamentos de segurança, para que ocorra a reavaliação do perigo e a habituação.","learning_focus":"Manejo da resistência e ansiedade antecipatória durante a introdução de técnicas de exposição","decision_options":[{"option_letter":"A","intervention":"Validar o medo, revisar o plano de segurança e fazer o exercício junto com ele, modelando a atitude","approach":"Validação, colaboração e modelagem","is_optimal":true,"immediate_outcome":"Thiago se sente apoiado e seguro. Ele realiza o exercício. A SUDS sobe para 7, mas depois diminui para 4 dentro da sessão. Ele fica surpreso e aliviado por ter ''sobrevivido'' à sensação sem catástrofe.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Adiar a exposição e voltar a discutir os pensamentos catastróficos sobre ''perder o controle''","approach":"Evitação da exposição e retorno à cognição","is_optimal":false,"immediate_outcome":"Thiago sente alívio imediato, mas reforça-se a crença de que a situação era realmente perigosa demais para ser enfrentada. A esquiva é fortalecida, e o progresso estagna.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Minimizar sua preocupação e insistir para que ele ''confie em você'' e prossiga","approach":"Pressão autoritária e invalidação","is_optimal":false,"immediate_outcome":"Thiago pode ceder e fazer o exercício, mas com ressentimento e medo intensificado. A experiência é traumática, prejudicando a aliança e possivelmente levando ao abandono do tratamento.","long_term_effect":"","impact":{"rapport":2,"insight":3,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar para um exercício ainda mais suave, como sacudir a cabeça, sem abordar o medo expresso","approach":"Acomodação do comportamento de segurança","is_optimal":false,"immediate_outcome":"A exposição ocorre, mas o núcleo do medo (''perder o controle'') não é confrontado. Thiago aprende que só pode enfrentar sensações ''super seguras'', limitando a generalização do aprendizado.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":5,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":4,"session_title":"Mapeando o Pânico: Identificando Gatilhos e Sensações","session_phase":"middle","session_content":{"narrative":"A sessão começa com Thiago, 28 anos, relatando que teve dois ataques de pânico na semana, um no metrô e outro em casa, assistindo TV. Ele descreve o episódio no transporte público com detalhes vívidos: \"De repente, o coração disparou, senti que ia sufocar e tive certeza que ia morrer ali mesmo. Foi aterrorizante.\" Ele evitou o metrô desde então. Você nota que Thiago está visivelmente ansioso ao relembrar, com respiração acelerada. Você o elogia pela coragem de detalhar a experiência, validando seu sofrimento. Em seguida, introduz o modelo cognitivo-comportamental do pânico, explicando a sequência de sensações físicas, pensamentos catastróficos (ex: \"vou morrer\", \"vou enlouquecer\") e comportamentos de fuga/evitação. Juntos, começam a preencher um registro de pensamentos para o ataque no metrô, onde Thiago identifica a sensação inicial (taquicardia) e o pensamento automático (\"Isso é um infarto!\").","session_goals":["Psicoeducação sobre o ciclo do pânico conforme o DSM-5-TR","Iniciar o mapeamento cognitivo de um ataque recente"],"key_observations":["Thiago demonstra boa capacidade de introspecção ao detalhar os sintomas","Evitação do metrô já está consolidada como comportamento de segurança","Resposta fisiológica de ansiedade é ativada ao narrar o evento"],"critical_decision_point":"Como você responde para trabalhar essa dúvida persistente?"},"expert_commentary":"A opção A é ótima porque segue o princípio de Barlow (2002) de ''realidade versus percepção de ameaça''. Validar o medo mantém a aliança, enquanto o experimento comportamental propõe uma coleta de dados colaborativa. Isso é superior a apenas fornecer garantias verbais (Opção B), que são pouco eficazes no pânico. A Opção C reforça a ''busca por segurança'', um comportamento de manutenção do transtorno. A Opção D modela evitação, contraproducente para a terapia.","learning_focus":"Diferenciação entre validação emocional e confronto cognitivo colaborativo","decision_options":[{"option_letter":"A","intervention":"Validar a preocupação e propor um experimento comportamental conjunto","approach":"Abordagem colaborativa baseada em evidências","is_optimal":true,"immediate_outcome":"Você diz: \"É compreensível que essa dúvida assuste, já que as sensações são muito reais. Vamos usar as evidências dos seus exames e criar um pequeno teste? Podemos ver o que acontece com sua frequência cardíaca durante uma respiração acelerada controlada aqui no consultório, em segurança.\" Thiago concorda, sentindo-se ouvido e desafiando a crença de forma segura.","long_term_effect":"","impact":{"rapport":8,"insight":7,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"B","intervention":"Enfatizar que os exames são prova conclusiva e que a preocupação é irracional","approach":"Lógica racional diretiva","is_optimal":false,"immediate_outcome":"Você argumenta: \"Os exames médicos descartaram problema cardíaco. Portanto, sua preocupação é um produto da ansiedade, não um fato.\" Thiago fica em silêncio e concorda nominalmente, mas internaliza que suas preocupações estão sendo invalidadas como ''irracionais'', prejudicando a aliança.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Sugerir que ele consulte outro cardiologista para mais tranquilidade","approach":"Acomodação da ansiedade","is_optimal":false,"immediate_outcome":"Você sugere: \"Se isso ainda te preocupa, que tal buscar uma segunda opinião médica para ficar 100% tranquilo?\" Thiago sai da sessão decidindo marcar nova consulta. Isso reforça o comportamento de busca por segurança e adia o confronto com a cognição do pânico.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Mudar de tópico para evitar aumentar sua ansiedade na sessão","approach":"Evitação do terapeuta","is_optimal":false,"immediate_outcome":"Percebendo seu desconforto, você diz: \"Vamos deixar isso de lado por hoje e focar nos sintomas iniciais.\" A ansiedade de Thiago diminui momentaneamente, mas a crença central não é abordada, e ele aprende que o tema é ''perigoso'' demais para ser explorado.","long_term_effect":"","impact":{"rapport":3,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":5,"session_title":"Confrontando as Sensações: Experimentos Interoceptivos Iniciais","session_phase":"middle","session_content":{"narrative":"Thiago chega relatando que tentou o exercício de respiração acelerada em casa, mas parou com medo. \"A sensação de tontura me assustou muito, parecia que ia desmaiar.\" Você revisa o registro da sessão anterior, destacando a conexão entre a tontura e o pensamento \"vou desmaiar\". Com base na decisão anterior (se a Opção A foi escolhida), você propõe realizar os primeiros exercícios interoceptivos no consultório, explicando seu propósito: dessensibilizar e demonstrar que as sensações, embora desconfortáveis, são inofensivas e temporárias. Você modela o primeiro exercício (respirar rapidamente por um minuto) e depois pede que Thiago o faça. Ele hesita, mas concorda. Durante o exercício, ele fica pálido e agarra os braços da cadeira. Após 45 segundos, ele para, ofegante, e relata taquicardia e tontura intensa.","session_goals":["Introduzir e praticar exercícios interoceptivos em ambiente seguro","Monitorar e reestruturar pensamentos catastróficos durante as sensações"],"key_observations":["Thiago demonstra alta sensibilidade a sintomas vestibulares (tontura)","Comportamento de segurança (agarrar a cadeira) é evidente durante o exercício","Há uma adesão inicial, mas com alto nível de medo"],"critical_decision_point":"Como você procede após esta reação intensa ao exercício interoceptivo?"},"expert_commentary":"A Opção A é ideal porque capitaliza o ''momento de aprendizagem emocional'' pós-exposição, como descrito por Clark & Beck (2010). Processar a experiência em tempo real, destacando a não-ocorrência da catástrofe prevista, é central para a reestruturação cognitiva. A Opção B, embora bem-intencionada, reforça a fobia interoceptiva. A Opção C viola o princípio de colaboração e controle do paciente sobre a exposição, podendo levar a sensitização. A Opção D perde a oportunidade terapêutica mais valiosa da sessão.","learning_focus":"Manejo de reações intensas durante exposição interoceptiva e processamento cognitivo in vivo","decision_options":[{"option_letter":"A","intervention":"Normalizar a reação, validar a coragem e fazer uma análise cognitiva em tempo real","approach":"Integração de exposição e reestruturação cognitiva","is_optimal":true,"immediate_outcome":"Você responde calmamente: \"Thiago, você foi muito corajoso. É normal que a sensação seja idêntica e assustadora. Vamos observar juntos: o que aconteceu de fato? Você desmaiou? A taquicardia está diminuindo agora?\" Você guia ele a observar a redução natural dos sintomas e a desconectar a sensação da catástrofe. Ele se acalma gradualmente e percebe que sobreviveu à sensação.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Interromper os exercícios interoceptivos e retornar a técnicas de relaxamento","approach":"Retirada para evitar o sofrimento do paciente","is_optimal":false,"immediate_outcome":"Preocupado com seu sofrimento, você diz: \"Vamos parar por aqui. Talvez seja cedo para isso. Vamos focar em técnicas de respiração diafragmática para você se acalmar agora.\" Thiago se alivia no momento, mas internaliza que as sensações são realmente perigosas e intocáveis, fortalecendo a evitação.","long_term_effect":"","impact":{"rapport":6,"insight":3,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Insistir para que ele repita o exercício imediatamente para \"superar o medo\"","approach":"Exposição intensiva não colaborativa","is_optimal":false,"immediate_outcome":"Você incentiva: \"É preciso enfrentar! Vamos fazer de novo agora, não pode fugir.\" Thiago, pressionado, tenta novamente mas com pânico crescente. Ele pode completar o exercício, mas a experiência é traumática, danificando a aliança terapêutica e aumentando a resistência.","long_term_effect":"","impact":{"rapport":3,"insight":4,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Minimizar a reação e passar para o planejamento da tarefa de casa","approach":"Evitação do momento emocional crítico","is_optimal":false,"immediate_outcome":"Você diz: \"Bem, é assim mesmo. Agora, para casa, quero que você tente girar em uma cadeira para gerar tontura.\" Você não processa a experiência emocional intensa que acabou de acontecer. Thiago sai confuso e sentindo-se incompreendido, sem ferramentas para lidar com o medo que surgiu.","long_term_effect":"","impact":{"rapport":4,"insight":3,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":6,"session_title":"Expandindo a Tolerância: Da Sensação ao Contexto","session_phase":"advanced","session_content":{"narrative":"Thiago inicia a sessão mais confiante. \"Fiz o exercício de girar na cadeira em casa duas vezes. Na primeira foi péssimo, mas na segunda já foi um pouco menos pior. Não desmaiei.\" Você reforça esse progresso significativo. Juntos, revisam a hierarquia de exposição interoceptiva que construíram, e Thiago se mostra disposto a subir um degrau. O foco da sessão se desloca para os contextos de evitação. Thiago relata que ainda não voltou ao metrô e evita filas longas no supermercado. Você explora as cognições específicas para esses contextos: \"No metrô, além do medo de ter um ataque, tenho pavor de ficar preso e não conseguir ajuda.\" Você introduz o conceito de ''comportamentos de segurança'' (ex: levar remédios, ficar perto da porta, checar saídas) e Thiago identifica vários que utiliza. A sessão avança para o planejamento de uma primeira exposição in vivo de baixo grau.","session_goals":["Consolidar ganhos da interocepção e planejar exposição in vivo contextual","Identificar e trabalhar para a redução de comportamentos de segurança"],"key_observations":["Thiago demonstra aumento na tolerância à ansiedade e autoeficácia","A evitação agora está mais ligada a aspectos contextuais (estar preso, sem saída) do que apenas às sensações","Comportamentos de segurança são numerosos e bem estabelecidos"],"critical_decision_point":"Como você responde a essa proposta, que inclui dois comportamentos de segurança proeminentes?"},"expert_commentary":"A Opção A é a mais sábia, seguindo a recomendação de Craske et al. (2014) sobre a retirada gradual de comportamentos de segurança para facilitar o aprendizado de autoeficácia. Negociar reduz os comportamentos sem tornar a tarefa avassaladora. A Opção B é comum, mas perpetua a atribuição externa do sucesso. A Opção C ignora o princípio da ''exposição com prevenção de resposta'' adaptada, podendo ser contraproducente. A Opção D representa uma evitação do terapeuta em avançar para etapas cruciais da terapia.","learning_focus":"Manejo e redução gradual de comportamentos de segurança durante o planejamento de exposição in vivo","decision_options":[{"option_letter":"A","intervention":"Validar a intenção e negociar um plano que minimize os comportamentos de segurança","approach":"Abordagem de redução gradual dos comportamentos de segurança","is_optimal":true,"immediate_outcome":"Você responde: \"Entendo que isso te daria uma sensação de segurança inicial. Vamos pensar em como fazer isso de um jeito que ainda seja um desafio proveitoso. Que tal ir com sua esposa, mas combinando que ela fica a alguns metros de distância? E quanto ao remédio, podemos deixá-lo em casa, mas você leva um papel com estratégias de coping que treinamos?\" Thiago concorda com um plano adaptado, sentindo-se desafiado, mas não sobrecarregado.","long_term_effect":"","impact":{"rapport":8,"insight":8,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Aceitar a proposta como está para garantir que a exposição aconteça","approach":"Permissão total para usar todos os comportamentos de segurança inicialmente","is_optimal":false,"immediate_outcome":"Você diz: \"Ótimo! O importante é você ir. Use todos os recursos que precisar.\" Thiago realiza a exposição com a esposa ao lado e o remédio no bolso. Ele completa a tarefa, mas atribui seu sucesso aos apoios externos (\"deu certo porque eu tinha o remédio\"), não à sua própria capacidade de tolerar a ansiedade, limitando o aprendimento correcional.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":5,"symptom_reduction":0}},{"option_letter":"C","intervention":"Insistir que ele vá sozinho e sem o remédio para uma \"exposição pura\"","approach":"Proibição rígida de qualquer comportamento de segurança","is_optimal":false,"immediate_outcome":"Você afirma: \"Para que a exposição funcione, você precisa ir sozinho e sem o remédio. Senão, não conta.\" Thiago se sente pressionado e despreparado. Ele pode desistir da tarefa ou realizá-la com um nível de ansiedade tão alto que leva a uma experiência negativa, prejudicando a motivação.","long_term_effect":"","impact":{"rapport":4,"insight":6,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Sugerir que ainda é cedo para contextos reais","approach":"Adiar a exposição in vivo e focar em mais exercícios interoceptivos","is_optimal":false,"immediate_outcome":"Você propõe: \"Acho melhor dominarmos mais os exercícios de tontura antes de ir para o metrô.\" A exposição é adiada. Thiago sente alívio no curto prazo, mas a evitação contextual permanece intocada, e a generalização dos ganhos da terapia fica estagnada.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":7,"session_title":"Mapeando os Gatilhos e a Evitação","session_phase":"middle","session_content":{"narrative":"A sessão começa com a paciente, Sofia, relatando que conseguiu identificar um padrão de pensamentos catastróficos antes de um ataque de pânico na semana anterior, mas que ainda evitou ir ao supermercado sozinha. Ela descreve uma sensação de ''medo do medo'' constante. Você revisa o diário de sintomas que ela preencheu, notando que os ataques ocorrem com maior frequência em situações de confinamento (como filas) ou quando ela percebe alterações em sua frequência cardíaca. Sofia fala sobre sua rotina de ''checagem de segurança'', como sempre carregar água e um ansiolítico, mesmo sem tomar. Ela demonstra insight sobre como esses comportamentos a mantêm presa no ciclo do pânico, mas expressa desesperança sobre conseguir mudar. A narrativa dela é marcada por uma hipervigilância corporal extrema, um sintoma central do transtorno de pânico (DSM-5-TR).","session_goals":["Refinar a análise funcional dos ataques de pânico e comportamentos de segurança.","Introduzir o conceito de exposição interoceptiva de forma psicoeducacional."],"key_observations":["Sofia demonstra boa adesão ao diário, permitindo uma análise funcional precisa.","Ela verbaliza insight sobre o ciclo da evitação, mas com afeto desesperançoso.","Os comportamentos de segurança (carregar remédio, água) são claros e atuam como reforçadores negativos."],"critical_decision_point":"Como você responde para promover o próximo passo terapêutico?"},"expert_commentary":"A pergunta de Sofia é um momento crucial. Ela está no limiar entre o insight e a mudança comportamental. A opção ótima (A) segue o princípio de ''colaboração empírica'' da TCC: transformar a dúvida em um teste comportamental. A exposição interoceptiva, recomendada por Clark & Beck (2010) para desfazer a associação entre sensações corporais e catástrofe, deve ser introduzida de forma gradual e colaborativa. Validar o medo é essencial antes de desafiar a crença.","learning_focus":"Habilidade em conduzir psicoeducação emocionalmente sintonizada e introduzir técnicas de exposição de forma colaborativa e não confrontadora.","decision_options":[{"option_letter":"A","intervention":"Validar o medo e propor um experimento comportamental conjunto.","approach":"Psicoeducação sobre ansiedade vs. perigo real e planejamento de exposição interoceptiva gradual.","is_optimal":true,"immediate_outcome":"Você normaliza a dúvida, explicando a resposta de luta/fuga e propõe, na sessão, simular sintomas (como girar em uma cadeira) para demonstrar que são inofensivos. Sofia se sente compreendida e concorda em tentar um exercício simples.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":7,"symptom_reduction":0}},{"option_letter":"B","intervention":"Garantir que é apenas ansiedade e instruí-la a parar os comportamentos imediatamente.","approach":"Abordagem diretiva e de confronto.","is_optimal":false,"immediate_outcome":"Sofia se sente invalidada e pressionada. Ela concorda verbalmente, mas a intervenção é prematura, aumentando sua ansiedade e a probabilidade de abandonar o tratamento.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Desviar da pergunta e focar novamente nos registros do diário.","approach":"Evitação do conteúdo emocional carregado.","is_optimal":false,"immediate_outcome":"A aliança terapêutica é prejudicada, pois Sofia sente que sua preocupação central foi ignorada. Ela se retrai e participa menos no restante da sessão.","long_term_effect":"","impact":{"rapport":3,"insight":4,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Sugerir que ela consulte um cardiologista para ''tirar a dúvida de vez''.","approach":"Encaminhamento médico como primeira resposta.","is_optimal":false,"immediate_outcome":"Isso reforça a crença catastrófica de Sofia de que o perigo é físico. Ela pode buscar repetidos exames (comportamento de segurança), consolidando o ciclo do pânico, como descrito por Barlow (2002): ''a busca por garantias mantém a ansiedade''.","long_term_effect":"","impact":{"rapport":5,"insight":2,"behavioral_change":1,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":8,"session_title":"Confrontando as Sensações Temidas","session_phase":"advanced","session_content":{"narrative":"Considerando que na sessão anterior você optou por validar o medo e propor um experimento (Opção A), Sofia chega relatando que tentou girar em uma cadeira em casa, como combinado. Ela conseguiu induzir tontura, mas interrompeu o exercício antes dos 30 segundos planejados devido a um pico de ansiedade. Ela descreve: ''Meu coração acelerou muito e eu pensei: é agora, vou desmaiar''. Você explora esse momento, destacando que ela *teve a sensação, teve o pensamento, mas o desmaio não ocorreu*. Ela reconhece isso, mas ainda está apreensiva. O foco da sessão é solidificar a prática da exposição interoceptiva, trabalhando com a tolerância ao desconforto e a reestruturação cognitiva *durante* a indução dos sintomas. Sofia parece mais engajada, mas ainda luta contra o impulso de escapar.","session_goals":["Realizar exposição interoceptiva in vivo durante a sessão.","Aplicar reestruturação cognitiva no pico da ansiedade induzida.","Planejar uma tarefa de exposição situacional gradual para a semana."],"key_observations":["Sofia demonstra coragem ao tentar o exercício em casa, um progresso significativo.","A interrupção precoce mostra que a ''fuga'' ainda é um reforçador potente.","Ela consegue observar a dissociação entre pensamento catastrófico e resultado real, um insight crucial."],"critical_decision_point":"Qual sua intervenção imediata para maximizar o aprendizado correcional?"},"expert_commentary":"Este é o coração da terapia para pânico: a experiência corretiva direta. A opção ótima (A) segue o protocolo de Barlow (2014), que enfatiza a ''exposição até a habituação'' e a ''prevenção de respostas de fuga/segurança''. A reestruturação no momento do pico de ansiedade é mais potente do que fora dele. Permitir que a ansiedade diminua naturalmente, sem comportamentos de segurança, fornece a prova visceral de que as sensações não são perigosas. Como citado por Clark (1986), ''a exposição interoceptiva visa quebrar associações condicionadas entre sensações corporais e catástrofe''.","learning_focus":"Habilidade em conduzir exposições interoceptivas in vivo, gerenciando a prevenção de resposta e integrando a reestruturação cognitiva no momento de maior ativação emocional.","decision_options":[{"option_letter":"A","intervention":"Instruí-la a manter os sintomas e guiar uma reestruturação cognitiva no momento.","approach":"Exposição com prevenção de resposta (não fugir) e reestruturação cognitiva in vivo.","is_optimal":true,"immediate_outcome":"Você diz: ''Perfeito, são exatamente as sensações. Vamos ficar com elas juntos por mais 60 segundos. O que o seu corpo está *realmente* fazendo, além de sentir isso?''. Você a guia para observar que, apesar do medo, ela está respirando, consciente e segura. A ansiedade atinge um pico e depois diminui, proporcionando uma experiência corretiva vital.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Parar o exercício imediatamente e acalmá-la com técnicas de respiração diafragmática.","approach":"Redução de ansiedade via controle de sintomas.","is_optimal":false,"immediate_outcome":"Isso reforça inadvertidamente a crença de que os sintomas eram perigosos e precisavam ser controlados. Sofia aprende que ''escapar'' (parar) é a solução, consolidando o comportamento de segurança que mantém o transtorno.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Racionalizar fora do momento, explicando novamente a biologia da ansiedade.","approach":"Psicoeducação intelectualizada no pico emocional.","is_optimal":false,"immediate_outcome":"Sofia está muito ativada emocionalmente para processar informações cognitivas complexas. Ela não internaliza a explicação e sente que você não entende a intensidade do seu medo.","long_term_effect":"","impact":{"rapport":5,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"D","intervention":"Minimizar a reação, dizendo ''Veja, não foi nada, você está bem''.","approach":"Subestimação da experiência subjetiva.","is_optimal":false,"immediate_outcome":"Sofia se sente invalidada. A mensagem implícita é que sua reação foi exagerada ou ''boba'', o que pode levar a vergonha e reduzir a adesão às exposições futuras.","long_term_effect":"","impact":{"rapport":4,"insight":3,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":9,"session_title":"Consolidando Ganhos e Enfrentando o Mundo","session_phase":"advanced","session_content":{"narrative":"Após a sessão anterior de exposição interoceptiva intensa (onde você escolheu a Opção A), Sofia chega relatando uma semana transformadora. Ela praticou os exercícios de indução de sintomas e, pela primeira vez, sentiu a ansiedade ''subir e descer como uma onda'' sem desencadear um ataque de pânico completo. Ela reduziu significativamente a checagem do pulso e deixou de carregar o ansiolítico em dois dias. No entanto, ela traz um novo desafio: foi convidada para um jantar em um restaurante apertado e já está antecipando ansiedade. ''Agora que eu sei que não vou morrer, meu medo é de passar vergonha, de ter que sair correndo'', ela compartilha. A sessão foca em consolidar os ganhos da exposição interoceptiva e transferir os aprendizados para a exposição situacional (agorafobia), trabalhando com crenças sobre avaliação social e tolerância ao desconforto em público.","session_goals":["Consolidar a nova crença de que as sensações são inofensivas através de revisão de evidências.","Elaborar uma hierarquia de exposição situacional para comportamentos de evitação agorafóbica.","Trabalhar crenças secundárias sobre avaliação social e ''vergonha'' durante sintomas."],"key_observations":["Sofia mostra uma mudança de paradigma clara: do medo de morrer para o medo de se envergonhar.","A redução dos comportamentos de segurança é um indicador robusto de progresso.","A evitação situacional (restaurante) agora é o principal obstáculo, um padrão comum após a redução do medo das sensações."],"critical_decision_point":"Como você trabalha essa nova camada de crenças (medo da avaliação social) para permitir que a exposição avance?"},"expert_commentary":"O surgimento do medo de avaliação social é um marco positivo: indica que o medo primário (de morrer) foi enfraquecido. A opção ótima (A) trata essa nova crença com a mesma ferramenta da TCC: teste de hipóteses. A exposição agora tem um duplo objetivo: habituação ao ambiente *e* testar crenças sobre o julgamento alheio. É crucial não introduzir novos comportamentos de segurança (D). O objetivo final, conforme o protocolo para pânico com agorafobia, é a tolerância à incerteza e ao desconforto em qualquer situação, não o controle absoluto dos sintomas ou das impressões sociais.","learning_focus":"Habilidade em identificar e trabalhar crenças secundárias (ex.: avaliação social) que surgem após a resolução do medo primário, utilizando reestruturação e testes comportamentais para promover a generalização dos ganhos terapêuticos.","decision_options":[{"option_letter":"A","intervention":"Explorar a crença e propor um teste de realidade comportamental.","approach":"Reestruturação cognitiva seguida de exposição com foco na tolerância à percepção de julgamento.","is_optimal":true,"immediate_outcome":"Você questiona: ''O que seria a prova de que as pessoas estão julgando você? Vamos testar?''. Vocês planejam que, durante a exposição, ela observe ativamente se as pessoas realmente a encaram ou reagem. Sofia concorda em testar a hipótese, deslocando o foco da sensação interna para a observação externa realista.","long_term_effect":"","impact":{"rapport":8,"insight":8,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Assegurar que ninguém vai notar e que ela está sendo irracional.","approach":"Tentativa de tranquilização e confronto direto à crença.","is_optimal":false,"immediate_outcome":"Isso invalida sua preocupação. Sofia pode não acreditar na garantia, ou pior, sentir que você não leva a sério seu medo social, prejudicando a aliança. A crença não é desafiada empiricamente.","long_term_effect":"","impact":{"rapport":5,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"C","intervention":"Sugerir adiar a exposição situacional e focar mais semanas só nos exercícios interoceptivos.","approach":"Evitação do novo núcleo fóbico (social/situacional).","is_optimal":false,"immediate_outcome":"Isso mantém a evitação agorafóbica, que é um critério do DSM-5-TR para o transtorno de pânico. O progresso estagna, e Sofia pode generalizar que ''estar bem em casa'' é o objetivo final, não a liberdade.","long_term_effect":"","impact":{"rapport":6,"insight":5,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"D","intervention":"Ensinar técnicas de dissimulação (como esconder as mãos) para que os outros não notem.","approach":"Substituição por um comportamento de segurança sutil.","is_optimal":false,"immediate_outcome":"Você estaria, inadvertidamente, reforçando a ideia de que os sintomas são vergonhosos e devem ser escondidos. Isso impede a habituação completa e a crença de que mesmo que notem, não é catastrófico, como discutido por Hofmann & Otto (2008) sobre a importância de abandonar todos os comportamentos de segurança.","long_term_effect":"","impact":{"rapport":7,"insight":3,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":10,"session_title":"Revisão da Exposição e Lida com a Evitação Sutil","session_phase":"advanced","session_content":{"narrative":"A sessão começa com Lucas, 28 anos, relatando um progresso significativo. Ele conseguiu enfrentar o supermercado e uma fila de banco sem ter um ataque de pânico completo, utilizando as técnicas de respiração e reestruturação cognitiva. No entanto, ele revela uma nova forma de evitação: começou a fazer compras online para evitar completamente o shopping center, que ele identifica como seu ''último grande desafio''. Ele descreve uma sensação de ''alívio, mas também de fraqueza'' por estar cedendo a essa evitação. O humor é de ambivalência, orgulhoso das conquistas, mas frustrado por ainda sentir medo de um local específico. A narrativa segue para uma análise detalhada do pensamento catastrófico por trás do medo do shopping (''vou desmaiar e ninguém vai me ajudar''), que persiste apesar dos sucessos em outros contextos.","session_goals":["Consolidar os ganhos das exposições realizadas","Identificar e abordar novos padrões de evitação sutil (comportamental e cognitiva)","Planejar uma exposição interoceptiva para a sensação de desmaio, um medo central persistente"],"key_observations":["O paciente demonstra habilidade em aplicar técnicas, mas a evitação adaptativa (compras online) ameaça a generalização do aprendizado","O medo de desmaiar permanece como uma crença nuclear não totalmente desafiada, apesar da ausência de desmaios reais em sua história","Há um aumento da autocrítica (''fraqueza''), que pode se tornar um obstáculo emocional"],"critical_decision_point":"Como você responde para promover a progressão terapêutica?"},"expert_commentary":"A opção A é ótima porque segue o princípio de ''colaboração empática'' da TCC. Como Barlow e Craske (2007) enfatizam, a exposição deve ser apresentada como um experimento de aprendizagem, não uma prova de coragem. Validar o alívio da evitação reduz a resistência. Psicoeducar sobre como a evitação, mesmo ''inteligente'' (online), impede a nova aprendizagem de segurança (\"nada de terrível acontece\") é crucial. A proposta de um experimento conjunto mantém Lucas como agente ativo, aumentando a adesão.","learning_focus":"Identificação e manejo de esquivas sutis que ameaçam a generalização do tratamento.","decision_options":[{"option_letter":"A","intervention":"Validar o alívio que a evitação traz, mas psicoeducar sobre a manutenção do transtorno e propor um experimento comportamental conjunto","approach":"Validação + Psicoeducação + Colaboração","is_optimal":true,"immediate_outcome":"Lucas se sente compreendido e não julgado. Ele aceita a lógica de que a evitação, mesmo sutil, fortalece o medo a longo prazo. Concorda em co-criar um plano de exposição gradual ao shopping, começando com apenas entrar e sair da porta.","long_term_effect":"","impact":{"rapport":9,"insight":8,"behavioral_change":8,"symptom_reduction":0}},{"option_letter":"B","intervention":"Confrontar diretamente a evitação, enfatizando que ele está ''trapaceando'' no próprio tratamento e deve ser mais corajoso","approach":"Confrontação Direta","is_optimal":false,"immediate_outcome":"Lucas se sente envergonhado e criticado. Ele pode concordar por complacência, mas sua resistência e autocrítica aumentam, prejudicando a aliança terapêutica e a adesão genuína ao plano.","long_term_effect":"","impact":{"rapport":3,"insight":5,"behavioral_change":2,"symptom_reduction":0}},{"option_letter":"C","intervention":"Focar exclusivamente no sucesso das exposições passadas e adiar a discussão sobre o shopping para uma sessão futura","approach":"Foco no Positivo e Adiamento","is_optimal":false,"immediate_outcome":"A sessão mantém um tom positivo, mas perde a oportunidade de abordar um mecanismo de manutenção crucial. A evitação sutil se consolida, tornando mais difícil enfrentá-la depois.","long_term_effect":"","impact":{"rapport":7,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Sugerir que a terapia já atingiu seus objetivos principais e que evitar o shopping é uma adaptação razoável da vida moderna","approach":"Normalização Prematura da Evitação","is_optimal":false,"immediate_outcome":"A mensagem reforça a fobia. Lucas pode terminar a terapia prematuramente com uma área de incapacidade significativa não resolvida, aumentando o risco de recaída em outros contextos.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":2,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":11,"session_title":"Exposição Interoceptiva e Desafiando o Medo do Desmaio","session_phase":"advanced","session_content":{"narrative":"Com base na decisão da sessão anterior, Lucas realizou a primeira etapa da exposição ao shopping: ficar 5 minutos na entrada. Ele relata alta ansiedade, mas conseguiu usar a respiração diafragmática. O foco da sessão agora se volta para o medo nuclear que emergiu: o pavor de desmaiar. Lucas acredita firmemente que as sensações de tontura e calor durante a crise são sinais precoces de um desmaio iminente. É apresentada a técnica de exposição interoceptiva. Você demonstra exercícios para induzir sensações semelhantes (girar em uma cadeira, respirar através de um canudo) em um ambiente seguro. Lucas inicialmente hesita, mas concorda em tentar. Durante o exercício de hiperventilação controlada, ele experimenta formigamento e tontura, reagindo com medo inicial, seguido de alívio ao perceber que não desmaiou.","session_goals":["Introduzir e praticar exposição interoceptiva para dessensibilizar as sensações físicas temidas","Testar diretamente a crença catastrófica \"sensações de tontura levam ao desmaio\"","Coletar dados comportamentais para reestruturar a crença"],"key_observations":["O paciente mostra coragem ao realizar a exposição in vivo inicial, mas sua crença sobre desmaio permanece intacta","Durante a exposição interoceptiva, a reação de medo é intensa mas breve, seguida por uma nova aprendizagem perceptível (\"não cai, é só desconfortável\")","Há uma oportunidade de vincular a experiência física à reestruturação cognitiva em tempo real"],"critical_decision_point":"Como você capitaliza essa experiência para consolidar a nova aprendizagem?"},"expert_commentary":"A opção A é ótima porque integra perfeitamente a exposição com a reestruturação cognitiva, seguindo o modelo de ''aprendizagem corretiva'' de Hoffart e al. (2016). O momento pós-exposição é crítico para atribuir significado à experiência. Questionar a evidência e co-criar um teste comportamental futuro transforma uma dúvida residual em um novo experimento, promovendo autoconfiança e internalização do controle. A garantia (B) é iatrogênica no pânico, pois reforça a ideia de que a segurança vem do terapeuta, não das próprias ações e descobertas do paciente.","learning_focus":"Integração de exposição interoceptiva com reestruturação cognitiva em tempo real para modificar crenças nucleares.","decision_options":[{"option_letter":"A","intervention":"Realizar uma análise cognitiva em tempo real, questionando a evidência e propondo um experimento comportamental para testar a nova hipótese no contexto real","approach":"Reestruturação Cognitiva Integrada à Exposição","is_optimal":true,"immediate_outcome":"Você guia Lucas a examinar a evidência: ele nunca desmaiou. A nova hipótese é que as sensações são intensas, mas inofensivas. Juntos, planejam o próximo passo da exposição ao shopping para testar se o contexto muda o resultado. Lucas sai com um plano claro e uma crença mais flexível.","long_term_effect":"","impact":{"rapport":8,"insight":9,"behavioral_change":9,"symptom_reduction":0}},{"option_letter":"B","intervention":"Assegurá-lo de que, como ele não desmaiou no consultório, também não desmaiará no shopping, encerrando o assunto","approach":"Garantia e Fechamento Prematuro","is_optimal":false,"immediate_outcome":"A garantia pode acalmar temporariamente, mas não modifica a crença subjacente. Lucas pode duvidar internamente da validade da experiência no consultório (''aqui é seguro, lá não''), mantendo o medo.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Propor repetir o exercício interoceptivo várias vezes nesta sessão até a ansiedade extinguir, sem abordar o pensamento diretamente","approach":"Foco Exclusivo na Habituação Fisiológica","is_optimal":false,"immediate_outcome":"A habituação pode ocorrer no consultório, mas a generalização para o contexto real é limitada sem o componente cognitivo. Lucas pode aprender a tolerar a sensação apenas no ambiente terapêutico.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":6,"symptom_reduction":0}},{"option_letter":"D","intervention":"Minimizar sua dúvida, dizendo que é ''normal'' ainda ter medo e passar para outro tópico","approach":"Evitação do Processamento da Dúvida","is_optimal":false,"immediate_outcome":"A dúvida crucial não é processada, deixando uma brecha para a crença catastrófica se reafirmar antes da próxima exposição. A oportunidade de consolidar a aprendizagem é perdida.","long_term_effect":"","impact":{"rapport":5,"insight":3,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"},{"session_number":12,"session_title":"Consolidação, Prevenção de Recaída e Planejamento do Pós-Tratamento","session_phase":"closing","session_content":{"narrative":"Lucas chega animado. Ele realizou o experimento planejado: foi ao shopping, sentiu tontura, aplicou as técnicas e permaneceu no local por 20 minutos. ''A sensação veio, foi forte, mas eu lembrei do canudo e do girar... e passou. Eu não desmaiei.'' Ele descreve um sentimento de conquista profunda. A sessão é dedicada a consolidar todo o percurso. Juntos, revisam o modelo cognitivo-comportamental do seu pânico, desde os primeiros ataques ''do nada'' até a compreensão atual do ciclo do medo do medo. Lucas identifica seus principais gatilhos, sinais de alerta e o ''kit de ferramentas'' que construiu (respiração, reestruturação, exposição). O tom é de celebração, mas também de realismo. Surge a preocupação: ''E se, daqui a um ano, eu tiver uma crise de novo? Vou voltar à estaca zero?''","session_goals":["Revisar e consolidar o modelo de manutenção do pânico e as habilidades aprendidas","Elaborar um plano de prevenção de recaída detalhado","Discutir o encerramento da terapia e o conceito de ''alta''"],"key_observations":["O paciente demonstra domínio conceitual e prático das estratégias, mostrando-se o ''especialista'' no próprio transtorno","A preocupação com recaída é um sinal saudável de engajamento e realismo, não de fracasso","Há um equilíbrio emocional entre orgulho pelas conquistas e apreensão pelo futuro, típico da fase de encerramento"],"critical_decision_point":"Como você estrutura a resposta para promover autonomia e resiliência a longo prazo?"},"expert_commentary":"A opção A é ótima e segue as diretrizes baseadas em evidência para prevenção de recaída no pânico (Craske & Barlow, 2014). O plano escrito transforma ansiedades abstratas em um protocolo de ação concreto, aumentando o senso de controle. Normalizar a possibilidade de sintomas (''não é ''tudo ou nada'') é crucial para evitar a catastrofização de uma eventual recaída, que é um evento comum. Empoderar o paciente como seu próprio terapeuta é o objetivo final da TCC. A garantia (B) é contraproducente, pois o transtorno de pânico tem uma taxa de recorrência conhecida, e a preparação para isso é parte do tratamento.","learning_focus":"Estruturação de um plano de prevenção de recaída que promova autonomia e resiliência pós-alta.","decision_options":[{"option_letter":"A","intervention":"Reforçar que ele é o próprio terapeuta agora e co-criar um plano escrito de prevenção de recaída, normalizando a possibilidade de sintomas sem catastrofizá-los","approach":"Empoderamento + Planejamento Prático + Normalização","is_optimal":true,"immediate_outcome":"Lucas sente-se empoderado e preparado. Juntos, elaboram um plano com: 1) Sinais de alerta; 2) Passos de ação (ferramentas a usar); 3) Quando buscar ajuda novamente. Ele entende que um sintoma futuro não apaga suas conquistas, mas é um sinal para aplicar suas habilidades. A terapia é encerrada com um senso de competência.","long_term_effect":"","impact":{"rapport":9,"insight":9,"behavioral_change":10,"symptom_reduction":0}},{"option_letter":"B","intervention":"Garantir que, com as técnicas aprendidas, é muito improvável que ele tenha outra crise, minimizando seu medo","approach":"Garantia Otimista e Minimização","is_optimal":false,"immediate_outcome":"Se Lucas tiver uma crise no futuro, ele pode interpretar como uma falha pessoal ou do tratamento, levando a desmoralização e abandono das estratégias. A garantia cria uma expectativa irrealista e frágil.","long_term_effect":"","impact":{"rapport":7,"insight":5,"behavioral_change":4,"symptom_reduction":0}},{"option_letter":"C","intervention":"Sugerir que ele agende sessões de ''manutenção'' mensais indefinidamente para evitar qualquer risco de recaída","approach":"Dependência Prolongada da Terapia","is_optimal":false,"immediate_outcome":"Isso pode minar a autonomia de Lucas, transmitindo a mensagem de que ele não é capaz sem suporte contínuo. Pode criar uma dependência terapêutica e não promove o fechamento saudável do processo.","long_term_effect":"","impact":{"rapport":6,"insight":4,"behavioral_change":3,"symptom_reduction":0}},{"option_letter":"D","intervention":"Encerrar a terapia imediatamente, afirmando que o trabalho está completo e que dúvidas são naturais","approach":"Encerramento Brusco sem Ferramentas de Transição","is_optimal":false,"immediate_outcome":"Lucas fica sem um guia para lidar com futuras dificuldades. Sua apreensão não é processada, aumentando a ansiedade sobre o encerramento e o risco de uma recaída despreparada.","long_term_effect":"","impact":{"rapport":4,"insight":5,"behavioral_change":3,"symptom_reduction":0}}],"disorder":"Transtorno de Panico","difficulty_level":"intermediate"}]'::jsonb
WHERE title ILIKE '%Jornada%' AND (
  title ILIKE '%013%' OR 
  title ILIKE '%0013%'
);
COMMIT;
